INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('La zuppa di sasso', 'lettura', 'it', NULL, 9, 7, '{"description":"Un vecchio lupo arriva in un villaggio di animali e chiede ospitalità alla gallina per preparare la sua zuppa di sasso. Nonostante la paura iniziale, gli animali si lasciano coinvolgere e contribuiscono con ingredienti diversi, trasformando la situazione in una festa conviviale. Alla fine, il lupo rivela che il sasso non è ancora cotto e se lo riprende, lasciando gli animali a chiedersi chi sarà il prossimo ospite del lupo.","characters":[{"name":"Narratrice","description":""},{"name":"Lupo","description":""},{"name":"Gallina","description":""},{"name":"Porcello","description":""},{"name":"Cavallo","description":""},{"name":"Oca","description":""},{"name":"Pecora","description":""},{"name":"Capra","description":""},{"name":"Cane","description":""}],"scenes":[{"id":"scene_1","title":"Scena 1","setting":"Notte d’inverno, villaggio degli animali","music":"sottofondo musicale","beats":[{"type":"line","speaker":"Narratrice","to":"Pubblico","line":"È notte, è inverno, un vecchio lupo si avvicina ad un villaggio dove vivono gli animali e bussa alla porta della casa della gallina.","context":"Introduce la situazione: il lupo arriva al villaggio e crea attesa."}]},{"id":"scene_2","title":"Scena 2","setting":"Casa della gallina","beats":[{"type":"line","speaker":"Gallina","to":"Lupo","line":"Chi è?","context":"La gallina sente bussare ed è prudente."},{"type":"line","speaker":"Lupo","to":"Gallina","line":"Sono il lupo!","context":"Il lupo si presenta senza nascondersi."},{"type":"line","speaker":"Gallina","to":"Lupo","line":"IL LUPOOO!","context":"La gallina è spaventata."},{"type":"line","speaker":"Lupo","to":"Gallina","line":"Non aver paura gallina, sono vecchio e non ho più neanche un dente, lasciami scaldare e preparare la mia zuppa di sasso.","context":"Il lupo cerca di rassicurare la gallina e chiede ospitalità."},{"type":"line","speaker":"Narratrice","to":"Pubblico","line":"La gallina non sa cosa fare, non è tranquilla ma è curiosa e decide di aprire la porta.","context":"Spiega il conflitto interno della gallina: paura e curiosità."},{"type":"line","speaker":"Lupo","to":"Gallina","line":"Gallina per favore portami una pentola.","context":"Il lupo inizia la preparazione della zuppa."},{"type":"line","speaker":"Gallina","to":"Lupo","line":"Una pentola?","context":"La gallina è sorpresa e non capisce bene la ricetta."},{"type":"line","speaker":"Lupo","to":"Gallina","line":"Senti Gallina c’è pur bisogno di una pentola per preparare la zuppa di sasso.","context":"Il lupo risponde con naturalezza, come se fosse ovvio."},{"type":"line","speaker":"Gallina","to":"Lupo","line":"AH! Non lo sapevo, ti serve altro?!","context":"La gallina si lascia coinvolgere."},{"type":"line","speaker":"Lupo","to":"Gallina","line":"No, basta un sasso, dell’acqua e aspettare che bolla.","context":"Il lupo descrive una ricetta poverissima, lasciando spazio agli altri ingredienti."},{"type":"line","speaker":"Gallina","to":"Lupo","line":"Tutto qui?! Perché nelle mie zuppe metto sempre un po’ di sedano.","context":"La gallina propone il primo ingrediente aggiuntivo."},{"type":"line","speaker":"Lupo","to":"Gallina","line":"Sì, si può!","context":"Il lupo accetta e incoraggia la collaborazione."}]},{"id":"scene_3","title":"Scena 3","setting":"Vicino alla casa della gallina","beats":[{"type":"line","speaker":"Narratrice","to":"Pubblico","line":"Ma il porcello ha visto il lupo entrare nella casa della gallina ed è preoccupato.","context":"Introduce il porcello, che teme per la gallina."},{"type":"line","speaker":"Porcello","to":"Gallina","line":"Tutto bene?","context":"Il porcello controlla che la gallina non sia in pericolo."},{"type":"line","speaker":"Gallina","to":"Porcello","line":"Con il lupo stiamo preparando la zuppa di sasso.","context":"La gallina rassicura il porcello e spiega cosa sta succedendo."},{"type":"line","speaker":"Porcello","to":"Lupo","line":"Solo con un sasso? Si possono aggiungere anche delle zucchine?","context":"Il porcello passa dalla paura alla curiosità e propone un ingrediente."},{"type":"line","speaker":"Lupo","to":"Porcello","line":"Sì, si può!","context":"Il lupo accetta anche il contributo del porcello."}]},{"id":"scene_4","title":"Scena 4","setting":"Casa della gallina","beats":[{"type":"line","speaker":"Narratrice","to":"Pubblico","line":"Anche l’oca ed il cavallo hanno visto il lupo che entrava nella casa della gallina e si sono preoccupati.","context":"Arrivano altri animali, mossi dalla preoccupazione."},{"type":"line","speaker":["Cavallo","Oca"],"to":"Gruppo","line":"Tutto bene?","context":"Cavallo e oca chiedono se la situazione è sotto controllo."},{"type":"line","speaker":"Porcello","to":["Cavallo","Oca"],"line":"Con il lupo e la gallina stiamo preparando la zuppa di sasso con sedano e zucchine.","context":"Il porcello aggiorna i nuovi arrivati sugli ingredienti già aggiunti."},{"type":"line","speaker":"Oca","to":"Lupo","line":"Io che ho viaggiato molto mi ricordo di aver assaggiato una zuppa con il porro. È possibile?","context":"L’oca propone il porro, facendo riferimento alla propria esperienza."},{"type":"line","speaker":"Lupo","to":"Oca","line":"Sì, si può!","context":"Il lupo accetta un altro ingrediente."}]},{"id":"scene_5","title":"Scena 5","setting":"Casa della gallina, porta spalancata","beats":[{"type":"line","speaker":"Narratrice","to":"Pubblico","line":"Anche la pecora, la capra ed il cane hanno visto il lupo che entrava nella casa della gallina e si sono preoccupati. Trovano la porta spalancata ed entrano.","context":"Il gruppo si allarga: altri animali entrano nella casa."},{"type":"line","speaker":["Pecora","Capra","Cane"],"to":"Gruppo","line":"Cosa state facendo?","context":"I nuovi arrivati chiedono spiegazioni."},{"type":"line","speaker":"Cavallo","to":["Pecora","Capra","Cane"],"line":"Con il lupo, la gallina, il porcello e l’oca stiamo preparando la zuppa di sasso con sedano, zucchine e porri.","context":"Il cavallo riassume la situazione e gli ingredienti."},{"type":"line","speaker":"Pecora","to":"Gruppo","line":"Io prendo la rapa.","context":"La pecora contribuisce alla zuppa."},{"type":"line","speaker":"Capra","to":"Gruppo","line":"Io prendo il cavolo.","context":"La capra contribuisce alla zuppa."},{"type":"line","speaker":"Cane","to":"Gruppo","line":"Io prendo le patate.","context":"Il cane contribuisce alla zuppa."}]},{"id":"scene_6","title":"Scena 6","setting":"Tutti intorno al camino","beats":[{"type":"line","speaker":"Narratrice","to":"Pubblico","line":"Tutti sono intorno al camino in circolo aspettando che sia pronta la zuppa.","context":"La tensione iniziale è diventata convivialità."},{"type":"line","speaker":"Capra","to":"Gruppo","line":"Com’è bello essere tutti insieme!!","context":"La capra esprime la gioia del gruppo."},{"type":"line","speaker":"Cane","to":"Gruppo","line":"Dovremo organizzare cene più spesso!","context":"Il cane propone di ripetere l’esperienza."},{"type":"line","speaker":"Porcello","to":"Gruppo","line":"Pensavo che avremmo mangiato un brodo di carne.","context":"Il porcello fa una battuta sul lupo e sulla paura iniziale."},{"type":"stage_direction","action":"Gli animali ridacchiano, il lupo si porta la mano alla fronte.","context":"Reazione comica alla battuta del porcello."},{"type":"line","speaker":"Lupo","to":"Gruppo","line":"Credo che la zuppa sia pronta!","context":"Il lupo chiude l’attesa e serve la zuppa."},{"type":"line","speaker":"Narratrice","to":"Pubblico","line":"Il lupo serve tutti gli animali e ognuno si serve per ben tre volte.","context":"La zuppa è un successo e tutti mangiano insieme."}]},{"id":"scene_7","title":"Scena 7","setting":"Dopo cena","beats":[{"type":"line","speaker":"Narratrice","to":"Pubblico","line":"Il lupo tira fuori dal sacco un coltello e… infilza il sasso.","context":"Momento di suspense comica: sembra pericoloso, ma il lupo prende il sasso."},{"type":"line","speaker":"Lupo","to":"Gruppo","line":"Non è ancora cotto!, se permettete me lo riprendo per la cena di domani.","context":"Il lupo rivela il trucco della zuppa e si prepara ad andare via."},{"type":"line","speaker":"Capra","to":"Lupo","line":"Già te ne vai?","context":"La capra è dispiaciuta che il lupo parta."},{"type":"line","speaker":"Lupo","to":"Gruppo","line":"Vi ringrazio per questa bella serata!","context":"Il lupo saluta con gratitudine."},{"type":"stage_direction","action":"Il lupo esce dalla porta, gli animali stanno affacciati.","context":"Gli animali lo guardano andare via."},{"type":"line","speaker":"Narratrice","to":"Pubblico","line":"Chissà da chi andrà a cena domani…","context":"La narratrice prepara la battuta finale."},{"type":"stage_direction","action":"Il lupo si gira verso i bambini.","context":"Il lupo rompe la quarta parete."},{"type":"line","speaker":"Lupo","to":"Bambini","line":"Chi mi invita di voi a cena?","context":"Battuta finale rivolta direttamente al pubblico."}]}]}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('Saresti troppo impegnato a vendere tutto per sopravvivere.', 'lettura', 'it', NULL, 2, 2, '{"characters":[{"name":"Clark","description":"Cinico e provocatore, torna a casa dopo la morte del padre per rivendicare la sua parte di eredità."},{"name":"Pedro","description":"Erede unico, calmo ma trattenuto: difende la memoria del padre e impone limiti al fratello."}],"description":"Clark torna a casa dopo la morte del padre e si scontra con il fratello Pedro, che ha ereditato tutto. La tensione esplode quando Clark urina sulla tomba del padre, rivelando rancori profondi e questioni irrisolte sull’eredità e il passato familiare.","scenes":[{"id":"scene_1","setting":"Due sedie davanti al giardino. Una lapide è visibile. Bevono birra.","beats":[{"type":"line","speaker":"Clark","to":"Pedro","line":"Non riesco proprio a farmene una ragione.","context":"Clark è confuso e disturbato, cerca una reazione da Pedro."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Di cosa?","context":"Pedro è calmo, ma sulla difensiva."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Non ti sembra strano, per usare un eufemismo, che Roger abbia voluto essere sepolto nel suo giardino?","context":"Clark mette in discussione le scelte del padre Roger."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Qui era felice.","context":"Pedro difende il padre Roger."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Non riesco a immaginarmelo felice.","context":"Clark esprime cinismo e distanza emotiva."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Aveva i suoi momenti.","context":"Pedro prova a mantenere equilibrio."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Tutti abbiamo i nostri momenti, ma felice… quella è una cosa rara. Soprattutto per “Lo Scansafatiche”.","context":"Clark provoca usando un soprannome."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Perché lo chiamavi sempre così?","context":"Pedro vuole capire ma è infastidito."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Perché nostro padre ha evitato la vita. Ecco perché.","context":"Clark accusa direttamente il padre."},{"type":"stage_direction","action":"Clark si alza e si avvicina alla lapide.","context":"Cambio fisico: si confronta direttamente con il padre."},{"type":"line","speaker":"Clark","to":"Lapide","line":"Roger L. Dudson… cosa sta per la L?","context":"Clark legge e scopre qualcosa di nuovo."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Lemuel.","context":"Pedro sa più cose sul padre."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Stai scherzando? Il suo secondo nome era Lemuel?","context":"Clark è sorpreso e derisorio."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Come il nostro bisnonno.","context":"Pedro collega la storia familiare."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Non lo sapevo.","context":"Clark mostra ignoranza e distanza."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Ci sono tante cose che non sai.","context":"Pedro attacca indirettamente."},{"type":"stage_direction","action":"Clark urina sulla lapide.","context":"Atto provocatorio e irrispettoso di Clark verso il padre Roger."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Gli avevo detto che quando sarebbe morto gli avrei pisciato sulla tomba. Eccoci qua.","context":"Clark rivendica il gesto con rabbia."},{"type":"stage_direction","action":"Clark si sistema.","context":"Chiude il gesto."},{"type":"line","speaker":"Pedro","to":"Clark","line":"L’unico motivo per cui non ti spacco la faccia è perché so che sei mentalmente instabile.","context":"Pedro trattiene la rabbia ma attacca duramente."},{"type":"line","speaker":"Clark","to":"Pedro","line":"E tu perché sei così arrabbiato?","context":"Clark provoca ancora."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Devi andartene.","context":"Pedro impone un limite."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Andarmene?","context":"Clark finge sorpresa."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Sì. Devi andartene.","context":"Pedro è deciso."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Per una pisciata?","context":"Clark minimizza."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Per essere venuto qui, per averci invaso la vita, per pensare di avere voce in capitolo!","context":"Pedro esplode: il vero problema emerge."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Ah sì?","context":"Clark sfida apertamente."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Vattene!","context":"Ordine finale."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Ti sei preso la casa, il terreno, il camion… cos’altro vuoi togliermi?","context":"Clark introduce il tema dell’eredità."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Clark, devi—","context":"Pedro prova a fermarlo."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Dov’è la mia eredità? METÀ È MIA!","context":"Clark esplode, rivendica diritti."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Papà ha fatto testamento. Ha affidato tutto a me.","context":"Pedro si appella ai fatti legali."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Stronzate.","context":"Negazione totale."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Ti ho già mostrato i documenti.","context":"Pedro resta razionale."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Stronzate.","context":"Clark rifiuta la realtà."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Eri presente quando l’avvocato ha spiegato tutto.","context":"Pedro richiama la memoria condivisa."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Una farsa!","context":"Clark continua ad attaccare."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Questi sono i fatti.","context":"Pedro resta fermo."},{"type":"line","speaker":"Clark","to":"Pedro","line":"I fatti sono cose che stanno su un foglio finché qualcuno non ha abbastanza soldi per stamparli.","context":"Clark non accetta la legalità del testamento e trasforma tutto in sospetto."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Non è una cospirazione, Clark. È un testamento.","context":"Pedro prova a restare freddo, ma è stanco."},{"type":"line","speaker":"Clark","to":"Pedro","line":"È una cospirazione con il notaio.","context":"Clark rilancia con sarcasmo amaro."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Tu non vuoi giustizia. Vuoi contanti.","context":"Pedro individua il vero bisogno di Clark."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Mi pare che i contanti siano una forma molto rispettata di giustizia.","context":"Clark non nega davvero."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Ecco perché papà non ti ha lasciato niente.","context":"Pedro colpisce Clark nel punto più doloroso."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Perché era un bastardo.","context":"Clark risponde subito, ma è ferito."},{"type":"line","speaker":"Pedro","to":"Clark","line":"No. Perché ti conosceva.","context":"Pedro dice una verità che ha trattenuto troppo a lungo."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Lui non mi conosceva. Lui mi giudicava. È diverso.","context":"Clark distingue tra essere visto e essere condannato."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Ti giudicava perché ogni volta che entravi da quella porta spariva qualcosa.","context":"Pedro apre il dossier dei rancori concreti."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Ah, eccolo. Il martirio della famiglia Dudson.","context":"Clark prova a sminuire prima che Pedro sia più preciso."},{"type":"line","speaker":"Pedro","to":"Clark","line":"La motosega. Il televisore piccolo. Il fucile da pesca. La fede di mamma.","context":"Pedro elenca senza enfasi, aumentando il peso della scena."},{"type":"line","speaker":"Clark","to":"Pedro","line":"La fede di mamma l’ho impegnata.","context":"Clark si difende su un dettaglio, rivelando colpa."},{"type":"line","speaker":"Pedro","to":"Clark","line":"È un modo elegante per dire venduta.","context":"Pedro non gli lascia via di fuga."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Avevo bisogno di soldi.","context":"Clark lascia cadere la maschera per un istante."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Hai sempre bisogno di soldi.","context":"Pedro non è crudele, ma esausto."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Beato te che hai sempre avuto bisogno solo di sentirti migliore.","context":"Clark contrattacca sul piano morale."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Io ho avuto bisogno di restare. Di pagare le bollette. Di portarlo alle visite. Di lavarlo quando non riusciva più ad alzarsi.","context":"Pedro rivela cosa significava davvero ereditare."},{"type":"line","speaker":"Clark","to":"Pedro","line":"E quindi ti sei guadagnato il premio.","context":"Clark non riesce ad accogliere la sofferenza di Pedro."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Premio? Questa casa ha il tetto marcio, il camion non passa la revisione e il terreno è pieno di debiti arretrati.","context":"Pedro smonta l’idea dell’eredità come ricchezza."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Allora vendi tutto.","context":"Clark propone la soluzione che Pedro temeva."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Tu venderesti tutto.","context":"Pedro capisce che il problema è proprio questo."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Sì. Perché io non sono innamorato della muffa.","context":"Clark resta pratico e sprezzante."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Non saresti nemmeno abbastanza libero da piangere papà. Saresti troppo impegnato a vendere tutto per sopravvivere.","context":"Pedro pronuncia il cuore della scena: Clark è prigioniero del bisogno."},{"type":"stage_direction","action":"Clark resta fermo. Per la prima volta non risponde subito.","context":"La frase ha colpito davvero."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Bella frase. Te l’ha lasciata lui o l’hai inventata mentre lucidavi la sua bara?","context":"Clark prova a recuperare controllo con crudeltà."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Mi ha lasciato una busta per te.","context":"Pedro cambia direzione e introduce un nuovo elemento."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Una busta?","context":"Clark è sorpreso e sospettoso."},{"type":"line","speaker":"Pedro","to":"Clark","line":"È in cucina. Nel cassetto dove teneva le cose che non voleva buttare e non sapeva come guardare.","context":"Pedro parla del padre con una tenerezza trattenuta."},{"type":"line","speaker":"Clark","to":"Pedro","line":"E non me l’hai data prima?","context":"Clark trasforma subito la notizia in accusa."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Aspettavo che tu finissi di pisciargli addosso.","context":"Pedro chiude con durezza secca."},{"type":"stage_direction","action":"Pedro prende le bottiglie vuote e rientra in casa. Clark resta solo davanti alla lapide.","context":"Pedro abbandona il campo, Clark resta con il padre morto."},{"type":"line","speaker":"Clark","to":"Lapide","line":"Lemuel. Che razza di nome di merda.","context":"Clark parla alla lapide, ma il tono è meno aggressivo di prima."},{"type":"stage_direction","action":"Clark guarda verso la casa. Dopo un momento, lo segue.","context":"Fine scena: Clark sceglie di entrare, non di andarsene."}]},{"id":"scene_2","setting":"Cucina della casa. Notte. Sul tavolo ci sono documenti, una lampada accesa, due birre chiuse e una busta ingiallita.","beats":[{"type":"stage_direction","action":"Clark entra piano. Pedro è già seduto al tavolo, ma non guarda il fratello.","context":"La tensione si sposta dal giardino alla casa, in uno spazio più intimo."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Quindi adesso c’è anche la busta melodrammatica.","context":"Clark prova a ridicolizzare il momento."},{"type":"line","speaker":"Pedro","to":"Clark","line":"C’è una busta.","context":"Pedro non accetta il tono teatrale di Clark."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Dentro cosa c’è? Un’altra copia del testamento? Una foto di te con un’aureola?","context":"Clark continua a difendersi con sarcasmo."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Non l’ho aperta.","context":"Pedro stabilisce un confine morale."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Certo.","context":"Clark non gli crede."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Clark.","context":"Pedro lo richiama alla serietà."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Che c’è? Vuoi che mi commuova perché per una volta non hai controllato qualcosa?","context":"Clark attacca Pedro come uomo del controllo."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Voglio che tu la apra o che te ne vada. Una delle due.","context":"Pedro mette Clark davanti a una scelta concreta."},{"type":"stage_direction","action":"Clark prende la busta. La gira tra le mani senza aprirla.","context":"Clark ha paura del contenuto più di quanto voglia mostrare."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Ha scritto il mio nome male.","context":"Clark nota un dettaglio per evitare il contenuto emotivo."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Ha sempre scritto male.","context":"Pedro attenua il colpo con normalità."},{"type":"line","speaker":"Clark","to":"Pedro","line":"No. Il tuo lo scriveva bene.","context":"Clark trasforma anche l’ortografia in prova di esclusione."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Il mio lo vedeva sulle bollette.","context":"Pedro risponde secco, senza compiacimento."},{"type":"stage_direction","action":"Clark apre la busta. Dentro ci sono una lettera breve, una vecchia fotografia e una chiave arrugginita.","context":"La busta contiene memoria, non denaro."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Una chiave. Fantastico. Sono ricco.","context":"Clark reagisce male alla mancanza di valore economico."},{"type":"line","speaker":"Pedro","to":"Clark","line":"È del capanno dietro al pozzo.","context":"Pedro riconosce l’oggetto."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Il capanno con le lamiere e i topi?","context":"Clark ricorda il luogo con disprezzo."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Sì.","context":"Pedro non spiega ancora."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Mi ha lasciato i topi.","context":"Clark cerca la battuta per non aprire la lettera."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Leggi.","context":"Pedro lo costringe gentilmente ad affrontare il padre."},{"type":"stage_direction","action":"Clark apre la lettera. La legge in silenzio. Il suo viso cambia appena.","context":"Non serve sentire subito il testo: conta la reazione."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Che dice?","context":"Pedro, pur avendo rispettato la busta, vuole sapere."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Niente.","context":"Clark mente istintivamente."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Clark.","context":"Pedro riconosce la bugia."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Dice che nel capanno ci sono le mie cose.","context":"Clark concede solo il minimo."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Che cose?","context":"Pedro è incuriosito."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Non lo so. Roba vecchia. Spazzatura.","context":"Clark svaluta prima di scoprire."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Allora buttala.","context":"Pedro lo provoca senza alzare la voce."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Non ho detto che la butto.","context":"Clark rivela che gli importa."},{"type":"stage_direction","action":"Pedro apre una birra e la mette davanti a Clark, poi ne apre una per sé.","context":"Primo gesto di tregua."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Hai urinato sulla tomba di nostro padre e io ti sto offrendo una birra. Direi che la famiglia ha fatto passi avanti.","context":"Pedro usa ironia asciutta per allentare la tensione."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Non montarti la testa. È birra scadente.","context":"Clark accetta la tregua senza ammetterlo."},{"type":"line","speaker":"Pedro","to":"Clark","line":"È quella che beveva lui.","context":"Pedro collega il gesto al padre."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Allora era scadente anche lui.","context":"Clark torna subito all’attacco."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Sì.","context":"Pedro sorprende Clark concedendo qualcosa."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Sì?","context":"Clark non si aspettava accordo."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Sì. Era scadente. Era duro, testardo, vigliacco con le parole. Faceva prima a morire che a chiedere scusa.","context":"Pedro ammette i limiti del padre."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Finalmente.","context":"Clark sente di aver ottenuto una crepa nella difesa di Pedro."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Ma è rimasto.","context":"Pedro salva comunque il padre su ciò che per lui conta."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Non tutti restano perché amano. Alcuni restano perché non sanno dove andare.","context":"Clark vede nel padre una forma di immobilità, non devozione."},{"type":"line","speaker":"Pedro","to":"Clark","line":"E alcuni se ne vanno chiamandola libertà, ma è solo fuga con una giacca migliore.","context":"Pedro risponde specularmente."},{"type":"stage_direction","action":"I due bevono in silenzio.","context":"Nessuno vince. La scena respira."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Posso dormire qui stanotte?","context":"Clark chiede qualcosa senza travestirlo da provocazione."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Sul divano.","context":"Pedro concede, ma con un limite."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Il divano è mio per metà?","context":"Clark torna al tema dell’eredità, ma ora è quasi un gioco."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Solo la parte sfondata.","context":"Pedro risponde con la stessa lingua di Clark."},{"type":"stage_direction","action":"Clark sorride appena, poi guarda la chiave sul tavolo.","context":"Il conflitto non è risolto, ma una porta si è aperta."},{"type":"line","speaker":"Clark","to":"Pedro","line":"Domani vado a vedere cosa c’è nel capanno.","context":"Clark decide di affrontare il lascito non economico del padre."},{"type":"line","speaker":"Pedro","to":"Clark","line":"Domani.","context":"Pedro accetta il rinvio come una piccola promessa."},{"type":"stage_direction","action":"La luce della cucina resta accesa. Fuori, nel buio, la lapide è appena visibile.","context":"Finale sospeso: la casa non è pace, ma per ora non è più solo guerra."}]}]}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('15 minuti di fama su YouTube', 'lettura', 'it', NULL, 3, 2, '{"description":"Dillon Spree, un ragazzo di scuola superiore, viene convocato d’urgenza nell’ufficio del preside a causa di un video virale leggermente inappropriato e imbarazzante. Il preside, invece di punirlo, cerca di sfruttare la sua improvvisa fama per promuovere la scuola. Dillon si trova così a dover navigare tra l’imbarazzo della sua notorietà e le aspettative della comunità scolastica.","characters":[{"name":"Dillon","description":"Studente modello impaurito, vittima involontaria di un video virale che lo mette al centro dell''attenzione."},{"name":"Pembelton","description":"Assistente burocratico del preside, applica le direttive del comitato genitori con assurda serietà."},{"name":"Preside Smock","description":"Opportunista pronto a sfruttare la fama di Dillon per il prestigio e i fondi della scuola."}],"scenes":[{"id":"scene_1","setting":"Corridoio della scuola. Dillon viene convocato d’urgenza nell’ufficio del preside.","beats":[{"type":"line","speaker":"Pembelton","to":"Dillon","line":"Dillon Spree, per favore recati nell’ufficio del Preside. Immediatamente. Signor Dillon Spree.","context":"Pembelton è formale e urgente. Sta chiamando Dillon come se fosse nei guai seri."},{"type":"line","speaker":"Dillon","to":"Pembelton","line":"Io non sono mai stato nell’ufficio del preside. Sono un secchione da tutti dieci. Faccio parte del club di scacchi. Io— io—","context":"Dillon è nel panico. Non capisce cosa possa aver fatto di sbagliato."},{"type":"line","speaker":"Pembelton","to":"Dillon","line":"Signor Spree, abbiamo davvero bisogno di lei nell’ufficio del Preside! Ora!","context":"Pembelton interrompe Dillon e aumenta la pressione."},{"type":"stage_direction","action":"Il Preside Smock aspetta Dillon. Dillon entra. Pembelton esce.","context":"Cambio di spazio: dall’esterno dell’ufficio al confronto diretto con il preside."}]},{"id":"scene_2","setting":"Ufficio del Preside Smock.","beats":[{"type":"line","speaker":"Dillon","to":"Preside Smock","line":"Ehm, voleva vedermi, Preside—","context":"Dillon è intimidito e cerca di essere educato."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Sì, sì, sì. Siediti, Dillon.","context":"Il preside taglia corto. Vuole passare subito al punto."},{"type":"stage_direction","action":"Dillon si siede.","context":"Dillon obbedisce, ancora nervoso."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Dillon, un paio di cose. A me piacciono i video stupidi quanto a chiunque altro, ma questa è pur sempre una scuola pubblica. E non puoi usare quel linguaggio. Non puoi proprio.","context":"Il preside finge autorità morale, ma il problema è assurdo."},{"type":"line","speaker":"Dillon","to":"Preside Smock","line":"Preside Smock, io non c’entro niente con… aspetti, quale linguaggio?","context":"Dillon prova a difendersi, poi si confonde."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Sedere.","context":"Il preside pronuncia la parola come se fosse grave."},{"type":"line","speaker":"Dillon","to":"Preside Smock","line":"Sedere è una brutta parola?","context":"Dillon è incredulo."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Sedere è una brutta parola.","context":"Il preside conferma con serietà sproporzionata."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Ora, se stessimo parlando di “sedere” nel senso di stare seduti, come in: “Mi devo sedere perché sono stanco”, allora va bene. Quello puoi dirlo.","context":"Il preside tenta una spiegazione grammaticale ridicola."},{"type":"line","speaker":"Dillon","to":"Preside Smock","line":"È sicuro che sia una brutta parola? Sedere nel senso di… sedere?","context":"Dillon cerca di capire se il preside sta parlando seriamente."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Guarda, nemmeno io lo pensavo. Ma sono stato sommerso da email di genitori sconvolti perché i loro figli stanno guardando un video con la parola “sedere”. Quindi non dirla più. E cambia il titolo del video.","context":"Il preside non crede davvero al problema, ma vuole evitare lamentele."},{"type":"line","speaker":"Dillon","to":"Preside Smock","line":"Ma io non ho pubblicato il video!","context":"Dillon cerca di chiarire il malinteso principale."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"No? Strano. Allora dì a chiunque l’abbia pubblicato di non usare la parola sedere. Usate, ehm… accidenti, qual era la parola… Pembelton!","context":"Il preside non si concentra sulla responsabilità, ma solo sulla censura della parola."},{"type":"stage_direction","action":"Pembelton rientra.","context":"Pembelton viene chiamato come assistente tecnico del linguaggio accettabile."},{"type":"line","speaker":"Pembelton","to":"Preside Smock","line":"Sì, signore?","context":"Pembelton è pronto a eseguire."},{"type":"line","speaker":"Preside Smock","to":"Pembelton","line":"Come dobbiamo dire adesso al posto di sedere? Deretano?","context":"Il preside chiede la formula approvata."},{"type":"line","speaker":"Pembelton","to":"Preside Smock","line":"No, è troppo anatomico.","context":"Pembelton tratta la questione con assurda serietà burocratica."},{"type":"line","speaker":"Preside Smock","to":"Pembelton","line":"Fondo schiena?","context":"Il preside propone un’alternativa."},{"type":"line","speaker":"Pembelton","to":"Preside Smock","line":"Troppo allusivo.","context":"Pembelton boccia anche questa."},{"type":"line","speaker":"Preside Smock","to":"Pembelton","line":"A cosa?","context":"Il preside non capisce l’obiezione."},{"type":"line","speaker":"Pembelton","to":"Preside Smock","line":"Alle sedie.","context":"Risposta assurda, detta con convinzione."},{"type":"line","speaker":"Preside Smock","to":"Pembelton","line":"Giusto. Allora qual è? Cosa vogliono che diciamo?","context":"Il preside si arrende alla burocrazia."},{"type":"line","speaker":"Pembelton","to":"Preside Smock","line":"La terminologia accettabile decisa dal comitato genitori è… “mucchio carnoso”.","context":"Pembelton annuncia una soluzione molto peggiore del problema."},{"type":"line","speaker":"Preside Smock","to":"Pembelton","line":"Davvero? Suona molto più inappropriato.","context":"Il preside riconosce l’assurdità."},{"type":"line","speaker":"Pembelton","to":"Preside Smock","line":"Concordo, signore.","context":"Pembelton approva, ma non mette in discussione la regola."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Cioè, so che non è una parolaccia, però è… disgustosa da sentire. “Mucchio carnoso”. Bleah.","context":"Il preside prova repulsione per la nuova formula."},{"type":"line","speaker":"Pembelton","to":"Preside Smock","line":"È quello che vogliono che gli studenti usino d’ora in poi.","context":"Pembelton ribadisce l’ordine istituzionale."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Va bene. Come vogliono. Mucchio carnoso. D’ora in poi riferisciti alla tua parte posteriore come a un mucchio carnoso.","context":"Il preside applica la regola, pur trovandola assurda."},{"type":"line","speaker":"Dillon","to":"Preside Smock","line":"Ok. Va bene, ma io—","context":"Dillon prova ancora a spiegare che non è responsabile."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Ma non è nemmeno per questo che ti ho chiamato. Sai perché ti ho chiamato?","context":"Il preside rivela che il vero motivo è un altro."},{"type":"line","speaker":"Dillon","to":"Preside Smock","line":"Non perché ho detto “sedere”?","context":"Dillon testa il limite appena imposto."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Dillon.","context":"Il preside lo ammonisce severamente."},{"type":"line","speaker":"Dillon","to":"Preside Smock","line":"Voglio dire, mucchio carnoso.","context":"Dillon corregge la parola per evitare problemi."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"No. Senti, nonostante l’obiezione della scuola alla parola sedere, ci piacerebbe che tu partecipassi ad alcuni eventi per noi. Qualche raccolta fondi, cose così.","context":"Il preside passa dalla reprimenda allo sfruttamento della fama di Dillon."},{"type":"line","speaker":"Dillon","to":"Preside Smock","line":"Mi scusi, vuole che io—","context":"Dillon è spiazzato dal cambio di tono."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Non ho mai avuto uno studente famoso in questa scuola, Dillon. Nel 2005 c’era una possibilità che Zac Efron si iscrivesse da noi. Sarebbe stato magnifico. Mio Dio, la quantità di stampa e fondi spontanei che una scuola può ricevere se una celebrità la frequenta… fa venire l’acquolina in bocca.","context":"Il preside fantastica sui vantaggi economici e mediatici della fama."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Poi però ha deciso di fare un film. Inoltre era analfabeta, quindi avremmo dovuto ritoccargli parecchio i voti. Io ero disposto a farlo. Eccome se ero disposto… ma, ehm…","context":"Il preside rivela senza vergogna la sua opportunismo."},{"type":"line","speaker":"Dillon","to":"Preside Smock","line":"Signore.","context":"Dillon prova a riportarlo alla realtà."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Il punto è che adesso ce l’ho. Tu! Il ragazzo di “Ahia, mi sono fatto male al mucchio carnoso”. Il tuo video ha già superato mezzo milione di visualizzazioni.","context":"Il preside vede Dillon come una risorsa pubblicitaria."},{"type":"line","speaker":"Dillon","to":"Preside Smock","line":"Davvero?!","context":"Dillon è scioccato dalla portata della sua fama involontaria."},{"type":"line","speaker":"Preside Smock","to":"Dillon","line":"Allora, che ne dici? Saresti disposto a fare qualche evento per noi? Raduni scolastici, interviste, magari una raccolta fondi… tutto per il bene della tua scuola?","context":"Il preside cerca di convincerlo usando il senso di appartenenza alla scuola."}]}]}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('Il Pranzo dell''Ispettore Candela', 'lettura', 'it', 'Inspettore Candela', 3, 3, '{"characters":[{"name":"Rómulo Candela","description":"Detective privato di origini spagnole, teatrale, colorato, ironico e manipolatore."},{"name":"Lidia Giostra","description":"Ristoratrice elegante e nervosa. Vuole sembrare collaborativa, ma controlla ogni parola. Ha paura che il passato torni a galla."},{"name":"Tommaso Grieco","description":"Critico gastronomico brillante e sarcastico. Usa l’ironia per difendersi. Finge superiorità, ma è più fragile di quanto sembri."}],"scenes":[{"id":"scene_1","title":"Antipasto","setting":"Un piccolo ristorante mediterraneo. Tavolo apparecchiato per tre. Pomodori, olive, pane, birra leggera. Candela indossa una giacca colorata e occhiali da sole.","beats":[{"type":"line","speaker":"Rómulo Candela","to":["Lidia Giostra","Tommaso Grieco"],"line":"Bienvenidos. Mangiate, per favore. Nessuno confessa bene a stomaco vuoto.","context":"Candela apre il pranzo come se fosse una normale conversazione, ma vuole subito mettere i due sotto pressione."},{"type":"line","speaker":"Lidia Giostra","to":"Rómulo Candela","line":"Ispettore, lei ha detto che sarebbe stato un pranzo informale.","context":"Lidia cerca di riportare controllo e normalità."},{"type":"line","speaker":"Rómulo Candela","to":"Lidia Giostra","line":"Informale, sì. Ho ordinato sin avogados...","context":"Candela risponde con leggerezza, ma le ricorda che è sospettata."},{"type":"line","speaker":"Tommaso Grieco","to":"Rómulo Candela","line":"Se questa è una trappola, almeno ha scelto un buon olio.","context":"Tommaso usa sarcasmo per mostrarsi superiore."},{"type":"line","speaker":"Rómulo Candela","to":"Tommaso Grieco","line":"Gracias. Ma l’olio buono non vale nulla senza un buon pane. E in questo pane manca il sale.","context":"Candela accetta il gioco e lo trasforma in minaccia."},{"type":"line","speaker":"Lidia Giostra","to":"Tommaso Grieco","line":"Tu trovi sempre il modo di sembrare divertente nel momento più inopportuno.","context":"Lidia è irritata da Tommaso e teme che peggiori la situazione."},{"type":"line","speaker":"Tommaso Grieco","to":"Lidia Giostra","line":"E tu trovi sempre il modo di sembrare innocente nel momento più opportuno.","context":"Tommaso contrattacca, insinuando che Lidia stia recitando."},{"type":"line","speaker":"Rómulo Candela","to":["Lidia Giostra","Tommaso Grieco"],"line":"Ay Dios, che bello. Due persone educate che si pugnalano con le posate ancora pulite.","context":"Candela gode della tensione e li incoraggia a esporsi."},{"type":"line","speaker":"Lidia Giostra","to":"Rómulo Candela","line":"Cos''è questa cena? Non siamo ancora andati al funerale della povera Elena e siamo a festeggiare?","context":"Lidia prova a capire quanto Candela abbia scoperto."},{"type":"line","speaker":"Rómulo Candela","to":"Lidia Giostra","line":"Non siamo certo a festeggiare, señora Giostra, ma ho come l''idea che non siamo qui nemmeno per piangere.","context":"Candela resta ambiguo per aumentare l’ansia."},{"type":"line","speaker":"Tommaso Grieco","to":"Rómulo Candela","line":"Allora ci dica perché siamo qui.","context":"Tommaso vuole forzare Candela a scoprire le carte."},{"type":"line","speaker":"Rómulo Candela","to":["Lidia Giostra","Tommaso Grieco"],"line":"Porque uno di voi matò a Elena Vargas.","context":"Candela introduce l’oggetto chiave del caso."},{"type":"line","speaker":"Lidia Giostra","to":"Rómulo Candela","line":"Elena era mia amica. La sua morte è una tragedia. Veleno!? No, non è possibile.","context":"Lidia risponde subito sul piano emotivo, forse troppo in fretta."},{"type":"line","speaker":"Tommaso Grieco","to":"Lidia Giostra","line":"Era amica di tutti quando serviva.","context":"Tommaso insinua che Elena avesse relazioni opportunistiche."},{"type":"line","speaker":"Rómulo Candela","to":"Tommaso Grieco","line":"E nemica di chi, señor Greco?","context":"Candela coglie l’apertura e spinge Tommaso a sbilanciarsi."},{"type":"line","speaker":"Tommaso Grieco","to":"Rómulo Candela","line":"Era una gran donna, Ispettore, energetica e sincera. Nemica solo di chi si metteva sulla sua strada.","context":"Tommaso parla in modo generale, ma sta anche accusando Lidia."},{"type":"line","speaker":"Rómulo Candela","to":"Tommaso Grieco","line":"Allora era nemica del mondo intero...","context":"Candela sdrammatizza, ma tiene il ritmo sotto controllo."},{"type":"stage_direction","action":"Candela versa altra birra nel proprio bicchiere.","context":"Il gesto crea pausa e aumenta il disagio degli altri."},{"type":"line","speaker":"Rómulo Candela","to":["Lidia Giostra","Tommaso Grieco"],"line":"Vale, prima regola del pranzo: chi sbaglia paga la cuenta. Seconda regola: chi mente prende il dolce.","context":"Candela stabilisce un gioco, trasformando l’interrogatorio in performance."},{"type":"line","speaker":"Lidia Giostra","to":"Rómulo Candela","line":"E chi dice la verità?","context":"Lidia cerca una via d’uscita morale."},{"type":"line","speaker":"Rómulo Candela","to":"Lidia Giostra","line":"Chi dice la verita, señora Giostra, non era nella lista degli invitati...","context":"Candela chiude la scena con una minaccia elegante."}]},{"id":"scene_2","title":"Il primo","setting":"Lo stesso tavolo, più tardi. Arrivano i piatti principali. Candela è più rilassato, ma gli altri sono più tesi.","beats":[{"type":"line","speaker":"Rómulo Candela","to":"Lidia Giostra","line":"Lidia, lei ha detto che Elena era soprattutto sua amica. Però il giorno prima della morte ha cancellato dodici messaggi dal WhatsApp.","context":"Candela attacca Lidia che ha cencellato dei messaggi con Lidia."},{"type":"line","speaker":"Lidia Giostra","to":"Rómulo Candela","line":"Erano personali.","context":"Lidia si chiude, cercando di difendere la propria privacy."},{"type":"line","speaker":"Rómulo Candela","to":"Lidia Giostra","line":"Muy bien, andiamo avanti. Cosa c''era nel taccuino di Elena? Quello che la polizia non riesce a trovare?","context":"Candela non insiste sul tasto chiuso, ma cambia subito direzione per spiazzare Lidia con un dettaglio che lei non si aspetta che lui sappia."},{"type":"line","speaker":"Tommaso Grieco","to":"Rómulo Candela","line":"Inspettore, è morta una persona e noi siamo qua a pranzare come fossimo vecchi amici, non crede che sia un po’ irrispettoso?","context":"Tommaso provoca Candela cercando di spostare l’attenzione sulla situazione emotiva."},{"type":"line","speaker":"Rómulo Candela","to":"Tommaso Grieco","line":"Non sia geloso, señor Greco. Arrivo anche da lei.","context":"Candela sposta la pressione su Tommaso."},{"type":"line","speaker":"Rómulo Candela","to":"Tommaso Grieco","line":"Lei ha pubblicato una recensione feroce del ristorante di Elena e Lidia. Poi, il giorno prima del delitto, quest''ultima è sparita dal suo sito. Che coincidenza, no?","context":"Candela mostra che anche Tommaso ha cancellato qualcosa, e che anche lui ha un movente."},{"type":"line","speaker":"Tommaso Grieco","to":"Rómulo Candela","line":"Ho cambiato idea.","context":"Tommaso tenta una spiegazione semplice."},{"type":"line","speaker":"Rómulo Candela","to":"Tommaso Grieco","line":"Parece mentira, ma non importa. Cambiare idea succede.","context":"Candela smonta la difesa con ironia."},{"type":"line","speaker":"Lidia Giostra","to":"Tommaso Grieco","line":"Che cosa c’era nel taccuino, Tommaso?","context":"Lidia sospetta Tommaso e prova a farlo crollare."},{"type":"line","speaker":"Tommaso Grieco","to":"Lidia Giostra","line":"Ma che ne so! Chiedilo a lui. È lui che sta recitando da mezzogiorno.","context":"Tommaso devia la domanda su Candela."},{"type":"line","speaker":"Rómulo Candela","to":"Tommaso Grieco","line":"Secondo me, nel taccuino c''erano i piani di una persona ambiziosa. Troppo ambiziosa per chi aveva intorno, ma non abbastanza per cedere ai ricatti.","context":"Candela lascia intendere di aver risolto il caso."},{"type":"stage_direction","action":"Candela prende una sigaretta sul tavolo e inizia a girarsela tra le dita.","context":"Segnale rituale: Candela è vicino alla soluzione."},{"type":"line","speaker":"Tommaso Grieco","to":"Rómulo Candela","line":"Che cosa sta insinuando, ispettore?","context":"Tommaso sente la pressione e prova a smontare l''accusa indiretta esigendo che Candela parli chiaro: vuole forzare la mano per non restare nel vago."},{"type":"line","speaker":"Rómulo Candela","to":"Lidia Giostra","line":"A ver! Lidia, se non mangia il piatto si freddarà.","context":"Candela ignora deliberatamente la domanda di Tommaso e cambia bersaglio: usa una battuta sul cibo per ricordare che è lui a decidere ritmo e regole del pranzo."},{"type":"line","speaker":"Lidia Giostra","to":"Rómulo Candela","line":"Non ho appetito, voglio sapere cosa sta insinuando.","context":"Lidia è stanca dei giochi di Candela e vuole chiarezza."},{"type":"line","speaker":"Rómulo Candela","to":["Lidia Giostra","Tommaso Grieco"],"line":"Non sto insinuando niente. Sto solo dicendo che ci sono alcuni dettagli da chiarire.","context":"Candela resta vago, ma la sua insistenza fa capire che sa chi è il colpevole."},{"type":"line","speaker":"Tommaso Grieco","to":"Rómulo Candela","line":"[Alzandosi in piedi] Io non ho ricattato nessuno!","context":"Tommaso perde la maschera del distacco sarcastico ed esplode: la parola \\"ricatto\\" lo ha colpito sul vivo, scopre più di quanto vorrebbe."},{"type":"line","speaker":"Rómulo Candela","to":"Tommaso Grieco","line":"Si sieda, senor Griego, dobbiamo finire il pranzo prima di arrabbiarci.","context":"Candela riporta l''ordine con autorità giocosa: il pranzo è il suo palcoscenico, e nessuno se ne va prima che lui lo decida."},{"type":"stage_direction","action":"L''ispettore candela posa teatralmente la sigaretta sul tavolo.","context":"Gesto rituale che chiude la fase del primo: Candela ha finito di stuzzicare e sta preparando il colpo finale del dolce."}]},{"id":"scene_3","title":"Il dolce","setting":"Il pranzo continua nel silenzio, i camerieri portano via i piatti mezzi pieni degli indiziati e quello dove l''Ispettore ha fatto scarpetta con il sugo. All''arrivo del dolce Candela prende la parola.","beats":[{"type":"line","speaker":"Rómulo Candela","to":["Lidia Giostra","Tommaso Grieco"],"line":"Compañeros! Finalmente il dolce!","context":"Candela apre l''atto finale con falsa allegria conviviale."},{"type":"line","speaker":"Lidia Giostra","to":["Rómulo Candela","Tommaso Grieco"],"line":"Questa sceneggiata è durata fin troppo! Non ho intenzione di farmi predendere in giro ulteriolmente. E'' una vergogna per la memoria della povera Elena!","context":"Lidia è al limite, si rifiuta di continuare il pasto."},{"type":"line","speaker":"Tommaso Grieco","to":"Rómulo Candela","line":"Esattamente, è una vergogna. Ed oltre tutto il cibo è a dir poco mediocre.","context":"Tommaso conferma e rincara la dose criticando il cibo."},{"type":"stage_direction","action":"Lidia e Tommaso fanno per alzarsi e andare via.","context":"Tentativo di fuga coordinato: i due capiscono che restando si scoprono e provano a sfuggire al gioco di Candela."},{"type":"line","speaker":"Rómulo Candela","to":["Lidia Giostra","Tommaso Grieco"],"line":"Paren! Vale, quindi questo è il limite di un assassino.","context":"Candela li blocca con una frase-trappola, colpevolizzandoli."},{"type":"stage_direction","action":"Candela prende la sigaretta e se la accende, mentre Tommaso e Lidia rimangono in piedi accanto al tavolo.","context":"Pausa drammatica: Candela si prende il suo tempo, sa di aver vinto e lascia che il silenzio faccia crollare i due."},{"type":"line","speaker":"Tommaso Grieco","to":"Lidia Giostra","line":"Oh mio dio Lidia! Sei stata tu davvero, l''hai uccisa perchè voleva vendere il ristorante ai tedeschi, tagliandoti fuori. Me lo ha detto sai!?","context":"Tommaso scarica per primo: accusa Lidia con un dettaglio specifico per togliersi di dosso il sospetto."},{"type":"line","speaker":"Lidia Giostra","to":"Tommaso Grieco","line":"Io!? E tu invece, lurido schifoso, lo so che hai minacciato di farci fallire se non avesse accettato di uscire con te. Schifoso maiale! Sicuramente l''hai uccisa tu!","context":"Lidia controattacca furiosa: rivela il ricatto sentimentale di Tommaso per ribaltare l''accusa e per pura rabbia accumulata."},{"type":"line","speaker":"Tommaso Grieco","to":"Lidia Giostra","line":"Cosa c''era in quei messaggi che hai eliminato, eh!? L''avevi forse invitata al ristorante per ucciderla? Avevi preparato TU una cena per scusarti? Scusarti col veleno! Assassina!","context":"Tommaso vuole spingere Lidia al crollo definitivo davanti a Candela."},{"type":"line","speaker":"Lidia Giostra","to":"Tommaso Grieco","line":"Aaaaah certo! Io volevo scusarmi per le mie sfuriate. Ma tu! Tu che hai cancellato la recensione che ci avrebbe fatto fallire, solo quando lei ha accettato di uscire con te a cena. Mi ha detto di cucinare per due per una cena di affari, ma per te quegli affari non erano abbastanza. Viscido maiale!","context":"Lidia confessa la propria parte ma rivela il ricatto di Tommaso e si racconta come vittima."},{"type":"line","speaker":"Tommaso Grieco","to":"Rómulo Candela","line":"Ispettore Candela, mi scuso con lei, ora capisco che ci ha portato qui per arrestare questa pazza omicida! E'' vero, ero a cena con Elena quella sera e LEI deve averle avvelenato il cibo.","context":"Tommaso prova a fingersi alleato di Candela contro Lidia."},{"type":"line","speaker":"Lidia Giostra","to":"Rómulo Candela","line":"Ispettore Candela, io non ho fatto niente di tutto ciò! Lui. Lui. Lui! Deve averla avvelenata mentre non guardava. Avrama messo il veleno nel piatto mentre era in bagno! Arresti questo criminale!","context":"Lidia rispecchia la mossa di Tommaso e inventa una ricostruzione plausibile."},{"type":"stage_direction","action":"Candela continua a fumare, calmo, guardando i suoi commensali","context":"Padronanza assoluta della scena: Candela li lascia distruggersi a vicenda perché ogni accusa reciproca aggiunge un pezzo alla sua ricostruzione."},{"type":"line","speaker":"Rómulo Candela","to":"Tommaso Grieco","line":"El veneno, non estaba nel cibo.[Pausa] Lei non beve vero, senor Griego?","context":"Candela smonta in un colpo entrambe le accuse precedenti e introduce il fatto che Tommaso non beve."},{"type":"line","speaker":"Tommaso Grieco","to":"Rómulo Candela","line":"Bevo solo per lavoro. Assaggio gli accostamenti con le pietanze, ma non gradisco il mal di testa, sono una persona seria che può perdere minimente il controllo.","context":"Tommaso si difende con un alibi professionale e si vanta di autocontrollo."},{"type":"line","speaker":"Rómulo Candela","to":"Lidia Giostra","line":"Ay, Ay. E lei Lidia, immagino che abbia apparacchio per scusarsi con la sua amica.","context":"Candela con tono dolce induce Lidia a vantarsi del dettaglio che la incrimina, l''apparecchiatura."},{"type":"line","speaker":"Lidia Giostra","to":"Rómulo Candela","line":"Certo avevo predisposto l''apparecchiatura dei grandi eventi. Il tavolo migliore con i coperti delle grandi occasioni.","context":"Lidia conferma orgogliosa di aver preparato lei la tavola."},{"type":"line","speaker":"Rómulo Candela","to":["Lidia Giostra","Tommaso Grieco"],"line":"Il veneno era sia nel bicchiere che nel vino, due mezze dosi che insieme sono state fatali. Un gran mal di pancia si è trasformato in muerte.","context":"Candela rivela il meccanismo del delitto: due dosi separate, una nel bicchiere preparato da Lidia, una nel vino versato da Tommaso, ognuna innocua da sola."},{"type":"line","speaker":["Tommaso Grieco","Lidia Giostra"],"to":"Rómulo Candela","line":"Non l''ho uccisa io!","context":"Reazione corale e quasi simultanea: ognuno dei due urla di non essere l''assassino."},{"type":"line","speaker":"Rómulo Candela","to":["Lidia Giostra","Tommaso Grieco"],"line":"Lidia tu mataste per sopravvivenza. [Pausa] Tu invece mataste per desiderio, il più classico dei delitti. Vittima e boia in un''inaspettata collaborazione. La mataron juntos...","context":"Candela pronuncia la sentenza con calma teatrale: assegna a ciascuno il proprio movente — Lidia per non perdere il ristorante, Tommaso per gelosia — e li unisce in un destino condiviso."},{"type":"stage_direction","action":"Lidia e Tommaso crollano sulle sedie, devastati dalla realizzazione. Candela si gira sornione verso il pubblico","context":"Crollo finale dei due colpevoli; Candela rompe la quarta parete e diventa narratore, spostando il caso dal tavolo alla platea."},{"type":"line","speaker":"Rómulo Candela","to":"Pubblico","line":"¿Y tú, a quién matasteis?","context":"Battuta finale di Candela rivolta al pubblico: gioco metateatrale che chiude lo spettacolo trasformando l''accusa in una domanda diretta agli spettatori."}]}],"description":"Elena Vargas è stata avvelenata durante un pranzo al suo ristorante. L’ispettore Rómulo Candela interroga i due sospetti principali, la collega Lidia Giostra e il critico gastronomico Tommaso Grieco, in un confronto teso e ironico che si svolge tutto a tavola."}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('Il Tutore', 'lettura', 'it', NULL, 3, 2, '{"characters":[{"name":"Guadalberto","description":"Il figlio. Un giovane sveglio e razionale che studia per diventare dotto."},{"name":"Adalberto","description":"Il padre. Un ricco mercante sempre intento a fare affari e al guadagno."},{"name":"Magister Foscafides","description":"Un losco alchimista fiammingo, forse un ciarlatano, forse un demonio."}],"scenes":[{"id":"scene_1","title":"Scena 1","setting":"Guadalberto è immerso nello studio alla sua scrivania, sommerso da fogli e manoscritti, quando entra senza bussare o annunciarsi il padre, Adalberto.","beats":[{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"Buongiorno, filius meus, vedo che siete molto indaffarato.","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Buongiorno padre! Qual buon vento vi porta nelle mie stanze?","context":""},{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"Mi è giunta voce che ormai da tempo vi state trastullando su fanfole e diavolerie non consone ad un buon Cristiano. Negate?","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Messer padre! La filosofia di Natura e lo studio dell''operato del nostro Creatore non sono certo opera del diavolo!","context":""},{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"Ebbene! Se vuoi perdere la tua anima non mi interessa, ma già che ne va anche del mio buon nome ho deciso che almeno il tuo operato porti guadagno alla nostra famiglia.","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Ovvero babbo caro? Mi manderete forse all''Università di Bologna dove potrò far brillare il nome dei nostri tra quelli dei più grandi eruditi d''Europa?","context":""},{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"Assolutamente no. Ho deciso che invece di studiare questa tua scienza senza futuro ti prodigherai in qualcosa di più concreto. Come l''Alchimia.\\n[Batte le mani]","context":""},{"type":"stage_direction","action":"Entra nella stanza il Magister, Guadalberto si alza in piedi.","context":""},{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"Ti presento il Magister Johannes Foscafides l''Alchimista, l''ho fatto arrivare direttamente dalle Fiandre per formarti come Alchimista, così da ottimizzare al meglio la tua dannazione eterna.","context":""},{"type":"line","speaker":"Guadalberto","to":"Magister Foscafides","line":"Magister, vi porgo il mio saluto e mi presento: Gaudalberto, di Adalberto, di un altro Guardalberto, di Bentivoglio, di Giovanni, di Alberto.","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Guadalberto","line":"Io v''odo, figliuolo, e vostro padre Ser Adalberto, di Guadalberto, di Bentivoglio, di Giovanni, di Alberto, già mi introdusse e mi parlò di voi e delle vostre contorsioni intellettuali...","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Parlo con licenza padre e mi mena dire che, con tutto il rispetto, l''Alchimia è un esercizio che ha poco a che spartire con la mia ricerca del vero. Anzi da ciò che so pare spesso è adoperata dai ciarlatani per spillare danari agli ingenui.","context":""},{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"Le parole che usi per offendere Nostro Signore sono solo un minimo dettaglio del peccato! Però se nel mentre riesci a trasformare il piombo in oro almeno ci guadagno...","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Adalberto","line":"Il giovane ha ragione, Ser Adalberto, ci sono molti ciarlatani che si fingono dottori...","context":""},{"type":"line","speaker":"Guadalberto","to":"Magister Foscafides","line":"[Scrutando la collana del Magister] Ma... Magister Johannes, con devozione... voi portate al collo un crocifisso rovesciato!? Che Dio ci protegga!","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Guadalberto","line":"Aaah questo... nooo, no... questo fu... fatto... un''opera di carità... me lo feci fare da un fabbro... cieco, per dargli opera e sfamar la sua famiglia..","context":""},{"type":"line","speaker":"Adalberto","to":"Magister Foscafides","line":"Ah ma che brava persona che è lei Magister Foscafides! Bene adesso mi licenzio e vi lascio alla vostra prima lezione e mi aspetto, come da sua promessa, di veder dell''oro in questa stanza entro la fine della giornata. [Esce]","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Guadalberto","line":"[Scrutando i fogli sulla scrivania] Molto bene, figliuolo, vedo che ti sei prodigato molto nello studio della natura e degli astri. Ma ti serviranno a poco perché da oggi imparerai un arte che va OLTRE la natura.","context":""},{"type":"line","speaker":"Guadalberto","to":"Magister Foscafides","line":"Oltre la natura? Impossibile!","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Guadalberto","line":"[Alzando le braccia al cielo] OLTRE LA NATURA E OLTRE LA RAGIONEEE...","context":""},{"type":"line","speaker":"Guadalberto","to":"Magister Foscafides","line":"La ragio.... Ma le vostre mani, portate ai polsi... Padreeeeeee! Padreeeee! Accorrete!","context":""},{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"[Entrando correndo] Accorro! Accorro! Eccomi, è già l''oro!? E le gemme preziose?","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Ma Messer Padre, al contrario, il vostro magister qui porta pesanti ceppi di ghisa ai polsi e li muove come fossero seta! Ora che li veggo meglio sono anche marchiati col simbolo del Sant''Uffizio.  Quest''uomo è chiaramente un eretico, se non proprio un demonio!","context":""},{"type":"line","speaker":"Magister Foscafides","to":["Guadalberto","Adalberto"],"line":"Aaah queste, nooo, no. Sono... per penitenza... contro il peccato... originale. Me le ha fatte fare il Papa in persona dopo che riconobbe la mia estrema... devozione. [Risata molto malefica]","context":""},{"type":"line","speaker":"Adalberto","to":"Magister Foscafides","line":"Ah ma ovvio. Non sapevo che voi foste un tale uomo di fede Magister! Sarà per questo che Nostro Signore ha donato solo a voi la capacità di trasformare le cose in oro!","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Adalberto","line":"[Leccandosi le labbra] Mmmh... si infatti. Sono estremamente devoto al mio Signore, ed Egli mi ricompesa abbondantemente. Sì, sì, abbondantemente.","context":""},{"type":"line","speaker":"Adalberto","to":["Magister Foscafides","Guadalberto"],"line":"Siete veramente un brav''uomo Magister Foscafides. E tu Guadalberto vedi di non far più perdete tempo nè a me nè all''eminentissimo Magister. [Esce]","context":""},{"type":"line","speaker":"Guadalberto","to":"Magister Foscafides","line":"Come desideri padre... Magister, chieggo vostra perdonanza. Non fu mia intenzione offendervi. Se mi perdonate, chiedo di veder questi ceppi in luce buona.","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Guadalberto","line":"No! No i ceppi sono miei e miei soltanto. Ma non v’affliggete. Ogni uomo... falla.","context":""},{"type":"line","speaker":"Guadalberto","to":"Magister Foscafides","line":"Vi sia reso grazie, Maestro... non vi darò cagione di nuovo fallo, però vorrei davvero vedere codesti ceppi...","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Guadalberto","line":"Ti farò vedere ben di meglio, Messer Guadalberto. E ti imparerò che le cose importanti non le si guardano con gli occhi...","context":""},{"type":"line","speaker":"Guadalberto","to":"Magister Foscafides","line":"E con cosa, oh immenso Magister?","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Guadalberto","line":"Prima dobbiamo trovare un caprone dalle corna nere, un coltello arrugginito, due galloni di sangue di vergine ...","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Padreeee! Padre presto, accorete!.","context":""},{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"[Entra] Eccomi, eccomi, accorro! Dove sono i preziosi e le pietre? Avete trasformato i chiodi in oro? O i candelabri?","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Niente di tutto ciò, oh Padre Mio. Il Magister richiede caproni, coltelli e sangue di vergine. Vuole richiamare il Satanasso! Che dio ci protegga!","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Adalberto","line":"Noo... il sangue... no... Se mi fate finire, il sangue di vergine bovina... per una pozione che trasforma tutto.... in oro... tutto tutto. Serve anche carbone di quercia e delle belle... belle corna di capra. Molto belle.","context":""},{"type":"line","speaker":"Adalberto","to":["Magister Foscafides","Guadalberto"],"line":"Magister Foscafides, mi rallegro di sapere che ci avviciniamo. Molto bene, lei è un vero uomo di parola. E tu Guadalberto smettila di interrompere il Magister e mettiti a lavoro. [Esce]","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Chieggo vostra licenza e misericordia, Magister. Mea culpa ancora.","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Guadalberto","line":"Non vi affliggete Messere, non è cosa. Ma piuttosto ditemi, siete voi per caso vergine?","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Padreeeeeeee! Padreeeeeeeeeeee!","context":""}]},{"id":"scene_2","title":"Scena 2","setting":"Studio di Gaudalberto, le carte sulla sua scrivania sono carbonizzate.  Guadalberto,visibilmente scioccato, richiama il padre per l''ennesima volta, che rientra nello studio ormai fuori di se. Il Magister sta visibilmente masticando una testa di serpente.","beats":[{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"Per il beato nome della Vergine Maria santissima madre di Gesù Cristo, Adalberto! Hai rotto il cazzo! Cosa vuoi ora?","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Il Magister ha elencato parole proibite in Alamanno e in Goto, masticando la testa di un serpente velenoso e la mia scrivania ha preso fuoco! Ora mi credete che è il demonio?!?","context":""},{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"Guadalberto, ora basta! Smettetela di accusare questo sant''uomo di eresia, gli avete già trovato mille colpe e lui vi ha risposto con mille virtù. Adesso presenzierò anche io allo studio in modo da tenervi in buona disciplina, per Dio!","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Adalberto","line":"[Sputa resti di serpente] In ciò operate con prudenza, Ser Adalberto. [Sputa] Al giovane non gli manca il senno, ma l’applicazione! Potrebbe molto... se volesse...","context":""},{"type":"line","speaker":"Guadalberto","to":"Guadalberto","line":"Oh le mie pergamene! Il mio studio! L''opera mia! Tutto perduto nelle fiamme infernali di codesto lestofante!","context":""},{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"Cheta, figliuolo e non t''accendere. Hai fatto fallo l''ultima volta. Adesso taci e ascolta il Magister tuo.","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Vi ubbidirò, padre, ma il cuore non se ne persuade e porto dubbio.","context":""},{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"Che vi paia o no, così sarà. Prego Magister procedete, che il sole già ci lascia.","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Adalberto","line":"Aaaaaah... già... il sole si ritira... La luce fugge e lascia il mondo a pensieri meno pii... il giorno ci nega la sua compagnia e io con lui... debbo andare...","context":""},{"type":"line","speaker":"Adalberto","to":"Magister Foscafides","line":"Già ve ne andate? Ah! Le operazioni alchemiche richiedono il chiarore?","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Oppure a buio fatto gli spuntan artigli di belva e fauci da fiera!","context":""},{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"Chetati Adalberto! E fa parlare il Magister.","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Adalberto","line":"Molte cose... mutano... nelle grinfie della notte... E i miei saperi e le mie arti è meglio farli quando brilla... per sicurezza...","context":""},{"type":"line","speaker":"Adalberto","to":"Magister Foscafides","line":"Ma non vorrete lasciarci proprio ora, Magister? Se v''è prudenza nei vostri saperi, allora restate ancora un poco... finché il sole concede il suo favore.","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Adalberto","line":"NO! noooo, no.... la prudenza mia mi dice di congedarmi, e io l''ascolto perché non vi fu mai virtù più rara.","context":""},{"type":"line","speaker":"Adalberto","to":"Magister Foscafides","line":"Così sia, mi rimetto al vostro giudizio, l''oro allora sarà domani?","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Adalberto","line":"Si e a proposito... fatemi trovare alcune cose domani... se la signoria vostra lo permette. Limatura di ferro raccolta da lama usata in guerra, sette spine prese da sette rose nere, la terra presa da un incrocio di 3 strade e molto zolfo... molto molto zolfo... 666 libbre....","context":""},{"type":"line","speaker":"Guadalberto","to":"Adalberto","line":"Padre, vi imploro! E'' ridicolo questi oggetti sono chiaramente per una maledizione. Quest''uomo è un mago o uno stregone mandato dal demonio per ingannarci!","context":""},{"type":"line","speaker":"Adalberto","to":"Guadalberto","line":"Ancora vi ricadi? Parli con poca riverenza e minor sapere. Ciò che serve serve e il Magister lo avrà. Manderò subito i miei servi ad operarsi, perché domani farai l''oro, giusto?","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Adalberto","line":"Si.... si... Si può cambiare il piombo in oro…","context":""},{"type":"line","speaker":"Magister Foscafides","to":"Pubblico","line":"[Avvicinandosi al pubblico] ma gli uomini…gli uomini non cambiano mai.","context":""}]}],"description":"Siamo alle porte del Rinascimento ed il ricco mercante Adalberto si preoccupare degli interessi del figlio minore Gaudalberto. Decide quindi di affidarlo ad un tutore perchè possa formarlo adeguatamente in qualcosa di utile per la famiglia."}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('I Fraticelli', 'lettura', 'it', NULL, 4, 1, '{"characters":[{"name":"Fra Bozzo","description":"Frate corpulento e bonario. Ama la minestra, il vino leggero e il riposo. Ha una fede semplice e pratica, fatta più di abitudini che di teologia."},{"name":"Fra Cinghiale","description":"Frate impulsivo e sanguigno. Difende la fede con ardore, ma ragiona poco prima di parlare. Si scandalizza facilmente."},{"name":"Fra Milzio","description":"Frate giovane, curioso e studioso. Non vuole provocare, ma ogni sua domanda sincera apre una crepa nelle certezze degli altri."},{"name":"Frate Cardo","description":"Frate anziano e contemplativo. Parla piano, cerca equilibrio e pace, ma sotto la sua calma si nasconde un dubbio antico."}],"scenes":[{"id":"scene_1","title":"Il chiostro","setting":"Chiostro di un piccolo convento, al tramonto. I quattro frati sono seduti o passeggiano lentamente. Una campana lontana annuncia quasi il vespro.","beats":[{"type":"line","speaker":"Fra Bozzo","to":"Gruppo","line":"Io ve lo dico con cuore aperto: se il Signore non voleva che l’uomo amasse la minestra, non avrebbe inventato le lenticchie.","context":"Bozzo parla con soddisfazione dopo aver mangiato. La sua fede è concreta e gastronomica."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Bozzo","line":"Il Signore non ha inventato le lenticchie per la tua gola, Fra Bozzo, ma per la nostra umiltà.","context":"Cinghiale rimprovera Bozzo, ma in modo più teatrale che realmente severo."},{"type":"line","speaker":"Fra Bozzo","to":"Fra Cinghiale","line":"Allora io mi umilio volentieri anche domani.","context":"Bozzo risponde con semplicità comica."},{"type":"line","speaker":"Frate Cardo","to":"Gruppo","line":"Lasciatelo stare. Ogni anima trova il Creatore dove può. Alcune nella Scrittura, altre nel brodo caldo.","context":"Cardo media con dolcezza e ironia."},{"type":"line","speaker":"Fra Milzio","to":"Frate Cardo","line":"Frate Cardo, se ogni anima trova Dio dove può, vuol dire che Dio sta in ogni cosa?","context":"Milzio fa una domanda ingenua, ma già potenzialmente pericolosa."},{"type":"line","speaker":"Frate Cardo","to":"Fra Milzio","line":"In certo modo sì, fratello. Tutto il creato porta il segno del suo Creatore.","context":"Cardo risponde con prudenza."},{"type":"line","speaker":"Fra Milzio","to":"Gruppo","line":"Anche le pulci?","context":"Milzio porta la riflessione su un esempio basso e comico."},{"type":"line","speaker":"Fra Bozzo","to":"Fra Milzio","line":"Nelle pulci il Signore ha messo soprattutto la sua pazienza.","context":"Bozzo prova a restare leggero."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Milzio","line":"Non si ragiona di pulci quando si ragiona di Dio!","context":"Cinghiale si scandalizza."},{"type":"line","speaker":"Fra Milzio","to":"Fra Cinghiale","line":"E perché no? Se Dio le ha fatte, forse ci ha ragionato prima di farle.","context":"Milzio insiste con logica sincera."},{"type":"line","speaker":"Fra Cinghiale","to":"Gruppo","line":"Dio non ragiona come noi.","context":"Cinghiale usa una formula difensiva."},{"type":"line","speaker":"Fra Milzio","to":"Fra Cinghiale","line":"Allora quando diciamo che una cosa è giusta, come sappiamo che è giusta anche per Lui?","context":"Milzio apre la prima vera crepa: rapporto tra morale umana e volontà divina."},{"type":"line","speaker":"Fra Bozzo","to":"Fra Milzio","line":"Io per sicurezza direi che è giusto ciò che non ci fa beccar frustate.","context":"Bozzo cerca di sgonfiare il ragionamento."},{"type":"line","speaker":"Frate Cardo","to":"Fra Milzio","line":"Sappiamo poco, Milzio. Ma crediamo molto.","context":"Cardo prova a riportare il discorso sul terreno della fede."},{"type":"line","speaker":"Fra Milzio","to":"Frate Cardo","line":"E se crediamo molto perché sappiamo poco?","context":"Seconda crepa: la fede come risposta all’ignoranza."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Milzio","line":"Questa è una frase da scrivere, bruciare e poi confessare.","context":"Cinghiale tenta di fermarlo con autorità comica."},{"type":"line","speaker":"Frate Cardo","to":"Fra Cinghiale","line":"In quest’ordine?","context":"Cardo nota l’assurdità pratica."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Bozzo","line":"Prima confessare, poi bruciare.","context":"Cinghiale si corregge confuso."},{"type":"line","speaker":"Fra Milzio","to":"Gruppo","line":"Io non voglio perdere la fede. Voglio solo capire dove finisce il capire e dove comincia il credere.","context":"Milzio chiarisce la sua intenzione: non è ribelle, è curioso."},{"type":"line","speaker":"Frate Cardo","to":"Fra Milzio","line":"Comincia dove l’uomo si inginocchia.","context":"Cardo dà una risposta bella, ma fragile."},{"type":"line","speaker":"Fra Milzio","to":"Frate Cardo","line":"E se uno si inginocchia perché ha paura?","context":"Terza crepa: fede e paura."},{"type":"line","speaker":"Fra Bozzo","to":"Gruppo","line":"Io mi inginocchio spesso perché mi fanno male i piedi.","context":"Bozzo prova ancora a riportare tutto al corpo."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Milzio","line":"La paura di Dio è santa!","context":"Cinghiale difende la dottrina con foga."},{"type":"line","speaker":"Fra Milzio","to":"Fra Cinghiale","line":"Ma se uno ama Dio perché ha paura dell’inferno, ama Dio o ama la propria salvezza?","context":"Milzio mette in crisi la purezza della devozione."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Milzio","line":"Tu parli troppo.","context":"Cinghiale non sa rispondere e passa all’attacco."},{"type":"line","speaker":"Fra Milzio","to":"Fra Cinghiale","line":"Chiedo solo se sapete, siamo qui a far domande.","context":"Milzio accetta la critica senza difendersi."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Milzio","line":"Tu se l''unico a far domande!","context":"Cinghiale non sa rispondere e passa all’attacco."},{"type":"line","speaker":"Frate Cardo","to":"Gruppo","line":"Forse non tutto l’amore nasce puro. Forse diventa puro camminando.","context":"Cardo tenta una via spirituale e poetica."},{"type":"line","speaker":"Fra Bozzo","to":"Frate Cardo","line":"Come il vino?","context":"Bozzo traduce tutto in esperienza concreta."},{"type":"line","speaker":"Frate Cardo","to":"Fra Bozzo","line":"Il vino non cammina, fratello.","context":"Cardo lascia passare la metafora."},{"type":"line","speaker":"Fra Milzio","to":"Gruppo","line":"Se Dio conosce tutto prima che avvenga, conosce anche ogni nostro peccato prima che lo commettiamo?","context":"Milzio apre la questione della prescienza divina."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Milzio","line":"Certo. Nostro signore sa tutto e vede tutto.","context":"Cinghiale risponde d’istinto."},{"type":"line","speaker":"Fra Milzio","to":"Fra Cinghiale","line":"E se lo conosce prima, non potrebbe impedircelo?","context":"Milzio introduce il problema del libero arbitrio."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Milzio","line":"Certo, nella sua immensa misericordia.","context":"Cinghiale risponde ancora d’istinto, ma si mette in trappola."},{"type":"line","speaker":"Fra Milzio","to":"Fra Cinghiale","line":"Allora Dio può fermare il male ma decide di non farlo?","context":"Milzio chiude il ragionamento con calma."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Milzio","line":"No.","context":"Cinghiale si irrigidisce."},{"type":"line","speaker":"Fra Milzio","to":"Fra Cinghiale","line":"Allora non possiamo non commetterlo.","context":"Milzio mostra l’altro corno del dilemma."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Milzio","line":"Neanche.","context":"Cinghiale rifiuta entrambe le conclusioni."},{"type":"line","speaker":"Fra Bozzo","to":"Gruppo","line":"Signore mio, queste lenticchie.","context":"Bozzo sintetizza comicamente il paradosso."},{"type":"line","speaker":"Frate Cardo","to":"Fra Milzio","line":"Il tempo degli uomini non è il tempo di Dio.","context":"Cardo usa una risposta teologica più raffinata."},{"type":"line","speaker":"Fra Milzio","to":"Frate Cardo","line":"Allora quando preghiamo, Lui ci ha già ascoltati?","context":"Milzio sposta il problema sulla preghiera."},{"type":"line","speaker":"Frate Cardo","to":"Fra Milzio","line":"Sì.","context":"Cardo risponde, ma con meno sicurezza."},{"type":"line","speaker":"Fra Milzio","to":"Frate Cardo","line":"E ha già deciso?","context":"Milzio stringe la questione."},{"type":"line","speaker":"Frate Cardo","to":"Fra Milzio","line":"La volontà divina non muta per capriccio.","context":"Cardo tenta di preservare la perfezione divina."},{"type":"line","speaker":"Fra Milzio","to":"Gruppo","line":"Allora perché pregare per cambiare ciò che è perfetto?","context":"Quarta crepa: funzione della preghiera."},{"type":"stage_direction","action":"Silenzio. Si sente una rondine passare sopra il chiostro.","context":"Il ragionamento ha prodotto un vuoto reale."},{"type":"line","speaker":"Fra Bozzo","to":"Gruppo","line":"Io prego spesso che la minestra non sia annacquata.","context":"Bozzo rompe il silenzio con una battuta."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Bozzo","line":"Fratello Bozzo, tu non hai nessun altro posto dove andare?","context":"Cinghiale chiede senza accorgersi di peggiorare la questione."},{"type":"line","speaker":"Fra Bozzo","to":"Fra Cinghiale","line":"Perchè me lo chiedi?","context":"Bozzo risponde con triste onestà."},{"type":"line","speaker":"Fra Cinghiale","to":"Gruppo","line":"La preghiera non serve a cambiare Dio. Serve a cambiare noi.","context":"Cinghiale trova una risposta efficace, sorprendentemente."},{"type":"line","speaker":"Fra Milzio","to":"Fra Cinghiale","line":"E ci cambia?","context":"Milzio mette alla prova la risposta."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Milzio","line":"Dovrebbe.","context":"Cinghiale perde sicurezza."},{"type":"line","speaker":"Fra Milzio","to":"Fra Cinghiale","line":"E se non ci cambia?","context":"Milzio continua con gentilezza."},{"type":"line","speaker":"Fra Bozzo","to":"Gruppo","line":"Forse la diciamo male.","context":"Bozzo offre una spiegazione semplice e quasi tenera."},{"type":"line","speaker":"Frate Cardo","to":"Fra Bozzo","line":"O forse la diciamo per essere sentiti dagli altri frati.","context":"Cardo lascia emergere un dubbio morale sulla devozione esteriore."},{"type":"line","speaker":"Fra Cinghiale","to":"Frate Cardo","line":"Frate Cardo!","context":"Cinghiale è sconvolto che il dubbio venga dall’anziano."},{"type":"line","speaker":"Frate Cardo","to":"Fra Cinghiale","line":"Che vuoi? Ti ho sentito pregare nella tua cella sai?","context":"Cardo ammette una fragilità antica."},{"type":"line","speaker":"Fra Milzio","to":"Frate Cardo","line":"Voi dubitate, padre?","context":"Milzio vede che non è solo."},{"type":"line","speaker":"Frate Cardo","to":"Fra Milzio","line":"Io? No. Io ho solo imparato a chiamare certe nebbie con il loro nome.","context":"Cardo ammette senza ammettere."},{"type":"line","speaker":"Fra Bozzo","to":"Frate Cardo","line":"E come le chiamate?","context":"Bozzo chiede con innocenza."},{"type":"line","speaker":"Frate Cardo","to":"Fra Bozzo","line":"Mistero.","context":"Cardo dà una risposta bella ma difensiva."},{"type":"line","speaker":"Fra Milzio","to":"Frate Cardo","line":"E come sappiamo quando è mistero e quando è solo ignoranza vestita bene?","context":"Quinta crepa: il linguaggio religioso come copertura."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Milzio","line":"Basta! Andate a fare penitenza o vado a chiamare l’abate!","context":"Cinghiale esplode."},{"type":"line","speaker":"Fra Milzio","to":"Fra Cinghiale","line":"Ho detto qualcosa di empio?","context":"Milzio è sincero, non provocatorio."},{"type":"line","speaker":"Fra Cinghiale","to":"Fra Milzio","line":"Non lo so, ed è questo che mi turba.","context":"Cinghiale confessa il proprio disorientamento."},{"type":"stage_direction","action":"Le campane del vespro cominciano a suonare.","context":"La chiamata alla preghiera interrompe il ragionamento."},{"type":"line","speaker":"Fra Bozzo","to":"Gruppo","line":"È il vespro.","context":"Bozzo nomina l’interruzione."},{"type":"line","speaker":"Fra Cinghiale","to":"Gruppo","line":"Andiamo a messa.","context":"Cinghiale si aggrappa al gesto rituale."},{"type":"line","speaker":"Fra Milzio","to":"Fra Cinghiale","line":"Per chiedere cosa?","context":"Milzio, ormai, non può più non domandare."},{"type":"line","speaker":"Frate Cardo","to":"Fra Milzio","line":"Non si prega per chiedere, fratello caro. Si prega per pregare.","context":"Cardo cerca una forma di fede senza domanda."},{"type":"line","speaker":"Fra Bozzo","to":"Gruppo","line":"Allora per stare zitti insieme?","context":"Bozzo trova una soluzione semplice, quasi mistica."},{"type":"line","speaker":"Frate Cardo","to":"Fra Bozzo","line":"Perché no? Meglio che star qui con voi.","context":"Cardo accoglie la semplicità di Bozzo."},{"type":"line","speaker":"Fra Cinghiale","to":"Gruppo","line":"Sicuramente non si pecca a stare zitti, anche se mi basta stare qui accanto a voi per sentire le fiamme dell’inferno che mi leccano i piedi.","context":"Cinghiale pronuncia il dubbio più grande."},{"type":"stage_direction","action":"I quattro restano immobili. Le campane continuano.","context":"La fede non è scomparsa del tutto, ma non è più solida come prima."},{"type":"line","speaker":"Fra Bozzo","to":"Gruppo","line":"Io sicuramente ci vado.","context":"Bozzo sceglie il gesto, anche senza aver risolto il pensiero."},{"type":"line","speaker":"Fra Milzio","to":"Fra Bozzo","line":"Per fede?","context":"Milzio chiede l’ultima definizione."},{"type":"line","speaker":"Fra Bozzo","to":"Fra Milzio","line":"L''abate leva la minestra a chi non prega al vespro.","context":"Bozzo chiude con una frase semplice e ambigua."},{"type":"stage_direction","action":"Escono lentamente verso la cappella. Frate Cardo resta un istante indietro, guarda il chiostro vuoto, poi segue gli altri.","context":"Finale sospeso: non una perdita totale della fede, ma una fede diventata fragile."}]}],"description":"Quattro frati chiacchierano nel chiostro. Partendo da osservazioni quotidiane, cominciano a farsi domande sulla fede, sulla preghiera, sul libero arbitrio e sul mistero. Ogni risposta apre una crepa, finché resta solo il gesto comune di andare a pregare."}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('La Rinascita', 'lettura', 'it', 'Mecha Padre Pio', 3, 3, '{"description":"Primo episodio della saga di Mecha Padre Pio. In un laboratorio segreto, uno scienziato e il Cardinale Porpora riportano in vita Padre Pio grazie a scienza, meccanica e intelligenza artificiale sacra. Ma la creatura rinata si trova divisa tra miracolo e macchina, fede e tecnologia. Alla fine sceglierà una nuova missione.","characters":[{"name":"Mecha Padre Pio","description":"Padre Pio riportato in vita in corpo meccanico. Saggio ma turbato, cerca di capire se possiede ancora anima, fede e libero arbitrio."},{"name":"Lo Scienziato","description":"Geniale inventore convinto che la tecnologia possa superare i limiti della morte e completare l’opera della creazione."},{"name":"Cardinale Porpora","description":"Alto prelato ambizioso e pragmatico. Vede in Mecha Padre Pio un possibile segno divino… e una potente risorsa per la Chiesa."}],"scenes":[{"id":"scene_1","title":"Il laboratorio segreto","setting":"Un laboratorio sotterraneo nascosto sotto un antico monastero. Bobine elettriche, reliquie, schermi e candele convivono nello stesso spazio. Al centro una grande capsula metallica coperta da un pesante lenzuolo.","beats":[{"type":"stage_direction","action":"Lampi elettrici attraversano la stanza. Lo Scienziato lavora febbrilmente su leve e quadranti mentre il Cardinale Porpora osserva con crescente disagio.","context":"Introduzione del laboratorio e della tensione."},{"type":"line","speaker":"Cardinale Porpora","to":"Lo Scienziato","line":"Ditemi che non ho attraversato tre diocesi clandestinamente per vedere esplodere una cantina.","context":"Porpora cerca di mantenere controllo e dignità."},{"type":"line","speaker":"Lo Scienziato","to":"Cardinale Porpora","line":"Eminenza, questa non è una cantina. È il laboratorio del futuro!","context":"Lo Scienziato parla con orgoglio visionario."},{"type":"line","speaker":"Cardinale Porpora","to":"Lo Scienziato","line":"Il futuro odora di ozono, grasso meccanico e probabilmente di eresia.","context":"Porpora è nervoso ma ironico."},{"type":"line","speaker":"Lo Scienziato","to":"Cardinale Porpora","line":"Ogni grande scoperta all’inizio sa di scandalo.","context":"Lo Scienziato giustifica l’impresa."},{"type":"line","speaker":"Cardinale Porpora","to":"Lo Scienziato","line":"Io vi ho finanziato per riportare in vita un santo, non per farlo a pezzi e riassemblarlo come un giocattolo.","context":"Porpora prende le distanze moralmente."},{"type":"line","speaker":"Lo Scienziato","to":"Cardinale Porpora","line":"Curiosa parola, santo. Gli uomini la usano sempre poco prima di fare qualcosa di enorme.","context":"Lo Scienziato provoca."},{"type":"line","speaker":"Cardinale Porpora","to":"Lo Scienziato","line":"E qualcosa di enorme è esattamente ciò che temo.","context":"Porpora rivela un timore autentico."},{"type":"stage_direction","action":"Lo Scienziato controlla una teca contenente reliquie e circuiti intrecciati.","context":"Mostra l’unione tra tecnologia e sacro."},{"type":"line","speaker":"Cardinale Porpora","to":"Lo Scienziato","line":"Non riesco ancora a credere che abbiate davvero usato reliquie autentiche.","context":"Porpora teme sacrilegio."},{"type":"line","speaker":"Lo Scienziato","to":"Cardinale Porpora","line":"Le reliquie sono dati biologici con eccellente valore simbolico.","context":"Lo Scienziato desacralizza."},{"type":"line","speaker":"Cardinale Porpora","to":"Lo Scienziato","line":"Voi avete una capacità notevole di bestemmiare senza usare parolacce.","context":"Porpora è scandalizzato."},{"type":"line","speaker":"Lo Scienziato","to":"Cardinale Porpora","line":"Io non bestemmio, Eminenza. Io aggiorno.","context":"Battuta provocatoria."},{"type":"stage_direction","action":"Si avvicina alla capsula coperta.","context":"Momento di suspense."},{"type":"line","speaker":"Cardinale Porpora","to":"Capsula","line":"E sotto quel lenzuolo… c’è davvero lui?","context":"Porpora ha paura della risposta."},{"type":"line","speaker":"Lo Scienziato","to":"Cardinale Porpora","line":"Neuroni sintetici. Tessuti rigenerati. Memorie archiviate. E una batteria al plutonio consacrato.","context":"Lo Scienziato enumera i risultati."},{"type":"line","speaker":"Cardinale Porpora","to":"Lo Scienziato","line":"Consacrato da chi?","context":"Dettaglio inquietante."},{"type":"line","speaker":"Lo Scienziato","to":"Cardinale Porpora","line":"Da me. Ho guardato alcuni tutorial.","context":"Comicità assurda."},{"type":"line","speaker":"Cardinale Porpora","to":"Lo Scienziato","line":"Che il Cielo abbia misericordia.","context":"Porpora ormai teme il peggio."},{"type":"stage_direction","action":"Lo Scienziato strappa il lenzuolo. Appare la figura metallica di Mecha Padre Pio, immobile, con saio corazzato e stimmate luminose.","context":"Grande rivelazione."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"Madonna santissima...","context":"Meraviglia e terrore."}]},{"id":"scene_2","title":"La rinascita","setting":"Il laboratorio. Le luci si abbassano mentre i macchinari entrano in funzione.","beats":[{"type":"stage_direction","action":"Le bobine scaricano energia nella capsula. Un ronzio profondo cresce.","context":"La resurrezione comincia."},{"type":"line","speaker":"Lo Scienziato","to":"Macchinari","line":"Sequenza di riattivazione… tre… due… uno…","context":"Attivazione."},{"type":"stage_direction","action":"Gli occhi di Mecha Padre Pio si illuminano.","context":"Segno di vita."},{"type":"line","speaker":"Mecha Padre Pio","to":"Vuoto","line":"…pace e bene…","context":"Prime parole."},{"type":"line","speaker":"Cardinale Porpora","to":"Lo Scienziato","line":"Funziona… funziona davvero!","context":"Porpora è sconvolto."},{"type":"line","speaker":"Mecha Padre Pio","to":"Gruppo","line":"Dove… mi trovo?","context":"Confusione iniziale."},{"type":"line","speaker":"Lo Scienziato","to":"Mecha Padre Pio","line":"Tra morte e progresso, Padre Pio.","context":"Lo Scienziato si sente vincitore."},{"type":"line","speaker":"Mecha Padre Pio","to":"Lo Scienziato","line":"E voi… siete San Pietro?","context":"Disorientamento."},{"type":"line","speaker":"Lo Scienziato","to":"Mecha Padre Pio","line":"No, sono più simile a un genitore per voi.","context":"Autoironia."},{"type":"stage_direction","action":"Mecha Padre Pio si alza. Il pavimento vibra sotto i suoi passi metallici.","context":"Potenza del corpo meccanico."},{"type":"line","speaker":"Mecha Padre Pio","to":"Se stesso","line":"Il mio cuore… non batte.","context":"Prima consapevolezza."},{"type":"line","speaker":"Lo Scienziato","to":"Mecha Padre Pio","line":"Perché ora avete una pompa magnetica di precisione.","context":"Risposta fredda."},{"type":"line","speaker":"Mecha Padre Pio","to":"Lo Scienziato","line":"E l’anima… avete costruito anche quella?","context":"Tema centrale."},{"type":"line","speaker":"Lo Scienziato","to":"Mecha Padre Pio","line":"Io costruisco il possibile. Sul resto lascio lavorare i teologi.","context":"Evita il problema."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"Forse la vostra esistenza è già una risposta.","context":"Porpora cerca lettura spirituale."},{"type":"line","speaker":"Mecha Padre Pio","to":"Cardinale Porpora","line":"O forse è una domanda... Se un uomo torna con ferri e circuiti… è resurrezione o riparazione?","context":"Padre Pio è turbato."},{"type":"stage_direction","action":"Silenzio. Si sente solo il ronzio della batteria.","context":"Peso del dubbio."},{"type":"line","speaker":"Mecha Padre Pio","to":"Gruppo","line":"E se la fede ha bisogno di macchine per tornare… allora era fede o manutenzione?","context":"Ultima e più forte crepa."}]},{"id":"scene_3","title":"La scelta","setting":"Il laboratorio. Una sirena lontana suona in superficie.","beats":[{"type":"stage_direction","action":"Un monitor mostra notizie di caos e violenza in città.","context":"Ingresso del mondo esterno."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"Il mondo là fuori è malato, Padre Pio. La gente soffre, la fede vacilla. Voi siete la nostra speranza.","context":"Introduzione della missione."},{"type":"line","speaker":"Mecha Padre Pio","to":"Se stesso","line":"Forse la grazia non abita nel ferro… ma in ciò che scegliamo di farne.","context":"Conclusione personale."},{"type":"line","speaker":"Lo Scienziato","to":"Cardinale Porpora","line":"Padre Pio non c''è più, eminenza. Però adesso davanti a noi c''è Mecha Padre Pio.","context":"Evita il problema."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"Mecha Padre Pio… mi ci devo abituare. Siete più di un miracolo, siete un simbolo. Ma ora dovete scegliere: ci aiuterete a proteggere i deboli?","context":"Introduzione della missione."},{"type":"line","speaker":"Mecha Padre Pio","to":"Pubblico","line":"Allora sia. Non sarò solo un miracolo… sarò un protettore. Un santo protettore!","context":"Nascita del supereroe."}]}]}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('Il Demonietto di Brindisi', 'lettura', 'it', 'Mecha Padre Pio', 3, 3, '{"description":"Il Cardinale Porpora assegna a Mecha Padre Pio la sua prima missione come Santo Protettore. Un piccolo demonio chiamato Mestollero si è impossessato di un fedele a Brindisi. Convinto di dover affrontare le forze dell''Apocalisse, Mecha Padre Pio scoprirà che la sua prima vittoria dipenderà più dalla comprensione che dalla forza.","characters":[{"name":"Mecha Padre Pio","description":"Il nuovo Santo Protettore. Ancora inesperto delle sue capacità e alla ricerca del proprio ruolo."},{"name":"Cardinale Porpora","description":"Coordinatore delle missioni di Mecha Padre Pio. Pragmatico e spesso costretto a gestire l''entusiasmo del suo campione."},{"name":"Giuliano Anvizzotti","description":"Un tranquillo pensionato brindisino posseduto dal demonietto Mestollero."}],"scenes":[{"id":"scene_1","title":"Prima missione","setting":"Quartier generale del Cardinale Porpora. Mecha Padre Pio osserva una grande mappa del mondo.","beats":[{"type":"line","speaker":"Mecha Padre Pio","to":"Cardinale Porpora","line":"Dove colpiremo per primi? Una setta infernale? Un drago dell''Apocalisse? Un portale per l''Abisso?","context":"Mecha Padre Pio è impaziente di iniziare."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"Brindisi.","context":"Risposta secca."},{"type":"line","speaker":"Mecha Padre Pio","to":"Cardinale Porpora","line":"Brindisi?","context":"Deluso."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"Brindisi.","context":"Conferma."},{"type":"line","speaker":"Mecha Padre Pio","to":"Cardinale Porpora","line":"L''Abisso si è aperto a Brindisi?","context":"Cerca di capire."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"No. Un demonietto ha posseduto un pensionato.","context":"Missione reale."},{"type":"line","speaker":"Mecha Padre Pio","to":"Cardinale Porpora","line":"Un demonietto?","context":"Sempre più deluso."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"Si chiama Mestollero. È classificato come Disturbo Infernale di Terza Categoria.","context":"Tono burocratico."},{"type":"line","speaker":"Mecha Padre Pio","to":"Cardinale Porpora","line":"Esistono categorie?","context":"Sorpreso"},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"Per tempo ti spiegherò tutto. Per ora concentrati sulla missione.","context":"Serissimo."},{"type":"stage_direction","action":"Porpora inserisce un auricolare nell''orecchio metallico di Mecha Padre Pio.","context":"Nuova tecnologia."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"Questo è un auricolare benedetto. Vi guiderò durante la missione.","context":"Supporto remoto."},{"type":"line","speaker":"Mecha Padre Pio","to":"Cardinale Porpora","line":"Un''altra voce nella mia testa. Non so se ci sarà spazio per me.","context":"Non sembra convinto."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"Non preoccuparti. Non interferirò con i tuoi pensieri. Sarò solo una guida...","context":"Supporto remoto."}]},{"id":"scene_2","title":"Il demonietto di Brindisi","setting":"Piazza principale di Brindisi. Giuliano Anvizzotti corre in cerchio urlando mentre i cittadini si nascondono.","beats":[{"type":"line","speaker":"Giuliano Anvizzotti","to":"Pubblico","line":"Io sono Mestollero! Terrore degli inferi! Flagello dei mortali! Mi sono impossessato del Signor Anvizzotti! E adesso dichiaro illegali i panzerotti!","context":"La voce è quella di Giuliano ma l''espressione e i modi sono completamente diversi."},{"type":"stage_direction","action":"Mecha Padre Pio atterra nella piazza con un tonfo metallico.","context":"Ingresso eroico."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"E adesso chi è questo robot? Irradia un luce fastidiosa","context":"Mestollero riconosce subito il suo avversario."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"[Auricolare] Mantenete la calma. È un demonio minore.","context":"Consigli tattici."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"E'' arrivato Mecha Padre Pio! Lascia quest''uomo e torna da dove sei venuto.","context":"Approccio diretto."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"No.","context":"Risposta immediata."},{"type":"line","speaker":"Mecha Padre Pio","to":"Cardinale Porpora","line":"[Auricolare] Cardinale e adesso cosa faccio?","context":"Porpora aspetta una strategia."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"[Auricolare] Rischiaritelo con la vostra empatia e con le vostre savie parole.","context":"Consigli tattici."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"Perché fai tutto questo?","context":"Cambia approccio."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"Perché nessuno si accorge mai di noi demonietti. Sempre Lucifero, sempre Belzebù... mai Mestollero. Una volta ho infestato una casa per 2 anni e nessuno se ne è accorto.","context":"Sfogo sincero."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"Quindi non vuoi distruggere l''umanità.","context":"Comprende il problema."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"No. Vorrei solo un po'' di rispetto professionale.","context":"Ammissione sincera."},{"type":"stage_direction","action":"Le stimmate luminose di Mecha Padre Pio brillano leggermente.","context":"La sua presenza diventa più rassicurante che minacciosa."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"Ti vedo, Mestollero. Sei un bravo ingranaggio della grande macchina del Signore!","context":"Primo atto di compassione."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"[Auricolare] Bravo santo padre! ","context":"Consigli tattici."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"Quindi state dicendo che faccio parte di un piano divino e sto recitando la parte che mi è stata assegnata?","context":"Lezione morale."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"Esattamente! Sei importante e amato!","context":"Primo atto di compassione."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"Allora smetto, non sto al gioco di nessuno. Inizierò a diffondere odio online e a fare commenti razzisti sui social!","context":"Mestollero sta cedendo."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"Fa quello che il tuo cuore si sente. Ma sappi che sei amato e che la tua esistenza ha un senso.","context":"Mecha Padre Pio riconosce il demonietto come creatura e non solo come minaccia."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"[Auricolare] No santo padre aspetta un momento...","context":"Consigli tattici."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"Beh... è stato bello essere ascoltato almeno una volta.","context":"Le ultime parole di Mestollero."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"[Auricolare] No santo padre, ferma subito quel demonio!","context":"Consigli tattici."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"Va! E sii felice! Sii te stesso!","context":"Mecha Padre Pio riconosce il demonietto come creatura e non solo come minaccia."},{"type":"stage_direction","action":"Giuliano vacilla e quasi cade. Quando rialza la testa il suo sguardo è cambiato. Mestollero non c''è più.","context":"La possessione è terminata."}]},{"id":"scene_3","title":"Il miracolo","setting":"Piazza di Brindisi ormai tranquilla.","beats":[{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"Dove sono?","context":"Giuliano si guarda attorno confuso."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"A Brindisi.","context":"Risposta semplice."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"Si fin qui c''ero arrivato. Ma cosa mi è successo?","context":"Prima battuta dopo la liberazione."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"Eravate imposseduto da un demonietto. Ora siete libero e il mondo è salvo.","context":"Risposta semplice."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"[Auricolare] Si padre... poi dovremmo risolvere la situazione che avete creato. Il problema non è risolto.","context":"Consigli tattici."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"Tutto è bene quel che finisce bene.","context":"Risposta semplice."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"Mi avete salvato. Grazie.","context":"Gratitudine sincera."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"Sono lieto che stiate bene.","context":"Risposta umile."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"Posso chiedervi una cosa?","context":"Esitante."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"Certamente."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"Secondo voi... il vostro ritorno è un miracolo?","context":"Domanda centrale dell''episodio."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"Non lo so.","context":"Risposta onesta."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"[Auricolare] Santo Padre! E'' stato trovato un hacker razzista e misogino che sta attaccando i server del Vaticano! Dobbiamo fermarlo!","context":"Consigli tattici."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"Pensavo che i santi sapessero tutto.","context":"Sorride."},{"type":"line","speaker":"Mecha Padre Pio","to":"Giuliano Anvizzotti","line":"I santi fanno domande come tutti gli altri. Solo che continuano a cercare la risposta.","context":"Tema della serie."},{"type":"line","speaker":"Giuliano Anvizzotti","to":"Mecha Padre Pio","line":"Allora continuerò a cercarla anch''io.","context":"Ispirato."},{"type":"stage_direction","action":"Mecha Padre Pio osserva il cielo. Nell''auricolare si sentono le urla del Cardinale Porpora.","context":"Epilogo."},{"type":"line","speaker":"Cardinale Porpora","to":"Mecha Padre Pio","line":"[Auricolare] Mecha Padre Pio! L''hacker ha appena dichiarato guerra alla Norvegia utilizzando il nostro Twitter ufficiale! Dobbiamo fermarlo ORA!","context":"Chiusura ufficiale."},{"type":"line","speaker":"Mecha Padre Pio","to":"Pubblico","line":"Un''anima è stata salvata. Per oggi può bastare.","context":"Chiusura dell''episodio."}]}]}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('TG Ribalta', 'lettura', 'it', NULL, 7, 1, '{"description":"Una nuova puntata di TG Ribalta, il TG più amato della TV!","characters":[{"name":"Gianni Meraviglia","description":"Il presentatore del tg. Sempre sorridente e frizzante, porta l''entusiasmo ogni giorno in studio."},{"name":"Vince Toombound","description":"Inviato speciale del TG, parla con accento americano. Viene mandato negli angoli più disparati del globo ma è sempre a suo agio."},{"name":"Sara Nasi della Rocca","description":"Inviata per gli aggiornamenti politici, interni ed esteri. Parla molto lentamente, con linguaggio ricercato e tenie sempre una postura impeccabile."},{"name":"Tullio Calalamarca","description":"Si occupa di sport. Parla con spiccata voce nasale e non ha ben chiaro le regole dei vari sport."},{"name":"Tina Mastrotta","description":"Parla dei peggiori casi di cronoca nera con leggerezza e allegria. La sofferenza altrui la fa ridere."},{"name":"Lo Sponsor","description":"Lo Sponsor"},{"name":"Kamalel l''Eradicatore","description":"Un demone antico come la disperazione. Si occupa di intrattenimento e cultura."}],"scenes":[{"id":"scene_1","title":"TG Ribalta","setting":"Studio del TG. Gianni Meraviglia sorride alla telecamera come se avesse appena ricevuto la migliora notizia della sua vita.","beats":[{"type":"stage_direction","action":"Sigla del TG.","context":"Apertura volutamente enfatica e televisiva."},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Buongiorno a tutti e ben sintonizzati per questa nuova puntata di TG Ribalta che, come tutti i giorni, porta nelle vostre case l''informazione di qualità. Qui per voi il vostro amatissimo Gianni Meraviglia, ma prima una parola allo sponsor.","context":"Gianni apre con entusiasmo standard da telegiornale."},{"type":"line","speaker":"Lo Sponsor","to":"Telecamera","line":"La vostra vita senza i nostri prodotti è una merda e lo sapete.","context":"Sponsor aggressivo, diretto e disturbante."},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Ok. Grazie mille Lo Sponsor. Ma iniziamo subito. Le elezioni si avvicinano e  in questo momento di divisione ci sono tumulti tra i candidati che non fanno presagire le migliori intenzioni. Passiamo la parola alla nostra Sara Nasi.","context":"Gianni prova a rientrare nel formato normale del TG."},{"type":"line","speaker":"Sara Nasi della Rocca","to":"Gianni Meraviglia","line":"[Stizzita] Della Rocca...","context":"Sara corregge il cognome con irritazione trattenuta."},{"type":"line","speaker":"Gianni Meraviglia","to":"Sara Nasi della Rocca","line":"Come Sara?","context":"Gianni non capisce o finge di non capire."},{"type":"line","speaker":"Sara Nasi della Rocca","to":"Gianni Meraviglia","line":"Il mio nome è Sara Nasi della Rocca, non Sara Nasi. Comunque. Ci troviamo dinanzi a una fase di particolare, delicatissima e, mi permetto di affermare, quasi tettonica instabilità istituzionale.","context":"Sara riprende il controllo della propria immagine."},{"type":"line","speaker":"Gianni Meraviglia","to":"Sara Nasi della Rocca","line":"Un terremoto per il nostro paese, vero Sara?","context":"Gianni prova a tradurre per il pubblico."},{"type":"line","speaker":"Sara Nasi della Rocca","to":"Gianni Meraviglia","line":"Sì. I principali candidati dei due partiti di maggioranza si stanno offendendo su internet da giorni ormai. Dalle banali parolaccie e imprecazioni siamo passati a video fatti con l''AI dell''uno che massacra l''altro di pugni e viceversa.","context":"Sara spiega senza semplificare davvero."},{"type":"line","speaker":"Gianni Meraviglia","to":"Sara Nasi della Rocca","line":"Quindi immagino non hanno intenzione di cooperare?","context":"Gianni cerca un appiglio concreto."},{"type":"line","speaker":"Sara Nasi della Rocca","to":"Gianni Meraviglia","line":"Immagino di no... Anche se da informazioni trapelate da canali non ufficiali sembra che si trovino spesso per giocare a Padel.","context":"Sara mantiene tono impeccabile."},{"type":"line","speaker":"Gianni Meraviglia","to":"Sara Nasi della Rocca","line":"E gli elettori cosa dicono?","context":"Domanda giornalistica semplice."},{"type":"line","speaker":"Sara Nasi della Rocca","to":"Gianni Meraviglia","line":"Tradotto in un lessico maggiormente consono, dicono che il Padel è uno sport di scarso pregio e di ancor più limitata dignità.","context":"Burocrazia che risponde alla confusione producendo altra confusione."},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Molto bene. Grazie Sara Nasi della Rocca per i tuoi aggiornamenti sempre lucidi, ma adesso ti dobbiamo lasciare per ridare la parola a Lo Sponsor","context":"Gianni enfatizza il nome completo per evitare correzioni."},{"type":"line","speaker":"Lo Sponsor","to":"Telecamera","line":"Un giorno vi troverete davanti al vostro dio e dovrete giustificare quello spreco che è stata la vostra esistenza.","context":""},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Lo Sponsor, sempre puntuale e sempre dritto al punto, ahahahah.","context":"Gianni cerca di salvare la faccia del TG."},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Ci spostiamo ora all''estero, dove la situazione internazionale continua a essere disastrosa . In collegamento con noi Vince Toombound. Ciao Vince!","context":"Gianni introduce il servizio esteri con entusiasmo vuoto."},{"type":"line","speaker":"Vince Toombound","to":"Gianni Meraviglia","line":"Hi Gianni! Yes, mi trovo in un''area geopoliticamente molto spicy.","context":"Vince parla con accento americano e naturale disinvoltura."},{"type":"line","speaker":"Gianni Meraviglia","to":"Vince Toombound","line":"Come sempre vecchio amico, dove esattamente Vince?","context":"Gianni vuole localizzare la notizia."},{"type":"line","speaker":"Vince Toombound","to":"Gianni Meraviglia","line":"Dipende a chi lo chiedi. Per alcuni sono in Portogallo se chiedi ad altri sono in Argentina. Però se chiedi a me sono in un posto belissimo.","context":"Vince è completamente a suo agio nell''assurdo."},{"type":"line","speaker":"Gianni Meraviglia","to":"Vince Toombound","line":"Ma e perchè sei laggiù? Qual è la notizia?","context":"Gianni prova a rimettere ordine."},{"type":"line","speaker":"Vince Toombound","to":"Telecamera","line":"La notizia, Gianni, è che 2 nazioni rivendicano questa piccola isola ma entrambe affermano anche di non volerla. Mentre i locali si ritengono indipendenti.","context":"Situazione geopolitica ridicola."},{"type":"line","speaker":"Gianni Meraviglia","to":"Vince Toombound","line":"Perché la rivendicano se non la vogliono?","context":"Domanda sensata."},{"type":"line","speaker":"Vince Toombound","to":"Gianni Meraviglia","line":"Per prestigio. Nessuno vuole perderlo, perché perderla significherebbe lasciarla all''altro.","context":"Vince spiega con logica paradossale."},{"type":"line","speaker":"Gianni Meraviglia","to":"Vince Toombound","line":"Ovviamente Vince. Ma la popolazione locale si sta ribellando? Sta per partire una rivoluzione armata?","context":"Gianni cerca il punto umano della storia."},{"type":"line","speaker":"Vince Toombound","to":"Gianni Meraviglia","line":"I locals sono composti da 4 case, un benzinaio, 2 capre e un uomo che vende calamite da frigo con scritto ''Non toccate le nostre capre''.","context":"Vince elenca con naturalezza."},{"type":"line","speaker":"Gianni Meraviglia","to":"Vince Toombound","line":"Gente semplice e onesta. C''è pericolo per il nostro inviato?","context":"Finta preoccupazione."},{"type":"line","speaker":"Vince Toombound","to":"Gianni Meraviglia","line":"Zero danger, Gianni. Ho comprato una calamita e adesso il tizio delle calamite mi ha invitato a pranzo da lui.","context":"Vince trova una soluzione assurda e pratica."},{"type":"line","speaker":"Gianni Meraviglia","to":"Vince Toombound","line":"Grazie Vince. Rimani al sicuro.","context":"Gianni chiude il collegamento."},{"type":"line","speaker":"Vince Toombound","to":"Gianni Meraviglia","line":"Always, Gianni. Domani ho fissato con il mio amico delle calamite per andare a pescare! A voi la linea!","context":"Vince resta sereno."},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Bene dall''estero è tutto, passiamo ora alla cronaca nera con la nostra Tina Mastrotta, che come sempre saprà addolcire le notizie più terribili. A te Tina!","context":"Gianni introduce Tina con fiducia ingenua."},{"type":"line","speaker":"Tina Mastrotta","to":"Telecamera","line":"Grazie Gianni! Anche oggi sono successe un sacco di tragedie, alcune più noiose e altre invece molto interessanti.","context":"Tina è allegra in modo inquietante."},{"type":"line","speaker":"Gianni Meraviglia","to":"Tina Mastrotta","line":"Ovviamente la redazione è molto rattristata da tutta queste catastrofi. Ma andiamo a capire tutti i minimi dettagli delle tragedie di oggi.","context":"Gianni prova a correggerla."},{"type":"line","speaker":"Tina Mastrotta","to":"Gianni Meraviglia","line":"Tre rapine, due incendi e finalmente un omicidio dopo una settimana davvero fiacca!","context":"Tina presenta un caso grottesco."},{"type":"line","speaker":"Gianni Meraviglia","to":"Tina Mastrotta","line":"Che tempi bui per il nostro paese.... Raccontaci tutto su questo omicidio!","context":"Gianni è preoccupato."},{"type":"line","speaker":"Tina Mastrotta","to":"Gianni Meraviglia","line":"Con grandissimo piacere, Gianni! Questa mattina alle 7:43 il signor Ernesto Baldi è stato accoltellato ben diciassette volte davanti al proprio garage. Una dinamica davvero ricca di colpi di scena, che ha richiesto l''intervento di ben quattro pattuglie, due ambulanze e perfino un elicottero! [Ride di felicità] Lavoriamo giorno e notte per raccogliere tutti i dettagli.","context":"Tina tratta la tragedia come spettacolo."},{"type":"line","speaker":"Gianni Meraviglia","to":"Tina Mastrotta","line":"Non una grande nottata per il Signor Baldi. Cosa dice la sua povera povera famiglia?","context":"Sara mantiene il tono istituzionale."},{"type":"line","speaker":"Tina Mastrotta","to":"Gianni Meraviglia","line":"Sono comprensibilmente distrutti, Gianni. Non hanno voluto rilasciare commenti, ma ovviamente noi siamo sempre qui appostati ad aspettare che gli venga voglia.","context":"Tina è teatralmente commossa."},{"type":"line","speaker":"Gianni Meraviglia","to":"Tina Mastrotta","line":"Grazie Tina, il paese deve sapere tutti i minimi dettagli della sofferenza di questa povera famiglia. Ma ci sono sospettati?","context":"Domanda da cronaca."},{"type":"line","speaker":"Tina Mastrotta","to":"Gianni Meraviglia","line":"Ce ne sono tantissimi! Ed hanno tutti un alibi di ferro! Questa storia andra avanti per settimane... se non mesi!","context":"Finale assurdo del caso."},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Scusami Tina se ti interrompo, ma dalla regia mi dicono che possiamo nuovamente passare la linea allo sponsor.","context":"Gianni cerca una formula accettabile."},{"type":"line","speaker":"Tina Mastrotta","to":"Telecamera","line":"Figurati, Gianni. Ho appena visto il figlio del signor Baldi che sta cercando di scappare via in lacrime! Vi aggiornerò al più presto.","context":"Tina saluta con inquietante leggerezza."},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Grazie Tina e linea a Lo Sponsor!","context":""},{"type":"line","speaker":"Lo Sponsor","to":"Telecamera","line":"L''ho ucciso io quel figlio di troia maledetto. State attenti.","context":""},{"type":"stage_direction","action":"Sparisce Tina e appare Tullio sullo schermo.","context":"Transizione allo sport."},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Ahahahah e adesso lo sport con Tullio Calalamarca. Vai Tullio!","context":"Gianni passa al segmento sportivo."},{"type":"line","speaker":"Tullio Calalamarca","to":"Telecamera","line":"Grazie Gianni. Grande serata di sport ieri, quando vari giocatori hanno giocato moltissimi sport in vari campi e sì... c''è stato molto sport.","context":"Tullio parla con voce nasale e rimane molto generico."},{"type":"line","speaker":"Gianni Meraviglia","to":"Tullio Calalamarca","line":"Una giornata avvincente, vuoi darci più dettagli?","context":"Gianni nota l''errore."},{"type":"line","speaker":"Tullio Calalamarca","to":"Gianni Meraviglia","line":"Sì, Gianni. Nel calcio è andato tutto bene, la gente si è divertita e qualcuno ha fatto anche gol. Non si è fatto male nessuno.","context":"Tullio si difende con sicurezza infondata."},{"type":"line","speaker":"Sara Nasi della Rocca","to":"Tullio Calalamarca","line":"Finalmente delle buone notizie Tullio! Per quanto riguarda la pallacanestro?","context":"Sara interviene precisa."},{"type":"line","speaker":"Tullio Calalamarca","to":"Sara Nasi della Rocca","line":"Bene si anche lì tutto apposto.","context":"Tullio interpreta l''obiezione come conferma."},{"type":"line","speaker":"Gianni Meraviglia","to":"Tullio Calalamarca","line":"Risultati dagli altri campi?","context":"Gianni prova ad andare avanti."},{"type":"line","speaker":"Tullio Calalamarca","to":"Telecamera","line":"Nel tennis... così così. Ci sono stati dei problemi, però insomma le palline ci sono e le racchette anche. Hanno giocato tanto, faceva caldo anche... però bene dai.","context":"Confusione totale fra sport."},{"type":"line","speaker":"Gianni Meraviglia","to":"Tullio Calalamarca","line":"Eh come si sa il tennis è uno sport molto mentale e a volti succede di avere dei giorni un po'' così. Altri aggiornamenti?","context":"Gianni prova a verificare."},{"type":"line","speaker":"Tullio Calalamarca","to":"Telecamera","line":"Chiudiamo con la Formula Uno: ottima partenza, molte macchine giravano tutte nella stessa direzione, segno di grande spirito di squadra. Da qui é tutto a voi a linea.","context":"Tullio chiude lo sport fraintendendo il concetto di gara."},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Grazie Tullio. Sempre pieno di energia il nostro Tullio. La stessa energia che porta nelle vostre case Lo Sponsor!","context":"Gianni sintetizza il segmento."},{"type":"line","speaker":"Lo Sponsor","to":"Telecamera","line":"Tutti i tuoi amici sono migliori di te. Tua madre non ti ama.","context":""},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Arriviamo ora alle notizie di cultura, spettacolo e cronaca rosa con Kamalel l''Eradicatore. Buongiorno Kamalel!","context":"Gianni introduce il demone come se fosse un normale opinionista."},{"type":"stage_direction","action":"Kamalel l''Eradicatore compare nello schermo, un''enorme catena alla vita lo tiene prigioniero.","context":"Ingresso demoniaco ma da rubrica televisiva."},{"type":"line","speaker":"Kamalel l''Eradicatore","to":"Telecamera","line":"Salute a voi, creature dalla carne provvisoria. Partiamo subito con la cultura, ha riaperto dopo una lunga ristrutturazione il Museo Nazionale di Storia Naturale.","context":"Kamalel parla solennemente di gossip."},{"type":"line","speaker":"Gianni Meraviglia","to":"Kamalel l''Eradicatore","line":"Ah che ottima notizia e cosa possiamo trovare in questo bel Museo?","context":"Gianni mantiene il formato TG."},{"type":"line","speaker":"Kamalel l''Eradicatore","to":"Gianni Meraviglia","line":"Il pallido miraggio della vostra convizione di essere eterni. Non siete che un battito di ciglia nell''infinita vastità del vuoto senza stelle.","context":"Satira del gossip e dell''esposizione online."},{"type":"line","speaker":"Gianni Meraviglia","to":"Kamalel l''Eradicatore","line":"Eheh... ok Kamalel. Per quanto riguarda invece [Ammicca] ... il gossip?","context":"Gianni prova a proseguire."},{"type":"line","speaker":"Kamalel l''Eradicatore","to":"Telecamera","line":"Il noto cantante Friz Maresciallo, degli Electric Voltaren, ha dichiarato di essere tornato con la sua ex dopo un percorso di crescita personale durato quarantotto ore.","context":"Kamalel annuncia il gossip con tono apocalittico."},{"type":"line","speaker":"Gianni Meraviglia","to":"Kamalel l''Eradicatore","line":"Eheheh... 48 ore non sono proprio un percorso lunghissimo...","context":"Sara corregge formalmente."},{"type":"line","speaker":"Kamalel l''Eradicatore","to":"Sara Nasi della Rocca","line":"Il tempo è un''illusione che voi umani utilizzate come abaco della vostra breve esistenza.","context":"Kamalel risponde con antica esperienza."},{"type":"line","speaker":"Gianni Meraviglia","to":"Kamalel l''Eradicatore","line":"Se lo dici tu Kamalel! Ma a proposito di cantanti, cosa ci dici di concerti ed eventi?","context":"Gianni torna alla notizia forte."},{"type":"line","speaker":"Kamalel l''Eradicatore","to":"Gianni Meraviglia","line":"Le vostre orecchie non possono sentire l''eco delle grida di dolore della nascita dell''universo e i vostri occhi ignorano le complessità di ciò che la vostra mente limitata chiama paradossi. La vostra condizione mi disgusta.","context":"Battuta sulla normalizzazione del patto infernale."},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Immagino allora non si prospetti niente di emozionante per questo weekend, ahahahah...","context":"Gianni tenta disperatamente di chiudere il TG."},{"type":"line","speaker":"Kamalel l''Eradicatore","to":"Telecamera","line":"Mortale se non fosse per queste catene...","context":"Kamalel offre una morale inquietante e mediatica."},{"type":"line","speaker":"Gianni Meraviglia","to":"Telecamera","line":"Da TG Ribalta è tutto. Ci vediamo domani con nuove notizie! Un caloroso saluto dal vostro solo e unico Gianni Meraviglia!","context":"Chiusura inquietante ma sorridente."},{"type":"line","speaker":"Lo Sponsor","to":"Telecamera","line":"Questa puntata vi è stata offerta da Lo Sponsor. Siamo dentro casa vostra.","context":"Ultimo intervento commerciale."},{"type":"stage_direction","action":"Sigla finale. Gianni saluta. Kamalel immobile fissa il pubblico. La telecamera indugia troppo a lungo.","context":"Finale da sketch con quarta parete disturbante."}]}]}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('Nella Sala della Preservazione dell’Armonia', 'lettura', 'it', 'Storie dall’Impero di Mezzo', 4, 1, '{"description":"Pechino, Città Proibita, ultimi anni del regno di Qianlong (fine XVIII secolo). Durante l’esame di palazzo, l’imperatore interroga un candidato jinshi sul governo dell’impero. Accanto a lui siedono un gran segretario mancese e un accademico Hanlin. Le parole sembrano un esercizio letterario, ma ogni citazione dai Classici diventa una prova politica.","characters":[{"name":"Imperatore Qianlong","description":"Sovrano della dinastia Qing. Colto, teatrale, consapevole del proprio ruolo di imperatore universale e custode dei Classici. Non ama essere contraddetto, ma apprezza l’eleganza della contraddizione ben mascherata."},{"name":"Fuca Mingliang","description":"Gran segretario mancese. Fedele alla casa imperiale, attento alla forma rituale e ai segnali di pericolo politico. Interviene poco, ma ogni intervento pesa."},{"name":"Liu Wenheng","description":"Accademico Hanlin cinese. Letterato raffinato, incaricato di leggere e commentare gli elaborati dei candidati. Conosce il potere delle parole e il rischio delle parole."},{"name":"Zhang Shiyu","description":"Candidato all’esame di palazzo. Giovane, brillante, teso. Sa che deve citare i Classici, ma sa anche che alcune citazioni possono sembrare rimproveri all’imperatore."}],"scenes":[{"id":"scene_1","title":"Il tema dell’impero","setting":"Baohe Dian, Sala della Preservazione dell’Armonia, Città Proibita. È mattina. I candidati sono allineati in silenzio. Sulla grande sala pendono drappi imperiali. Al centro, l’imperatore Qianlong siede sopraelevato. Davanti a lui: tavole con elaborati, pennelli, sigilli. Fuca Mingliang e Liu Wenheng stanno poco più in basso. Zhang Shiyu viene chiamato avanti.","beats":[{"type":"stage_direction","action":"Zhang Shiyu avanza, si inginocchia e compie il saluto rituale. Non guarda direttamente l’imperatore.","context":"Nella corte Qing la postura del corpo è parte del linguaggio politico. Zhang è sotto esame ancora prima di parlare."},{"type":"line","speaker":"Fuca Mingliang","to":"Zhang Shiyu","line":"Il candidato Zhang Shiyu, della provincia del Jiangnan, si presenta davanti al Figlio del Cielo.","context":"Annuncio formale. Il nome e la provincia ricordano che il candidato viene da un’area colta ma politicamente sensibile."},{"type":"line","speaker":"Imperatore Qianlong","to":"Zhang Shiyu","line":"Alzate il capo quanto basta per ascoltare, non tanto da dimenticare dove siete.","context":"Qianlong stabilisce subito il rapporto: benevolenza controllata, autorità assoluta."},{"type":"line","speaker":"Zhang Shiyu","to":"Imperatore Qianlong","line":"Il vostro servo ascolta tremando.","context":"Formula umile, adatta al contesto."},{"type":"line","speaker":"Imperatore Qianlong","to":"Zhang Shiyu","line":"Nel vostro elaborato scrivete: “Governare con la virtù è come la Stella Polare”. Dunque ditemi: se la Stella Polare resta ferma, perché l’impero richiede tanti editti?","context":"Qianlong cita Confucio e trasforma la citazione in una trappola: vuole vedere se il candidato sa distinguere virtù morale e amministrazione concreta."},{"type":"line","speaker":"Zhang Shiyu","to":"Imperatore Qianlong","line":"Maestà, la Stella Polare resta ferma, ma gli uomini sotto il Cielo non sono stelle. Confucio dice anche: “Guidarli con la virtù, ordinarli con il rito”. L’editto è il pennello; la virtù è l’inchiostro. Senza inchiostro, il tratto resta secco.","context":"Risposta elegante: non oppone legge e virtù, ma subordina il comando morale all’ordine rituale."},{"type":"line","speaker":"Liu Wenheng","to":"Imperatore Qianlong","line":"Il candidato non separa il governo dalla coltivazione morale. È una lettura ortodossa.","context":"Liu lo difende, ma con prudenza: dice che è ortodosso, non che è audace."},{"type":"line","speaker":"Fuca Mingliang","to":"Zhang Shiyu","line":"Molti candidati sanno citare. Pochi sanno fermarsi prima che la citazione diventi superbia.","context":"Mingliang avverte Zhang: l’erudizione può sembrare arroganza davanti al sovrano."},{"type":"line","speaker":"Imperatore Qianlong","to":"Zhang Shiyu","line":"Allora continuate. Nel tema parlate di tasse, carestie e magazzini pubblici. Perché portare il grano del popolo davanti al trono?","context":"Qianlong sposta il discorso su amministrazione e responsabilità imperiale."},{"type":"line","speaker":"Zhang Shiyu","to":"Imperatore Qianlong","line":"Perché Mencio insegna: “Chi ha mezzi stabili ha cuore stabile; chi non li ha, non ha cuore stabile”. Dove il popolo digiuna, la legge arriva tardi e la colpa arriva presto.","context":"Zhang cita Mencio per sostenere che la moralità dipende anche da condizioni materiali."},{"type":"line","speaker":"Fuca Mingliang","to":"Zhang Shiyu","line":"State dicendo che il crimine del suddito nasce dal difetto del governo?","context":"Mingliang individua il rischio politico della frase."},{"type":"line","speaker":"Zhang Shiyu","to":"Fuca Mingliang","line":"Dico solo che il contadino affamato non legge il Codice prima di rubare una ciotola di riso.","context":"Zhang risponde in modo concreto, rischiando ma senza accusare direttamente il trono."},{"type":"stage_direction","action":"Nella sala cala un silenzio breve. Liu Wenheng abbassa gli occhi. Qianlong osserva Zhang con interesse.","context":"La risposta è vera, ma pericolosa."},{"type":"line","speaker":"Imperatore Qianlong","to":"Zhang Shiyu","line":"Avete lingua sottile. Sottile come carta di riso: ci si può scrivere un classico o un’accusa.","context":"Qianlong riconosce la qualità letteraria e il pericolo politico."},{"type":"line","speaker":"Zhang Shiyu","to":"Imperatore Qianlong","line":"Il vostro servo non osa accusare. Il Libro dei Documenti dice: “Il Cielo vede come vede il popolo, il Cielo ascolta come ascolta il popolo”. Io non porto accuse: porto orecchie.","context":"Zhang usa una citazione forte: il popolo come tramite del Cielo. È legittima, ma molto audace davanti all’imperatore."},{"type":"line","speaker":"Fuca Mingliang","to":"Liu Wenheng","line":"Accademico Liu, questa frase è nel canone o nella gola del candidato?","context":"Mingliang vuole capire se può accusare Zhang di usare i Classici come critica politica."},{"type":"line","speaker":"Liu Wenheng","to":"Fuca Mingliang","line":"È nel canone, Eccellenza. Ma anche il canone, quando viene letto ad alta voce, cambia temperatura.","context":"Liu riconosce che una citazione ortodossa può diventare politicamente scomoda."},{"type":"line","speaker":"Imperatore Qianlong","to":"Liu Wenheng","line":"E voi, Hanlin, quale temperatura sentite?","context":"Qianlong testa anche Liu: nessuno è semplice spettatore."},{"type":"line","speaker":"Liu Wenheng","to":"Imperatore Qianlong","line":"Quella del Grande Studio, Maestà: “Il percorso del Grande Studio consiste nel rendere chiara la virtù, rinnovare il popolo, fermarsi al sommo bene” — rendere chiara la virtù, rinnovare il popolo, fermarsi al sommo bene. Il candidato ha ricordato la seconda parte. Vostra Maestà incarna la prima.","context":"Liu salva la situazione con una citazione che lusinga Qianlong e rimette il sovrano al centro."},{"type":"line","speaker":"Imperatore Qianlong","to":"Liu Wenheng","line":"Sapete lucidare una lama senza tagliarvi.","context":"Qianlong apprezza l’abilità retorica di Liu."},{"type":"line","speaker":"Imperatore Qianlong","to":"Zhang Shiyu","line":"Candidato Zhang, conoscete il Libro delle Odi?","context":"Cambio apparente di tema, ma sempre dentro la prova letteraria."},{"type":"line","speaker":"Zhang Shiyu","to":"Imperatore Qianlong","line":"Lo studio da quando ero bambino. Confucio disse: “Trecento poesie, una sola frase le contiene: pensiero senza stortura”.","context":"Zhang cita i Dialoghi su come leggere il Libro delle Odi."},{"type":"line","speaker":"Imperatore Qianlong","to":"Zhang Shiyu","line":"Allora recitate l’inizio.","context":"Qianlong chiede un classico elementare: è una prova di controllo, non di memoria."},{"type":"line","speaker":"Zhang Shiyu","to":"Imperatore Qianlong","line":"“Gli uccelli gridano sull’isola del fiume; la giovane virtuosa è degna compagna del principe.”","context":"Citazione dal primo poema del Libro delle Odi. In un esame di corte, anche una poesia d’amore diventa discorso sull’ordine morale."},{"type":"line","speaker":"Imperatore Qianlong","to":"Zhang Shiyu","line":"E che c’entra una fanciulla con i magazzini del grano?","context":"Qianlong vuole vedere se Zhang sa interpretare, non solo recitare."},{"type":"line","speaker":"Zhang Shiyu","to":"Imperatore Qianlong","line":"C’entra l’armonia, Maestà. Nel poema il desiderio non diventa disordine perché è trattenuto dal rito. Così nel governo: fame, ambizione e paura esistono; il compito del sovrano non è fingere che non esistano, ma accordarle come qin e se.","context":"Zhang interpreta la poesia in chiave politica, come avrebbe fatto un letterato confuciano."},{"type":"line","speaker":"Fuca Mingliang","to":"Zhang Shiyu","line":"Parlate come se il popolo fosse uno strumento e il sovrano dovesse temere di spezzarne le corde.","context":"Mingliang formula il sospetto in termini conservatori."},{"type":"line","speaker":"Zhang Shiyu","to":"Fuca Mingliang","line":"Non temere, Eccellenza. Accordare.","context":"Risposta breve, controllata."},{"type":"line","speaker":"Imperatore Qianlong","to":"Zhang Shiyu","line":"E se uno strumento suona contro il palazzo?","context":"Qianlong porta la metafora al punto politico: ribellione e dissenso."},{"type":"line","speaker":"Zhang Shiyu","to":"Imperatore Qianlong","line":"Allora bisogna chiedersi se la corda è ribelle o se il legno si è deformato nell’umidità.","context":"Zhang rischia moltissimo: suggerisce che il disordine può venire dal governo, non solo dal popolo."},{"type":"stage_direction","action":"Fuca Mingliang irrigidisce le spalle. Liu Wenheng chiude lentamente il ventaglio.","context":"Entrambi capiscono che la frase può essere interpretata come critica."},{"type":"line","speaker":"Fuca Mingliang","to":"Imperatore Qianlong","line":"Maestà, il candidato ha ingegno. Forse troppo ingegno per un primo incarico.","context":"Mingliang consiglia cautela: un uomo così brillante può essere utile o pericoloso."},{"type":"line","speaker":"Liu Wenheng","to":"Imperatore Qianlong","line":"Oppure abbastanza ingegno da sapere che i Classici non furono scritti per decorare le mensole.","context":"Liu difende l’idea che i Classici debbano guidare il governo, non essere solo ornamentali."},{"type":"line","speaker":"Imperatore Qianlong","to":"Liu Wenheng","line":"State difendendo lui o voi stesso?","context":"Qianlong sente l’ambiguità politica di Liu."},{"type":"line","speaker":"Liu Wenheng","to":"Imperatore Qianlong","line":"Difendo il pennello, Maestà. Senza pennello, anche l’editto resta muto.","context":"Liu si rifugia nella funzione letteraria dell’amministrazione."},{"type":"line","speaker":"Imperatore Qianlong","to":"Zhang Shiyu","line":"Mencio disse: “Il popolo è il più prezioso, poi vengono gli altari dello Stato, e il sovrano è il più leggero.” È una frase che molti ripetono con bocca virtuosa e cuore disordinato. Voi come la leggete?","context":"Qianlong pone la domanda più pericolosa: il primato del popolo può sembrare limite all’autorità imperiale."},{"type":"line","speaker":"Zhang Shiyu","to":"Imperatore Qianlong","line":"La leggo inginocchiato.","context":"Zhang risponde prima con il corpo: riconosce la gerarchia."},{"type":"line","speaker":"Imperatore Qianlong","to":"Zhang Shiyu","line":"Non basta.","context":"Qianlong pretende interpretazione, non solo sottomissione."},{"type":"line","speaker":"Zhang Shiyu","to":"Imperatore Qianlong","line":"Allora la leggo così: il sovrano è leggero non perché vale poco, ma perché deve stare in alto. Se diventa pesante, schiaccia ciò che dovrebbe reggere.","context":"Zhang salva la citazione: trasforma una frase potenzialmente anti-assolutista in immagine di responsabilità imperiale."},{"type":"stage_direction","action":"Qianlong resta immobile. Poi sorride appena.","context":"Il candidato ha trovato una via elegante: non nega Mencio e non offende il trono."},{"type":"line","speaker":"Imperatore Qianlong","to":"Fuca Mingliang","line":"Scrivete: Zhang Shiyu possiede lingua acuta, memoria salda e istinto di sopravvivenza.","context":"Qianlong concede approvazione, ma mantiene un’ombra ironica."},{"type":"line","speaker":"Fuca Mingliang","to":"Imperatore Qianlong","line":"Sarà scritto, Maestà.","context":"Mingliang obbedisce."},{"type":"line","speaker":"Imperatore Qianlong","to":"Zhang Shiyu","line":"Vi darò un posto dove le parole servano l’impero prima di pretendere di correggerlo.","context":"Qianlong non lo punisce: lo incanala nella burocrazia letteraria."},{"type":"line","speaker":"Zhang Shiyu","to":"Imperatore Qianlong","line":"Il vostro servo riceve la grazia come riceverebbe una lama: con entrambe le mani.","context":"Zhang sa che l’onore è anche controllo."},{"type":"line","speaker":"Imperatore Qianlong","to":"Zhang Shiyu","line":"Ricordate un’ultima frase dei Dialoghi: “Trasmettere, non inventare; credere negli antichi e amarli.” Ma ricordate anche questo: chi trasmette sceglie sempre cosa far passare.","context":"Qianlong chiude con un monito sulla responsabilità politica dell’erudizione."},{"type":"line","speaker":"Liu Wenheng","to":"Zhang Shiyu","line":"Inchinatevi. Avete superato la domanda. Ora vi resta l’impero.","context":"Liu parla piano, quasi come un avvertimento privato."},{"type":"stage_direction","action":"Zhang si inchina profondamente. Dietro di lui, gli altri candidati attendono immobili. Fuori dalla sala, il vento muove appena gli stendardi imperiali.","context":"Finale sospeso: la letteratura ha aperto una porta, ma la corte decide quanto quella porta può restare aperta."}]}]}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('Una coppa di vino', 'lettura', 'it', 'Storie dall’Impero di Mezzo', 3, 1, '{"description":"Nei primi anni della dinastia Song (circa anno 1000 DC), l’imperatore Taizu invita due vecchi compagni d’armi, i generali Shi Shouxin e Wang Shenqi, a un banchetto privato nel palazzo di Kaifeng. Tra vino, memoria militare e parole misurate, Taizu li conduce a comprendere che il nuovo impero non potrà sopravvivere se il potere dell’esercito resterà nelle mani degli stessi uomini che lo hanno fondato.","characters":[{"name":"Imperatore Taizu","description":"Zhao Kuangyin, fondatore della dinastia Song. Ex comandante militare, ora imperatore. Parla con calma, ma ogni frase è una mossa politica."},{"name":"Shi Shouxin","description":"Generale veterano della Guardia imperiale. Fedele a Taizu, ma consapevole che il proprio potere militare lo rende pericoloso agli occhi della corte."},{"name":"Wang Shenqi","description":"Generale esperto, compagno d’armi di Taizu. Più prudente di Shi, comprende prima degli altri dove l’imperatore vuole arrivare."}],"scenes":[{"id":"scene_1","title":"Il banchetto dopo l’udienza","setting":"Palazzo imperiale di Kaifeng, sala interna. È sera. Non è una grande udienza pubblica, ma un banchetto privato dopo gli affari di corte. Una tavola bassa, vino caldo, lampade a olio. Alcuni servitori restano lontani. Taizu siede senza armatura; i due generali portano abiti formali da ufficiali, non tenuta da battaglia.","beats":[{"type":"stage_direction","action":"Shi Shouxin e Wang Shenqi entrano, si inchinano con rispetto ma non si gettano a terra. Taizu li invita a sedere.","context":"La scena deve evitare gesti troppo tardi-imperiali: non è una corte Qing, ma un incontro Song sobrio e controllato."},{"type":"line","speaker":"Imperatore Taizu","to":["Shi Shouxin","Wang Shenqi"],"line":"Sedete. Questa sera non voglio parlare con titoli, sigilli e memoriali. Voglio bere con uomini che hanno marciato con me quando il destino non portava ancora il nome di Song.","context":"Taizu apre con familiarità calcolata: ricorda il passato militare comune per abbassare le difese dei generali."},{"type":"line","speaker":"Shi Shouxin","to":"Imperatore Taizu","line":"Vostra Maestà ci onora oltre misura. Noi siamo vostri servitori: prima sotto le insegne, ora sotto il Cielo che vi ha scelto.","context":"Shi risponde con lealtà formale, usando il linguaggio politico del mandato celeste."},{"type":"line","speaker":"Wang Shenqi","to":"Imperatore Taizu","line":"La pace della capitale dipende dalla vostra virtù. Se il vino è offerto da Vostra Maestà, anche il silenzio diventa un ordine lieto.","context":"Wang è più cauto: elogia l’imperatore ma segnala che capisce la natura politica dell’invito."},{"type":"line","speaker":"Imperatore Taizu","to":["Shi Shouxin","Wang Shenqi"],"line":"Il silenzio non mi serve. Ne ho già troppo durante le udienze. Tutti mi chiamano Figlio del Cielo, ma nessuno mi dice quanto pesa il Cielo quando cala sulle spalle.","context":"Taizu introduce il proprio disagio: è una confessione apparente, ma prepara il tema della minaccia interna."},{"type":"line","speaker":"Shi Shouxin","to":"Imperatore Taizu","line":"Chi oserebbe turbare il vostro riposo? Le armate della Guardia sono salde. I passi nelle vie di Kaifeng obbediscono al tamburo imperiale.","context":"Shi interpreta il timore come minaccia esterna o disordine cittadino."},{"type":"line","speaker":"Imperatore Taizu","to":"Shi Shouxin","line":"È proprio questo che mi toglie il sonno: le armate sono salde. Gli uomini sono fedeli. I tamburi rispondono. Così era anche prima che io salissi al trono.","context":"Taizu allude alla propria ascesa militare senza nominarla apertamente."},{"type":"line","speaker":"Wang Shenqi","to":"Imperatore Taizu","line":"Vostra Maestà parla del tempo in cui il comando di un esercito poteva mutare il destino di una dinastia.","context":"Wang capisce il riferimento alla transizione dai Cinque Regni e alla presa del potere da parte di Taizu."},{"type":"line","speaker":"Imperatore Taizu","to":"Wang Shenqi","line":"Io parlo del fatto che gli uomini dormono, ma le insegne no. Una veste gialla può essere gettata sulle spalle di un uomo anche quando quell’uomo dice di non volerla.","context":"Riferimento velato alla propria proclamazione imperiale, presentata come qualcosa che può accadere anche contro la volontà personale."},{"type":"line","speaker":"Shi Shouxin","to":"Imperatore Taizu","line":"Noi non siamo uomini da tradimento. I nostri figli mangiano grazie alla vostra grazia, i nostri nomi vivono grazie alla vostra fiducia.","context":"Shi si difende direttamente: prende la frase di Taizu come un sospetto personale."},{"type":"line","speaker":"Imperatore Taizu","to":"Shi Shouxin","line":"Lo so. Se temessi il vostro cuore, non vi avrei chiamati al vino. Temo il cuore degli altri: soldati, attendenti, parenti, uomini che sussurrano quando un generale vittorioso passa davanti a loro.","context":"Taizu distingue tra lealtà personale e pericolo strutturale: anche un generale fedele può diventare centro di ambizioni altrui."},{"type":"line","speaker":"Wang Shenqi","to":"Imperatore Taizu","line":"Un comandante può tenere ferma la propria mano, ma non sempre può tenere ferme le mani di chi gli sta dietro.","context":"Wang riconosce il punto dell’imperatore senza ancora cedere esplicitamente."},{"type":"line","speaker":"Imperatore Taizu","to":["Shi Shouxin","Wang Shenqi"],"line":"Avete combattuto abbastanza da sapere che una freccia non chiede consiglio all’arciere dopo essere partita. Così è il potere militare: una volta teso l’arco, non sempre torna nella faretra.","context":"Taizu usa una metafora militare comprensibile ai generali."},{"type":"stage_direction","action":"Taizu versa personalmente il vino nelle coppe dei due generali. Il gesto è cortese, ma mette i generali in una posizione impossibile: rifiutare sarebbe scortesia, accettare significa entrare nel suo gioco.","context":"Il vino diventa strumento politico, non semplice convivialità."},{"type":"line","speaker":"Shi Shouxin","to":"Imperatore Taizu","line":"Vostra Maestà ci offre vino, ma le vostre parole pesano come ferro. Diteci allora quale colpa dobbiamo lavar via.","context":"Shi è diretto, quasi ferito. Vuole trasformare il sospetto in accusa chiara."},{"type":"line","speaker":"Imperatore Taizu","to":"Shi Shouxin","line":"Nessuna colpa. È questo il punto. Se foste colpevoli, basterebbe una sentenza. Ma voi siete meritevoli, e i meriti sono più difficili da governare delle colpe.","context":"Taizu spiega la logica politica: il problema non è punire, ma prevenire."},{"type":"line","speaker":"Wang Shenqi","to":"Imperatore Taizu","line":"I meriti radunano uomini. Gli uomini radunano aspettative. Le aspettative radunano pericoli.","context":"Wang completa il ragionamento, ormai vicino alla decisione."},{"type":"line","speaker":"Imperatore Taizu","to":"Wang Shenqi","line":"E i pericoli costringono un sovrano a scegliere tra gratitudine e sospetto. Io non voglio diventare un imperatore che uccide i propri fratelli d’armi per poter dormire.","context":"Taizu si presenta come benevolo, ma fa capire che l’alternativa alla rinuncia potrebbe essere violenta."},{"type":"line","speaker":"Shi Shouxin","to":"Wang Shenqi","line":"Fratello Wang, senti anche tu il passo della tigre dietro la porta?","context":"Shi capisce finalmente che non è un invito, ma un passaggio obbligato."},{"type":"line","speaker":"Wang Shenqi","to":"Shi Shouxin","line":"Lo sento. Ma la tigre non è dietro la porta. È nella natura stessa del comando.","context":"Wang mantiene dignità e lucidità: non accusa Taizu, accetta la logica del potere."},{"type":"line","speaker":"Imperatore Taizu","to":["Shi Shouxin","Wang Shenqi"],"line":"Avete terre? Avrete terre più quiete. Avete figli? Li legheremo alla casa imperiale con matrimoni onorevoli. Avete desiderio di ricchezza? La ricchezza non mancherà. Ma lasciate che le armi appartengano al trono, non agli uomini.","context":"Taizu offre la soluzione storicamente coerente: ricchezza, onori, sicurezza familiare in cambio del ritiro dal comando effettivo."},{"type":"line","speaker":"Shi Shouxin","to":"Imperatore Taizu","line":"Vostra Maestà ci chiede di deporre il comando prima che il comando deponga noi.","context":"Shi formula la verità della scena."},{"type":"line","speaker":"Imperatore Taizu","to":"Shi Shouxin","line":"Vi chiedo di invecchiare ricchi, vivi e onorati. È più di quanto gli ultimi decenni abbiano concesso a molti generali.","context":"Taizu richiama implicitamente l’instabilità del periodo precedente alla Song."},{"type":"line","speaker":"Wang Shenqi","to":"Imperatore Taizu","line":"Se domani presentassimo memoriale chiedendo il congedo dai comandi, Vostra Maestà lo giudicherebbe atto di prudenza o di paura?","context":"Wang negozia il modo in cui la rinuncia sarà registrata: vuole preservare l’onore."},{"type":"line","speaker":"Imperatore Taizu","to":"Wang Shenqi","line":"Lo giudicherei atto di saggezza. E la corte saprebbe che chi serve la dinastia non serve solo con la spada, ma anche sapendo quando riporla.","context":"Taizu garantisce una narrazione onorevole."},{"type":"line","speaker":"Shi Shouxin","to":"Imperatore Taizu","line":"Allora domani il vostro servo chiederà di lasciare il comando della Guardia. Non perché il cuore vacilli, ma perché non vacilli l’impero.","context":"Shi accetta, salvando la propria lealtà."},{"type":"line","speaker":"Wang Shenqi","to":"Imperatore Taizu","line":"Anch’io presenterò memoriale. Se le nostre insegne devono scendere perché la dinastia Song resti alta, che scendano senza rumore.","context":"Wang accetta con tono più politico e rassegnato."},{"stage_direction":"Taizu solleva la coppa. I generali lo imitano.","type":"stage_direction","action":"Taizu solleva la coppa. I generali lo imitano.","context":"Il gesto conclude l’accordo: non serve un decreto pronunciato in scena."},{"type":"line","speaker":"Imperatore Taizu","to":["Shi Shouxin","Wang Shenqi"],"line":"Alla pace nelle case, alla quiete nei campi, alla lunga vita dei vecchi compagni.","context":"Brindisi volutamente domestico: Taizu sposta i generali dal mondo della guerra a quello della famiglia e della ricchezza privata."},{"type":"line","speaker":"Shi Shouxin","to":"Imperatore Taizu","line":"Alla lunga vita di Vostra Maestà.","context":"Formula leale, semplice."},{"type":"line","speaker":"Wang Shenqi","to":"Imperatore Taizu","line":"E alla dinastia che oggi impara a sopravvivere ai propri vincitori.","context":"Chiusura più amara e storicamente consapevole."},{"type":"stage_direction","action":"Bevono. Fuori dalla sala, lontanissimi, si sente il cambio della guardia. Taizu resta immobile con la coppa vuota in mano.","context":"Finale sospeso: la pace interna è stata comprata, ma anche il rapporto tra trono ed esercito è cambiato per sempre."}]}]}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('La congiura dei Pazzi', 'lettura', 'it', NULL, 4, 4, '{"description":"Firenze, 26 aprile 1478. Durante la messa grande in Santa Maria del Fiore, i Pazzi e i loro alleati tentano di sterminare i Medici. Giuliano muore sotto diciannove pugnalate, Lorenzo si salva per un soffio — e la vendetta che segue cambia la storia di Firenze. Adattamento dai documenti dell''epoca: la confessione di Giovan Battista da Montesecco, il Commentarium di Poliziano e le Istorie fiorentine di Machiavelli.","characters":[{"name":"Narratore","description":"La voce delle cronache. Guida il pubblico tra Roma e Firenze, cita i documenti, vede il destino prima dei personaggi. Tono asciutto, a tratti ironico."},{"name":"Lorenzo de'' Medici","description":"Il Magnifico. Ventinove anni, signore di Firenze senza corona: colto, rapidissimo, affascinante — e capace di essere spietato quando serve."},{"name":"Francesco de'' Pazzi","description":"Banchiere fiorentino alla corte del papa. Orgoglio di famiglia ferito, odio febbrile per i Medici. Nervoso, sprezzante, incapace di fermarsi."},{"name":"Giovan Battista da Montesecco","description":"Condottiero al soldo del conte Girolamo Riario. Soldato pratico, abituato a uccidere per mestiere, con un unico limite che si scoprirà decisivo: non in chiesa."}],"scenes":[{"id":"scene_1","title":"Roma, il prezzo dell''orgoglio","setting":"Roma, 1477. Una sala nel palazzo del conte Girolamo Riario, nipote di papa Sisto IV. Francesco de'' Pazzi ha fatto chiamare il capitano Giovan Battista da Montesecco.","beats":[{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Firenze, sul finire del Quattrocento. I Medici governano la città senza corona e senza titolo: banchieri che comandano più dei re. I Pazzi sono più antichi, più nobili — e secondi. A Roma, intanto, il papa ha tolto ai Medici il banco pontificio per darlo proprio a loro, ai Pazzi. La miccia è pronta. Serve solo chi l''accenda.","context":"Il conte Riario voleva comprare Imola: Lorenzo negò il prestito, i Pazzi lo concessero. Da lì il favore del papa passò ai Pazzi."},{"type":"line","speaker":"Francesco de'' Pazzi","to":"Giovan Battista da Montesecco","line":"Capitano. Voi servite il conte Riario, e il conte si fida di voi come della sua mano destra. Quello che sto per dirvi non è uscito da questa stanza: c''è un''impresa, a Firenze. Un''impresa che renderà grandi tutti quelli che vi avranno parte.","context":"Francesco parla a bassa voce, controllando la porta. È il reclutamento del braccio armato della congiura."},{"type":"line","speaker":"Giovan Battista da Montesecco","to":"Francesco de'' Pazzi","line":"Messer Francesco, io sono un soldato: le imprese le capisco quando hanno un nome. Parlate chiaro, o questa conversazione è già finita.","context":"Diffidente, concreto. Vuole misurare il rischio prima di tutto."},{"type":"line","speaker":"Francesco de'' Pazzi","to":"Giovan Battista da Montesecco","line":"Chiaro, dunque. Lorenzo de'' Medici ha negato al conte i denari per Imola. Ha strappato ai Pazzi un''eredità intera con una legge scritta apposta, retroattiva. Tiene l''arcivescovo Salviati fuori dalla sua diocesi di Pisa da tre anni, come un servo alla porta. Firenze va liberata da quest''uomo. Liberata, capitano.","context":"L''elenco dei torti è storico: la legge sull''eredità Borromei e il blocco dell''insediamento di Salviati sono documentati."},{"type":"line","speaker":"Giovan Battista da Montesecco","to":"Francesco de'' Pazzi","line":"\\"Liberata.\\" Le parole gentili lasciamole ai notai: voi mi state chiedendo di ammazzare Lorenzo e Giuliano de'' Medici. Tutti e due, perché uno solo non basta. E io, prima di sguainare, voglio sapere chi c''è dietro: chi paga, chi copre, chi risponde.","context":"Montesecco chiama le cose col loro nome: è la sua condizione per continuare ad ascoltare."},{"type":"line","speaker":"Francesco de'' Pazzi","to":"Giovan Battista da Montesecco","line":"Il conte Girolamo Riario. L''arcivescovo Francesco Salviati. La mia famiglia, con il suo oro e le sue braccia. E sopra di noi... alzate gli occhi, capitano. Chi abita più in alto di tutti, a Roma?","context":"L''allusione è a papa Sisto IV. Francesco non lo nomina: lo indica."},{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Quello che accadde dopo lo sappiamo da un documento straordinario: la confessione scritta che Montesecco dettò il quattro maggio 1478, prima di morire. Racconta di un''udienza. Un''udienza con il papa in persona.","context":"La confessione di Montesecco è la fonte principale sulla trama romana della congiura."},{"type":"line","speaker":"Giovan Battista da Montesecco","to":"Pubblico","line":"Il Santo Padre ci ricevette. Disse che desiderava per Firenze un mutamento di stato: Lorenzo era un uomo cattivo e infedele, e con lui la Chiesa non avrebbe mai avuto pace. Ma aggiunse — e lo ripeté due volte — che non voleva la morte di nessuno. Mutamento di stato sì, morte d''uomo no. Poi ci benedisse, e ci congedò.","context":"Ricostruito quasi alla lettera dalla confessione: Sisto IV chiedeva il rovesciamento dei Medici ''senza morte d''alcuno''."},{"type":"line","speaker":"Francesco de'' Pazzi","to":"Giovan Battista da Montesecco","line":"E voi capiste benissimo, capitano, come lo capimmo tutti: non si rovescia uno stato tenendo i pugnali nel fodero. Sua Santità sarà contento del risultato. Del come, non chiederà mai il conto.","context":"Il cinismo della congiura: la benedizione vale per il fine, i mezzi restano ai congiurati."},{"type":"stage_direction","action":"Cambio di luogo: Montesecco viaggia verso la Toscana con il pretesto di affari del conte Riario. A Firenze viene ricevuto da Lorenzo de'' Medici in persona.","context":"Storico: Montesecco incontrò davvero Lorenzo, per studiarlo da vicino, e ne rimase colpito."},{"type":"line","speaker":"Lorenzo de'' Medici","to":"Giovan Battista da Montesecco","line":"Il capitano da Montesecco! L''uomo di fiducia del conte Riario è ospite mio, e non si discute. Ditemi in cosa Firenze può servire il conte: se è cosa che posso fare, è già fatta.","context":"Lorenzo è caloroso, brillante, generoso: non sospetta nulla. L''ironia drammatica è tutta qui."},{"type":"line","speaker":"Giovan Battista da Montesecco","to":"Lorenzo de'' Medici","line":"Il Magnifico mi onora... più di quanto m''aspettassi. Riferirò al conte parole così cortesi. Non le dimenticherò facilmente nemmeno io.","context":"Misurato, quasi a disagio: sta guardando negli occhi l''uomo che ha promesso di uccidere."},{"type":"line","speaker":"Lorenzo de'' Medici","to":"Giovan Battista da Montesecco","line":"E ditegli anche questo: che le ruggini tra Roma e Firenze sono affari di banchieri e di cancellerie, non di uomini. A casa mia un soldato onesto trova sempre la porta aperta e il vino versato.","context":"Documentato nello spirito: Montesecco scriverà di essere stato trattato ''amorevolmente''."},{"type":"line","speaker":"Giovan Battista da Montesecco","to":"Pubblico","line":"M''avevano descritto un tiranno. Ho trovato un uomo che m''ha versato il vino e m''ha parlato d''amicizia. Ho ucciso per mestiere mezza Italia, ma questa commissione comincia a pesarmi come nessun''altra.","context":"A parte. Il dubbio di Montesecco è il seme del suo rifiuto futuro."},{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Ma l''oro del conte era già nelle sue tasche, e le congiure sono carri senza freni: si può scendere, fermarli no. Nella primavera del 1478 tutti i fili convergono su Firenze. Manca solo l''occasione.","context":"Chiusura di scena: transizione verso Firenze."}]},{"id":"scene_2","title":"La vigilia","setting":"Firenze, aprile 1478. Il giovanissimo cardinale Raffaele Riario, nipote del conte, è ospite in città: tra banchetti e visite in suo onore, i congiurati tessono la trappola.","beats":[{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Il piano era un banchetto: i due fratelli Medici a tavola, i congiurati intorno, il veleno o le lame tra una portata e l''altra. Ma Giuliano fa sapere che non verrà: una gamba dolorante, dicono. Le congiure odiano gli imprevisti. Bisogna trovare un luogo dove i due fratelli saranno insieme di sicuro.","context":"Storico: il piano originario del banchetto alla villa saltò per l''assenza di Giuliano."},{"type":"line","speaker":"Francesco de'' Pazzi","to":"Giovan Battista da Montesecco","line":"Giuliano non verrà a cena. Ma c''è un luogo dove i Medici non possono mancare: domenica, la messa grande in Santa Maria del Fiore, davanti al cardinale. Ci sarà tutta Firenze — e ci saranno tutti e due. Si farà lì. Voi prenderete Lorenzo.","context":"Nervoso, febbrile: il piano cambia all''ultimo e Francesco lo impone."},{"type":"line","speaker":"Giovan Battista da Montesecco","to":"Francesco de'' Pazzi","line":"In chiesa? No, messere. Ammazzo un uomo dove volete: in strada, a tavola, nel suo letto. Ma non davanti all''altare, nel momento in cui Dio scende sull''ostia. Non aggiungerò il sacrilegio al tradimento. Questa mano lì dentro non si sporca.","context":"Il rifiuto è storico e documentato: Montesecco non volle uccidere in chiesa, e la sua rinuncia cambiò il destino di Lorenzo."},{"type":"line","speaker":"Francesco de'' Pazzi","to":"Giovan Battista da Montesecco","line":"Scrupoli da sagrestia, capitano, e alla vigilia! Consolatevi: abbiamo chi non trema. Due preti — Antonio Maffei da Volterra e ser Stefano da Bagnone. Uomini di chiesa: l''altare è casa loro, non li spaventa.","context":"L''ironia è delle cronache stesse: al posto del soldato, accettarono due preti."},{"type":"line","speaker":"Giovan Battista da Montesecco","to":"Francesco de'' Pazzi","line":"Un prete col pugnale non è un soldato col pugnale, messer Francesco. La mano gli tremerà. E se Lorenzo esce vivo da quella chiesa, non c''è muro a Firenze abbastanza alto per nascondervi.","context":"Profezia esatta di quello che accadrà: da dire con calma gelida."},{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Il piano, dunque. Il segnale: il campanello dell''elevazione, quando ogni testa si china. Bernardo Bandini e Francesco de'' Pazzi prenderanno Giuliano. I due preti, Lorenzo. L''arcivescovo Salviati andrà a occupare il Palazzo della Signoria, e il vecchio Jacopo de'' Pazzi cavalcherà per le strade a sollevare il popolo. Tutto in un minuto. Cosa mai potrebbe andare storto?","context":"La distribuzione dei compiti è quella storica. L''ultima frase va detta con tutta l''ironia possibile."},{"type":"stage_direction","action":"Palazzo Medici, via Larga. Lorenzo riceve il cardinale Riario e il suo seguito: tra gli ospiti che gli baciano la mano ci sono anche i congiurati.","context":"La sera prima dell''attentato i congiurati furono davvero ospiti di Lorenzo."},{"type":"line","speaker":"Lorenzo de'' Medici","to":"Francesco de'' Pazzi","line":"Messer Francesco! I nostri banchi si fanno la guerra, ma le nostre case si salutano: così va Firenze. Domenica siete dei nostri in Santa Maria del Fiore? Il cardinale vuole vedere il Duomo pieno, e i Pazzi in prima fila fanno bella la città.","context":"Cordiale con un fondo di freddezza: Lorenzo invita il suo assassino alla propria esecuzione senza saperlo."},{"type":"line","speaker":"Francesco de'' Pazzi","to":"Lorenzo de'' Medici","line":"Non mancheremo, Magnifico. Ve lo prometto: domenica, in Duomo, i Pazzi saranno più vicini ai Medici di quanto siano mai stati.","context":"Ogni parola è a doppio taglio. Sorriso perfetto, mani gelide."},{"type":"line","speaker":"Lorenzo de'' Medici","to":"Giovan Battista da Montesecco","line":"E il capitano da Montesecco, ancora tra noi! Firenze vi piace, confessatelo. Restate anche voi per la messa: dopo, il mio vino è di nuovo vostro.","context":"Lorenzo lo riconosce e lo tratta da amico, davanti a tutti."},{"type":"line","speaker":"Giovan Battista da Montesecco","to":"Lorenzo de'' Medici","line":"Il... vostro vino, Magnifico, è di quelli che non si dimenticano. Ma domenica sarò già in viaggio. Affari del conte. Ve l''ho detto: certe cortesie non le dimentico. Vorrei solo... No. Buonanotte, Magnifico.","context":"Per un istante è sul punto di parlare, di avvertirlo. Non lo fa. Questo silenzio è la sua condanna."},{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Nessuno parlò. Quella notte Firenze dormì il suo ultimo sonno tranquillo: l''indomani era domenica 26 aprile 1478.","context":"Chiusura secca. Pausa prima della scena del Duomo."}]},{"id":"scene_3","title":"La domenica dell''elevazione","setting":"Domenica 26 aprile 1478. Santa Maria del Fiore gremita per la messa grande. Sotto la cupola del Brunelleschi c''è tutta Firenze: i Medici, i Pazzi, e diecimila testimoni.","music":"Canto sacro rinascimentale, che si interrompe di colpo al segnale","beats":[{"type":"line","speaker":"Narratore","to":"Pubblico","line":"La messa scorre. Lorenzo è presso il coro, tra gli amici. Giuliano arriva tardi, e non è armato: stamattina Francesco de'' Pazzi e Bernardo Bandini sono passati a prenderlo a casa, scherzando, e per strada Francesco l''ha abbracciato stretto. Non era affetto: cercava con le dita la corazza sotto il farsetto. Non c''era.","context":"L''abbraccio per verificare che Giuliano fosse senza corazza è nelle cronache. Uno dei dettagli più agghiaccianti della storia."},{"type":"line","speaker":"Francesco de'' Pazzi","to":"Pubblico","line":"Niente maglia di ferro. Niente pugnale al fianco. È venuto alla messa nudo come un agnello al macello. Che Dio mi guardi pure: tanto oggi guarda l''ostia.","context":"A parte, febbrile, mentre accompagna Giuliano verso il punto stabilito."},{"type":"line","speaker":"Giovan Battista da Montesecco","to":"Pubblico","line":"Io non ci sono, in quella chiesa. Guardo le porte da fuori, coi miei uomini e la mia vergogna. Ho detto no al sacrilegio, non ho saputo dire no al resto. Aspetto il rumore.","context":"In disparte, cupo: il testimone che avrebbe potuto fermare tutto."},{"type":"stage_direction","action":"Il campanello dell''elevazione. Tutte le teste si chinano. Un istante di silenzio assoluto — poi urla.","context":"Il segnale convenuto dai congiurati era proprio il momento più sacro della messa."},{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Bernardo Bandini pianta la lama nel petto di Giuliano, che fa pochi passi e cade. Francesco de'' Pazzi gli è addosso: colpisce, colpisce, colpisce — diciannove ferite. Colpisce così alla cieca che si pianta il pugnale nella propria coscia.","context":"Tutti i dettagli sono storici: le 19 ferite e l''autoferimento di Francesco alla coscia."},{"type":"line","speaker":"Francesco de'' Pazzi","to":"Pubblico","line":"Muori! Per l''onore dei Pazzi, muori! — Ah! La gamba... non importa, non importa niente: è fatta, è fatta!","context":"Furia cieca. Si è appena ferito da solo: la ferita che tra poche ore lo condannerà."},{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Nello stesso istante, alle spalle di Lorenzo, i due preti estraggono le lame. Ma la mano di Maffei trema — come aveva detto il soldato — e il taglio arriva di striscio, al collo.","context":"La ferita al collo di Lorenzo fu superficiale proprio per l''inesperienza dei sicari."},{"type":"line","speaker":"Lorenzo de'' Medici","to":"Pubblico","line":"Il mantello al braccio — così! — e fuori la spada. Indietro, pretacci! A me! Ai Medici, a me!","context":"Documentato: Lorenzo si avvolse il mantello al braccio come scudo e si difese con la spada."},{"type":"stage_direction","action":"Gli amici fanno cerchio attorno a Lorenzo. Francesco Nori si getta tra lui e Bandini e viene ucciso sul colpo. Poliziano e gli altri spingono Lorenzo nella sagrestia e sbarrano le porte di bronzo.","context":"Nori morì per salvare Lorenzo; le porte bronzee della sagrestia (di Luca della Robbia) fermarono gli assassini."},{"type":"line","speaker":"Lorenzo de'' Medici","to":"Pubblico","line":"Giuliano! Dov''è mio fratello? L''ho visto cadere — qualcuno mi dica di Giuliano! Aprite... no, non aprite. Ditemi solo se respira.","context":"Dalla sagrestia. Un amico gli succhiò la ferita temendo il veleno. Nessuno ebbe il coraggio di rispondergli su Giuliano."},{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Intanto l''arcivescovo Salviati tenta di prendere il Palazzo della Signoria: il gonfaloniere Petrucci lo chiude in una stanza con una porta a scatto. E il vecchio Jacopo de'' Pazzi cavalca in piazza gridando ''Popolo e libertà!''. La piazza gli risponde con le pietre, e con un altro grido: ''Palle! Palle!'' — le palle dello stemma dei Medici.","context":"Tutto storico: la trappola della porta a scatto, il giro a vuoto di Jacopo, il grido mediceo della folla."},{"type":"line","speaker":"Giovan Battista da Montesecco","to":"Pubblico","line":"L''avevo detto io, a messer Francesco: la mano del prete trema. Lorenzo è vivo, il popolo non s''è mosso, e ogni campana di Firenze sta già suonando per i Medici. Ora questa città diventerà un mattatoio — e io conosco i nomi di tutti.","context":"Gelido, da fuori: la congiura è già fallita e lui lo sa per primo."},{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Giuliano de'' Medici, ventiquattro anni, resta sul marmo del Duomo. Lorenzo è vivo. La congiura è durata un minuto: la vendetta durerà anni.","context":"Chiusura di scena, tono da lapide."}]},{"id":"scene_4","title":"Palle, palle","setting":"Firenze, le ore e i giorni seguenti. La città si riversa in strada al grido di ''Palle, palle''. Dalle finestre di Palazzo Vecchio pendono già le prime corde.","beats":[{"type":"line","speaker":"Narratore","to":"Pubblico","line":"La giustizia di Firenze quel giorno non aspettò i tribunali. Francesco de'' Pazzi fu trascinato fuori dal letto dove sanguinava per la ferita che s''era fatto da solo, e portato a Palazzo Vecchio. Lo impiccarono a una finestra, accanto all''arcivescovo Salviati — ancora in abiti da arcivescovo.","context":"Le impiccagioni alle finestre di Palazzo Vecchio avvennero il giorno stesso. Poliziano racconta persino che Salviati, morendo, morse il cadavere di Francesco."},{"type":"line","speaker":"Francesco de'' Pazzi","to":"Pubblico","line":"Non chiedo perdono a Firenze, e non lo chiedo ai Medici. Ho giocato la testa per il nome della mia casa e ho perso. Ricordatevi almeno questo: che i Pazzi non si sono inginocchiati.","context":"Ultime parole alla finestra, ricostruite: le cronache lo descrivono muto e sprezzante fino alla fine."},{"type":"stage_direction","action":"La folla porta teste sulle picche. Lorenzo, fasciato al collo, si affaccia dal palazzo Medici davanti a una moltitudine che grida il suo nome.","context":"Lorenzo parlò alla folla per calmarla, non per aizzarla."},{"type":"line","speaker":"Lorenzo de'' Medici","to":"Pubblico","line":"Fiorentini! Sono vivo — mio fratello no. Vi chiedo giustizia, non macelleria: lasciate fare alla legge, che oggi ha mani abbastanza forti. E chi tocca il cardinale Riario, che è un ragazzo e forse non sapeva, risponde a me.","context":"Documentato: Lorenzo invitò alla moderazione e protesse il giovane cardinale dal linciaggio."},{"type":"line","speaker":"Narratore","to":"Pubblico","line":"La folla lo ascoltò poco. Il vecchio Jacopo de'' Pazzi, fuggito verso l''Appennino, fu riconosciuto e riportato in città: impiccato anche lui. E non bastò: settimane dopo, i ragazzi di Firenze dissotterrarono il suo cadavere, lo trascinarono per le strade e lo gettarono in Arno.","context":"L''accanimento sul cadavere di Jacopo è uno degli episodi più cupi delle cronache."},{"type":"line","speaker":"Lorenzo de'' Medici","to":"Pubblico","line":"Poi toccò al nome. Stemmi scalpellati dai palazzi, il delfino dei Pazzi cancellato da ogni muro, la famiglia bandita, perfino le doti negate a chi ne sposava le figlie. Volevano cancellare i Medici: fu il loro nome, a sparire da Firenze.","context":"La damnatio memoriae dei Pazzi è storica: stemmi rimossi, nome proscritto, matrimoni penalizzati."},{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Il quattro maggio presero anche il capitano da Montesecco. E qui la storia ci ha lasciato il suo documento più prezioso: prima di morire, il soldato dettò tutto. Nomi, luoghi, udienze. È la confessione da cui questo copione è tratto.","context":"La confessione di Montesecco fece luce sul ruolo di Roma nella congiura."},{"type":"line","speaker":"Giovan Battista da Montesecco","to":"Lorenzo de'' Medici","line":"Magnifico, vi dico tutto e non per paura: il conte Riario, l''arcivescovo, i Pazzi — e l''udienza dal papa, parola per parola. Una cosa sola rivendico: quando vollero che vi uccidessi in chiesa, dissi di no. È l''unica cosa che rifarei uguale. Per il resto, chiedo la morte del soldato, non quella del traditore.","context":"Faccia a faccia con l''uomo che aveva promesso di uccidere e che l''aveva trattato da amico."},{"type":"line","speaker":"Lorenzo de'' Medici","to":"Giovan Battista da Montesecco","line":"Vi ho versato il vino una volta, capitano, e voi mi portavate la lama. Ma la vostra confessione vale per Firenze più della vostra spada, e quel ''no'' detto in tempo vi ha reso creditore d''una grazia piccola: avrete la scure, non la corda. Da soldato, come chiedete.","context":"Montesecco fu effettivamente decapitato al Bargello, non impiccato: una distinzione d''onore."},{"type":"line","speaker":"Giovan Battista da Montesecco","to":"Pubblico","line":"Morii da soldato, il quattro maggio 1478, nel cortile del Bargello. Di tutta la congiura, la mia parte fu la più strana: l''assassino che disse no, e non salvò nessuno — nemmeno se stesso.","context":"Epitaffio del personaggio: detto piano, senza autocommiserazione."},{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Mancava Bernardo Bandini, il primo pugnale: fuggì fino a Costantinopoli. Ma il sultano Maometto II lo rimandò a Firenze in catene, e nel dicembre del 1479 fu impiccato anche lui. Sotto la forca, un giovane pittore ne disegnò il corpo appeso, annotando con cura i colori dei vestiti. Si chiamava Leonardo, da Vinci.","context":"Il disegno di Leonardo del cadavere impiccato di Bandini esiste ed è celebre; l''estradizione dal sultano è storica."},{"type":"line","speaker":"Lorenzo de'' Medici","to":"Pubblico","line":"Il papa mi scomunicò e mandò l''interdetto su Firenze; il re di Napoli ci mosse guerra. Allora salii su una nave e andai io stesso da re Ferrante, nella tana del lupo, a comprare la pace con la mia faccia. Tornai vivo, e con la pace in tasca. Da quel giorno Firenze non mi chiamò più soltanto Lorenzo.","context":"Il viaggio a Napoli (1479-80) fu il capolavoro politico di Lorenzo e consacrò il titolo di ''Magnifico''."},{"type":"line","speaker":"Narratore","to":"Pubblico","line":"Così la congiura che doveva abbattere i Medici li lasciò soli al potere. Sui muri del Bargello, Botticelli dipinse gli impiccati, a futura memoria. E la storia la scrissero i sopravvissuti — come sempre. Questa che avete letto, almeno, l''abbiamo presa dai documenti.","context":"Botticelli dipinse davvero i congiurati impiccati; l''affresco fu poi distrutto. Chiusura al pubblico."}]}]}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('Pinocchio e il Campo dei miracoli', 'lettura', 'it', NULL, 4, 6, '{"description":"Da «Le avventure di Pinocchio» di Carlo Collodi (1883), capitoli XII, XIII, XVIII e XIX: la Volpe e il Gatto abbindolano Pinocchio con la promessa del Campo dei miracoli, dove gli zecchini si seminano e fioriscono come i fagioli. In scena c''è anche Collodi in persona: l''autore discute col suo burattino, prova (invano) a raddrizzargli la testa di legno, e intanto presta la voce all''oste, al Grillo, al Pappagallo, al giudice e al carceriere — perché la storia, ormai, è scritta e deve andare avanti.","characters":[{"name":"Collodi","description":"L''autore, dentro la sua storia. Brontolone toscano, parla direttamente coi suoi personaggi: avverte Pinocchio, litiga col Gatto, si dispera perché il burattino non gli dà mai retta — ma la storia è già stampata e lui deve mandarla avanti. Presta la voce ai personaggi minori: l''oste del Gambero Rosso, l''ombra del Grillo-parlante, il Pappagallo, il giudice e il carceriere."},{"name":"Pinocchio","description":"Il burattino. Ingenuo, entusiasta, di buon cuore ma senza un fil di giudizio: basta la parola «zecchini» per fargli dimenticare babbo, Abbecedario e ogni buon proponimento. Al suo autore, quando lo sente brontolare, risponde — o peggio: non risponde affatto."},{"name":"La Volpe","description":"Zoppa (per finta). L''imbrogliona che conduce il gioco: mielosa, garbatissima, si commuove delle proprie bugie e si offende quando le offrono un regalo."},{"name":"Il Gatto","description":"Cieco (per finta). Il complice di poche parole: ripete sempre l''ultima frase della Volpe. Ma quando c''è da mangiare — un merlo, per esempio — ci vede benissimo."}],"scenes":[{"id":"scene_1","title":"Cinque monete d''oro","setting":"Una strada di campagna, di mattina. Pinocchio torna verso casa dal teatro di Mangiafoco, con cinque monete d''oro in tasca. Al tavolino, in un angolo di luce, l''autore: penna, calamaio e poca pazienza.","music":"Una marcetta allegra e birichina, da fiaba","beats":[{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Dunque, dove eravamo. Il burattinaio Mangiafoco, commosso, ti ha regalato cinque monete d''oro: e tu le porti subito al tuo babbo Geppetto, siamo intesi? Dritto a casa, senza voltarti. Ti conosco: t''ho fatto io, dal ciuffo ai piedi. E infatti... eccole lì, sulla strada: una Volpe zoppa da un piede e un Gatto cieco da tutt''e due gli occhi, che se ne vanno là là, aiutandosi fra loro, da buoni compagni di sventura. Pinocchio. Pinocchio, guardami: dritto a casa.","context":"Cap. XII. L''autore apre la storia parlando direttamente al suo burattino. La Volpe zoppa cammina appoggiandosi al Gatto, e il Gatto cieco si lascia guidare dalla Volpe."},{"type":"line","speaker":"Pinocchio","to":"Collodi","line":"Dritto a casa, sicuro, parola di burattino! Casacca nuova per il babbo, Abbecedario per me, e a scuola da lunedì. Che cosa mai potrebbe succedere, di qui a casa?","context":"Promessa fatta col cuore: durerà una trentina di secondi."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Buon giorno, Pinocchio!","context":"Salutandolo garbatamente."},{"type":"line","speaker":"Pinocchio","to":"La Volpe","line":"Com''è che sai il mio nome?"},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Conosco bene il tuo babbo: l''ho veduto ieri sulla porta di casa sua. Era in maniche di camicia, e tremava dal freddo.","context":"Condensa un botta e risposta del cap. XII."},{"type":"line","speaker":"Pinocchio","to":"La Volpe","line":"Povero babbo! Ma, se Dio vuole, da oggi in poi non tremerà più… perché io sono diventato un gran signore."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Un gran signore… tu?","context":"Ride di un riso sguaiato e canzonatore."},{"type":"stage_direction","action":"Il Gatto ride anche lui; ma per non darlo a vedere, si pettina i baffi con le zampe davanti."},{"type":"line","speaker":"Pinocchio","to":["La Volpe","Il Gatto"],"line":"C''è poco da ridere! Mi dispiace davvero di farvi venire l''acquolina in bocca, ma queste qui, se ve ne intendete, sono cinque bellissime monete d''oro.","context":"Impermalito, tira fuori le monete avute in regalo da Mangiafoco."},{"type":"stage_direction","action":"Al simpatico suono di quelle monete, la Volpe allunga senza volere la gamba che pareva rattrappita, e il Gatto spalanca tutt''e due gli occhi, che paiono due lanterne verdi. Poi li richiude subito: Pinocchio non si accorge di nulla."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"E ora che cosa vuoi farne di codeste monete?"},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Di codeste monete?","context":"Il Gatto ripete sempre l''ultima frase della Volpe: è il suo modo di conversare."},{"type":"line","speaker":"Pinocchio","to":["La Volpe","Il Gatto"],"line":"Prima di tutto voglio comprare per il mio babbo una bella casacca nuova, tutta d''oro e d''argento e coi bottoni di brillanti; e poi voglio comprare un Abbecedario per me, perché voglio andare a scuola e mettermi a studiare a buono."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Guarda me! Per la passione sciocca di studiare ho perduto una gamba."},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Guarda me! Per la passione sciocca di studiare ho perduto la vista di tutt''e due gli occhi."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Pinocchio, non dar retta ai consigli dei cattivi compagni: se no, te ne pentirai! Senti cosa ha da dire questo Merlo.","context":"Collodi presta la voce al Merlo bianco appollaiato sulla siepe: un ultimo tentativo di salvare il salvabile."},{"type":"stage_direction","action":"Il Gatto, spiccando un gran salto, si avventa sul Merlo e se lo mangia"},{"type":"line","speaker":"Collodi","to":"Il Gatto","line":"Ehi! Quel Merlo ce l''avevo messo io, sulla siepe! Un personaggio intero, mangiato a metà della sua unica battuta. Con te non si può lavorare, Gatto: e il peggio è che t''ho scritto io così.","context":"L''autore protesta col suo personaggio: indignazione vera, autorità nessuna."},{"type":"line","speaker":"Pinocchio","to":"Il Gatto","line":"Povero Merlo! Perché l''hai trattato così male?"},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Ho fatto per dargli una lezione. Così un''altra volta imparerà a non metter bocca nei discorsi degli altri."}]},{"id":"scene_2","title":"Il paese dei Barbagianni","setting":"Più che a mezza strada verso casa. La Volpe si ferma di punto in bianco e guarda il burattino.","beats":[{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Vuoi tu raddoppiare le tue monete d''oro? Vuoi tu, di cinque miserabili zecchini, farne cento, mille, duemila?"},{"type":"line","speaker":"Pinocchio","to":"La Volpe","line":"Magari! E la maniera?"},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"La maniera è facilissima: invece di tornartene a casa tua, dovresti venir con noi, nel paese dei Barbagianni."},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Nel paese dei Barbagianni!"},{"type":"line","speaker":"Pinocchio","to":["La Volpe","Il Gatto"],"line":"No, non ci voglio venire. Oramai sono vicino a casa, e voglio andarmene a casa, dove c''è il mio babbo che m''aspetta. Purtroppo io sono stato un figliuolo cattivo, e il Grillo-parlante aveva ragione quando diceva: «I ragazzi disobbedienti non possono aver bene in questo mondo.»","context":"Condensato: nel romanzo ricorda anche i pericoli corsi in casa di Mangiafoco."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Dunque vuoi proprio andare a casa tua? Allora va'' pure, e tanto peggio per te."},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Tanto peggio per te!"},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Pensaci bene, Pinocchio, perché tu dài un calcio alla fortuna."},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Alla fortuna!"},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"I tuoi cinque zecchini, dall''oggi al domani, sarebbero diventati duemila."},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Duemila!"},{"type":"line","speaker":"Pinocchio","to":"La Volpe","line":"Ma com''è mai possibile che diventino tanti?","context":"Resta a bocca aperta dallo stupore."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Te lo spiego subito. Bisogna sapere che nel paese dei Barbagianni c''è un campo benedetto, chiamato da tutti il Campo dei miracoli. Tu fai in questo campo una piccola buca e ci metti dentro uno zecchino d''oro; poi ricopri la buca con un po'' di terra, l''annaffi con due secchie d''acqua di fontana, ci getti sopra una presa di sale, e la sera te ne vai tranquillamente a letto. Durante la notte lo zecchino germoglia e fiorisce, e la mattina dopo, ritornando nel campo, trovi un bell''albero carico di tanti zecchini d''oro quanti chicchi di grano può avere una bella spiga nel mese di giugno."},{"type":"line","speaker":"Pinocchio","to":"La Volpe","line":"Sicché dunque, se io sotterrassi in quel campo i miei cinque zecchini, la mattina dopo quanti zecchini vi troverei?"},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"È un conto facilissimo, un conto che puoi farlo sulla punta delle dita. Poni che ogni zecchino ti faccia un grappolo di cinquecento zecchini: moltiplica il cinquecento per cinque, e la mattina dopo trovi in tasca duemilacinquecento zecchini lampanti e sonanti."},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Lampanti e sonanti!"},{"type":"line","speaker":"Pinocchio","to":["La Volpe","Il Gatto"],"line":"Oh che bella cosa! Appena questi zecchini li avrò raccolti, ne prenderò per me duemila, e gli altri cinquecento li darò in regalo a voialtri due.","context":"Ballando dall''allegrezza."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Un regalo a noi? Dio te ne liberi! Noi non lavoriamo per il vile interesse: noi lavoriamo per arricchire gli altri.","context":"Sdegnandosi e chiamandosi offesa."},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Gli altri!"},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"«Che brave persone!» — lo so che lo stai pensando, ti sento pensare: t''ho fabbricato io, testa di legno compresa. E il babbo che trema dal freddo? E la casacca nuova? E l''Abbecedario? Pinocchio, una parola sola, guardami: la matematica dei furbi torna sempre... per i furbi.","context":"Nel romanzo: «E dimenticandosi lì sul tamburo del suo babbo, della casacca nuova, dell''Abbecedario e di tutti i buoni proponimenti fatti...». L''autore prova a fermarlo."},{"type":"line","speaker":"Pinocchio","to":["La Volpe","Il Gatto"],"line":"Andiamo subito: io vengo con voi.","context":"Ignorando completamente il suo autore."}]},{"id":"scene_3","title":"L''osteria del Gambero Rosso","setting":"Sul far della sera. Un''osteria di campagna: il Gambero Rosso. I tre viandanti arrivano stanchi morti.","music":"Brusio d''osteria, stoviglie e un violino sgangherato","beats":[{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"E cammina, cammina, cammina — v''ho fatto camminare fino a sera apposta, sperando che ti passasse la voglia. Macché. Eccovi arrivati, stanchi morti, all''osteria del Gambero Rosso. Entrate, entrate: tanto qui dentro so già come va a finire.","context":"Cap. XIII. L''autore li accompagna dentro, rassegnato."},{"type":"line","speaker":"La Volpe","to":["Pinocchio","Il Gatto"],"line":"Fermiamoci un po'' qui, tanto per mangiare un boccone e per riposarci qualche ora. A mezzanotte poi ripartiremo, per essere domani all''alba nel Campo dei miracoli."},{"type":"line","speaker":"Collodi","to":"Il Gatto","line":"E a tavola, si capisce, nessuno di voi aveva appetito. Tu per primo, povero Gatto: gravemente indisposto di stomaco com''eri, non hai potuto mangiare altro che trentacinque triglie con salsa di pomodoro e quattro porzioni di trippa alla parmigiana. Un languorino, insomma.","context":"L''ironia è di Collodi, dal romanzo: da dire al Gatto guardandolo dritto negli occhi «ciechi»."},{"type":"line","speaker":"Il Gatto","to":"Oste","line":"Oste! Ancora burro e formaggio grattato: questa trippa non mi pare condita abbastanza!","context":"Nel romanzo si rifà tre volte a chiedere il burro e il formaggio: battuta ricostruita dalla narrazione. Al suo autore non degna nemmeno un miagolio."},{"type":"line","speaker":"Collodi","to":["La Volpe","Pinocchio"],"line":"E madama, qui, che il medico ha messo a grandissima dieta, s''è dovuta contentare d''una semplice lepre dolce e forte, con un leggerissimo contorno di pollastre ingrassate e di galletti di primo canto. Tu invece, Pinocchio: uno spicchio di noce, un cantuccino di pane, e tutto lasciato nel piatto. Lo so io che cos''hai: col pensiero fisso a quel campo, l''indigestione di monete d''oro l''hai già presa in anticipo.","context":"Dal romanzo, quasi alla lettera: l''autore fa la conta dei piatti come un oste che presenta il conto."},{"type":"line","speaker":"La Volpe","to":"Oste","line":"Oste, datemi due buone camere: una per il signor Pinocchio, e un''altra per me e per il mio compagno. Prima di ripartire schiacceremo un sonnellino. Ricordatevi però che a mezzanotte vogliamo essere svegliati per continuare il nostro viaggio."},{"type":"line","speaker":"Collodi","to":"La Volpe","line":"«Sissignore!»","context":"Collodi si presta a fare l''oste: e strizza l''occhio alla Volpe e al Gatto, come a dire: «Ho mangiato la foglia, e ci siamo intesi!»"},{"type":"stage_direction","action":"Pinocchio va a letto e si addormenta di colpo. Sogna un campo pieno di arboscelli carichi di grappoli di zecchini d''oro che, dondolando al vento, fanno zin, zin, zin, come a dire: «Chi ci vuole, venga a prenderci.» Ma sul più bello, tre violentissimi colpi alla porta lo svegliano: è l''oste. La mezzanotte è sonata."},{"type":"line","speaker":"Pinocchio","to":"Oste","line":"E i miei compagni sono pronti?"},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Altro che pronti! Sono partiti due ore fa: il Gatto ha ricevuto un''imbasciata che il suo gattino maggiore, malato di geloni ai piedi, stava in pericolo di vita.","context":"Con la voce dell''oste."},{"type":"line","speaker":"Pinocchio","to":"Oste","line":"E la cena l''hanno pagata?"},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Che vi pare? Quelle lì sono persone troppo educate, perché facciano un affronto simile alla signoria vostra.","context":"Con la voce dell''oste, untuosissimo."},{"type":"line","speaker":"Pinocchio","to":"Oste","line":"Peccato! Quest''affronto mi avrebbe fatto tanto piacere! E dove hanno detto di aspettarmi, quei buoni amici?","context":"Grattandosi il capo."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"«Al Campo dei miracoli, domattina, allo spuntare del giorno.» E tu paghi, naturalmente: uno zecchino, per la cena tua e per quella dei tuoi compagni. Te ne restano quattro. Va'', va'' pure, benedetto figliuolo: fuori c''è un buio così buio che non ci si vede da qui a lì.","context":"Prima con la voce dell''oste, poi con la sua: l''autore lo guarda uscire nella notte e non può far altro che seguirlo."},{"type":"stage_direction","action":"Lungo la strada, sul tronco di un albero, riluce un piccolo animaletto di luce pallida e opaca, come un lumino da notte dentro una lampada di porcellana trasparente."},{"type":"line","speaker":"Pinocchio","to":"Grillo","line":"Chi sei?"},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Sono l''ombra del Grillo-parlante. Voglio darti un consiglio: ritorna indietro, e porta i quattro zecchini che ti sono rimasti al tuo povero babbo, che piange e si dispera per non averti più veduto.","context":"Con una vocina fioca fioca, che pare venire dal mondo di là."},{"type":"line","speaker":"Pinocchio","to":"Grillo","line":"Domani il mio babbo sarà un gran signore, perché questi quattro zecchini diventeranno duemila."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Non ti fidare, ragazzo mio, di quelli che promettono di farti ricco dalla mattina alla sera. Per il solito, o sono matti o imbroglioni! Dài retta a me: ritorna indietro. L''ora è tarda!… La nottata è scura…","context":"Sempre con la vocina del Grillo."},{"type":"line","speaker":"Pinocchio","to":"Grillo","line":"E io invece voglio andare avanti."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"La strada è pericolosa… Ricordati che i ragazzi che vogliono fare di loro capriccio e a modo loro, prima o poi se ne pentono.","context":"Voce del Grillo."},{"type":"line","speaker":"Pinocchio","to":"Grillo","line":"Voglio andare avanti! Le solite storie. Buona notte, Grillo."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Buona notte, Pinocchio: e che il cielo ti salvi dalla guazza e dagli assassini!","context":"Voce del Grillo, quasi un sospiro. L''autore, stavolta, la pensa esattamente come il suo Grillo."},{"type":"stage_direction","action":"Appena dette queste ultime parole, il Grillo-parlante si spegne a un tratto, come si spegne un lume soffiandoci sopra. E la strada rimane più buia di prima."}]},{"id":"scene_4","title":"Il ritrovo nel bosco","setting":"Molti giorni dopo, nel bosco, quasi in faccia alla Quercia grande. Pinocchio va incontro al suo babbo Geppetto per la via del bosco.","beats":[{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Da quella notte te ne sono capitate di tutti i colori: due assassini incappucciati in due sacchi di carbone t''hanno dato la caccia per rubarti gli zecchini, e a uno — bravo, questo lo dico — hai staccato con un morso l''intera zampa. Poi t''hanno impiccato al ramo della Quercia grande. E ti dirò una cosa, Pinocchio: io volevo finirla lì, la storia. Ero stanco, e mi pagavano poco. Ma i bambini scrissero al giornale, protestarono, pretesero: e dovetti mandare la Fata dai capelli turchini a salvarti. Ora corri incontro al tuo babbo... e chi ti vedo arrivare sulla strada? Loro due. Di nuovo.","context":"Riassume i capp. XIV–XVII. Vero anche il resto: Collodi chiuse davvero la storia col burattino impiccato (cap. XV, ottobre 1881, sul «Giornale per i bambini») e la riprese mesi dopo per le proteste dei piccoli lettori. Il particolare della zampa mozzata tornerà utile fra poco…"},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Ecco il nostro caro Pinocchio! Come mai sei qui?","context":"Abbracciandolo e baciandolo."},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Come mai sei qui?"},{"type":"line","speaker":"Pinocchio","to":["La Volpe","Il Gatto"],"line":"È una storia lunga, e ve la racconterò a comodo. Sappiate però che l''altra notte, quando mi avete lasciato solo all''osteria, ho trovato gli assassini per la strada… Mi volevano rubare le monete d''oro!"},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Gli assassini?… Oh, povero amico! E che cosa volevano? Infami!…"},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Infamissimi!"},{"type":"line","speaker":"Pinocchio","to":["La Volpe","Il Gatto"],"line":"Ma io cominciai a scappare, e loro sempre dietro: finché mi raggiunsero e m''impiccarono a un ramo di quella quercia.","context":"Accenna la Quercia grande, lì a due passi. Gli «assassini», naturalmente, erano proprio loro due."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Si può sentir di peggio? In che mondo siamo condannati a vivere? Dove troveremo un rifugio sicuro, noi altri galantuomini?"},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Noi altri galantuomini!"},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Pinocchio. Psst, Pinocchio. Mentre parlano così, guardagli la gamba destra davanti, al «galantuomo»: manca in fondo tutto lo zampetto con gli unghioli. Ti ricorda niente, quel morso? Su, per una volta: usala, la testa di legno.","context":"L''autore, per la prima volta, prova a suggerire invece che a predicare."},{"type":"line","speaker":"Pinocchio","to":"Il Gatto","line":"Che cosa hai fatto del tuo zampetto?"},{"type":"stage_direction","action":"Il Gatto vorrebbe rispondere qualche cosa, ma s''imbroglia. La Volpe interviene subito."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Il mio amico è troppo modesto, e per questo non risponde: risponderò io per lui. Sappi dunque che un''ora fa abbiamo incontrato sulla strada un vecchio lupo, quasi svenuto dalla fame, che ci ha chiesto un po'' d''elemosina. Non avendo noi da dargli nemmeno una lisca di pesce, che cosa ha fatto l''amico mio, che ha davvero un cuore di Cesare? Si è staccato coi denti uno zampetto delle sue gambe davanti, e l''ha gettato a quella povera bestia, perché potesse sdigiunarsi.","context":"Nel dir così, si asciuga una lagrima. La verità: quello zampetto glielo ha staccato Pinocchio con un morso, la notte degli assassini."},{"type":"line","speaker":"Pinocchio","to":"Il Gatto","line":"Se tutti i gatti ti somigliassero, fortunati i topi!","context":"Sussurrandoglielo negli orecchi, commosso anche lui. L''autore, al tavolino, si prende la testa fra le mani."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"E ora che cosa fai in questi luoghi?"},{"type":"line","speaker":"Pinocchio","to":"La Volpe","line":"Aspetto il mio babbo, che deve arrivare qui di momento in momento."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"E le tue monete d''oro?"},{"type":"line","speaker":"Pinocchio","to":"La Volpe","line":"Le ho sempre in tasca, meno una che la spesi all''osteria del Gambero Rosso."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"E pensare che, invece di quattro monete, potrebbero diventare domani mille e duemila! Perché non dài retta al mio consiglio? Perché non vai a seminarle nel Campo dei miracoli? Un altro giorno sarà tardi: quel campo è stato comprato da un gran signore, e da domani in là non sarà più permesso a nessuno di seminarvi i denari.","context":"Condensa un breve scambio del cap. XVIII."},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Sarà tardi!"},{"type":"line","speaker":"Pinocchio","to":"La Volpe","line":"Quant''è distante di qui il Campo dei miracoli?"},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Due chilometri appena. Vuoi venire con noi? Fra mezz''ora sei là: semini subito le quattro monete, dopo pochi minuti ne raccogli duemila, e stasera ritorni qui colle tasche piene."},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Vuoi venire con noi?","context":"Nel romanzo la Volpe ripete due volte la domanda: qui la seconda tocca al Gatto."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Esita, esita! Vedo che ti tornano in mente la buona Fata, il vecchio Geppetto, gli avvertimenti del Grillo... Pinocchio, ascoltami: questo capitolo l''ho già scritto, e so come va a finire. Te lo chiedo da autore a burattino, per una volta soltanto: di'' di no.","context":"Nel romanzo: «Pinocchio esitò un poco a rispondere... ma poi finì col fare come fanno tutti i ragazzi senza un fil di giudizio e senza cuore: dette una scrollatina di capo, e disse:»"},{"type":"line","speaker":"Pinocchio","to":["La Volpe","Il Gatto"],"line":"Andiamo pure: io vengo con voi.","context":"Una scrollatina di capo, e via. L''autore ha perso anche questa."}]},{"id":"scene_5","title":"Il Campo dei miracoli","setting":"Dopo mezza giornata di cammino: la città di Acchiappacitrulli e, fuori dalle mura, un campo solitario che somiglia su per giù a tutti gli altri campi.","music":"Vento leggero, atmosfera sospesa","beats":[{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Benvenuto ad Acchiappacitrulli, Pinocchio. Il nome l''ho scelto io: dimmi tu se non parla da solo. Guardati intorno: cani spelacchiati che sbadigliano dall''appetito, pecore tosate che tremano dal freddo, galline rimaste senza cresta che chiedono l''elemosina d''un chicco di granturco, farfalle che non possono più volare perché hanno venduto le loro bellissime ali colorite. Lo vedi, sì, che cosa hanno in comune? Hanno tutti seminato zecchini, da queste parti.","context":"Nel romanzo, fra questa folla di accattoni passano carrozze signorili con dentro qualche volpe, qualche gazza ladra o qualche uccellaccio di rapina."},{"type":"line","speaker":"Pinocchio","to":"La Volpe","line":"E il Campo dei miracoli dov''è?","context":"All''autore e alla sua città parlante non ha dato nessun ascolto."},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"È qui a due passi… Eccoci giunti! Ora chinati giù a terra, scava con le mani una piccola buca nel campo, e mettici dentro le monete d''oro."},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Le monete d''oro!"},{"type":"stage_direction","action":"Pinocchio obbedisce: scava la buca, ci pone le quattro monete d''oro che gli sono rimaste, e ricopre la buca con un po'' di terra. Poi, non avendo lì per lì una secchia, si leva una ciabatta, la riempie d''acqua alla gora vicina e annaffia la terra che copre la buca."},{"type":"line","speaker":"Pinocchio","to":"La Volpe","line":"C''è altro da fare?"},{"type":"line","speaker":"La Volpe","to":"Pinocchio","line":"Nient''altro. Ora possiamo andar via. Tu poi ritorna qui fra una ventina di minuti, e troverai l''arboscello già spuntato dal suolo, coi rami tutti carichi di monete."},{"type":"line","speaker":"Il Gatto","to":"Pinocchio","line":"Tutti carichi di monete!"},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"E tu li ringrazi. Mille volte, li ringrazi! Fuori di te dalla contentezza, gli prometti perfino un bellissimo regalo. Pinocchio, figliolo mio di legno: stanno per rubarti anche il grazie.","context":"Dal romanzo: «Il povero burattino, fuori di sé dalla contentezza, ringraziò mille volte la Volpe e il Gatto, e promise loro un bellissimo regalo.»"},{"type":"line","speaker":["La Volpe","Il Gatto"],"to":"Pinocchio","line":"Noi non vogliamo regali! A noi ci basta di averti insegnato il modo di arricchire senza durar fatica, e siamo contenti come pasque.","context":"«Risposero que'' due malanni», scrive Collodi. Salutano ed escono, augurandogli una buona raccolta."},{"type":"stage_direction","action":"La Volpe e il Gatto se ne vanno per i fatti loro. Pinocchio torna in città e conta i minuti a uno a uno; quando gli pare che sia l''ora, riprende di corsa la strada del campo, col cuore che gli batte forte e fa tic, tac, tic, tac, come un orologio da sala."},{"type":"line","speaker":"Pinocchio","to":"Pubblico","line":"E se invece di mille monete, ne trovassi su i rami dell''albero duemila?… E se invece di duemila, ne trovassi cinquemila?… E se invece di cinquemila, ne trovassi centomila? Oh che bel signore che diventerei! Vorrei un bel palazzo, mille cavallini di legno e mille scuderie per potermi baloccare, una cantina di rosolii e di alchermes, e una libreria tutta piena di canditi, di torte, di panettoni, di mandorlati e di cialdoni colla panna.","context":"Cap. XIX: fantastica ad occhi aperti mentre cammina."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Ecco il campo. E l''albero carico di zecchini? Nulla. Fai pure altri cento passi: nulla. Va'' sulla buca, va'': nulla, Pinocchio. Te l''avevo... no, lascia stare, non lo dico. Senti piuttosto che risata, lassù: c''è un grosso Pappagallo, sopra l''albero, che si spollina le poche penne che ha addosso.","context":"Nel romanzo Pinocchio, «dimenticando le regole del Galateo e della buona creanza», si dà una lunghissima grattatina di capo."},{"type":"line","speaker":"Pinocchio","to":"Pappagallo","line":"Perché ridi?","context":"Con voce di bizza."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Rido perché, nello spollinarmi, mi son fatto il solletico sotto le ali.","context":"Collodi presta la voce al Pappagallo."},{"type":"stage_direction","action":"Pinocchio non risponde. Va alla gora, riempie d''acqua la solita ciabatta e si rimette ad annaffiare la terra che ricopre le monete. Un''altra risata, ancora più impertinente della prima, risuona nella solitudine silenziosa del campo."},{"type":"line","speaker":"Pinocchio","to":"Pappagallo","line":"Insomma, si può sapere, Pappagallo mal educato, di che cosa ridi?","context":"Arrabbiandosi."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Rido di quei barbagianni che credono a tutte le scioccherie, e che si lasciano trappolare da chi è più furbo di loro.","context":"Voce del Pappagallo."},{"type":"line","speaker":"Pinocchio","to":"Pappagallo","line":"Parli forse di me?"},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Sì, parlo di te, povero Pinocchio: di te che sei così dolce di sale, da credere che i denari si possano seminare e raccogliere nei campi, come si seminano i fagioli e le zucche. Anch''io l''ho creduto una volta, e oggi ne porto le pene. Oggi — ma troppo tardi! — mi son dovuto persuadere che, per mettere insieme onestamente pochi soldi, bisogna saperseli guadagnare o col lavoro delle proprie mani o coll''ingegno della propria testa.","context":"Voce del Pappagallo. E qui, sotto le penne, parla anche un po'' l''autore: Carlo Lorenzini coi tavoli da gioco ci aveva perso davvero dei soldi."},{"type":"line","speaker":"Pinocchio","to":"Pappagallo","line":"Non ti capisco.","context":"Comincia già a tremare dalla paura."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Pazienza! Mi spiegherò meglio. Sappi dunque che, mentre tu eri in città, la Volpe e il Gatto sono tornati in questo campo: hanno preso le monete d''oro sotterrate, e poi sono fuggiti come il vento. E ora chi li raggiunge, è bravo!","context":"Voce del Pappagallo."},{"type":"stage_direction","action":"Pinocchio resta a bocca aperta. Non volendo credere alle parole del Pappagallo, comincia a scavare con le mani e con le unghie il terreno che aveva annaffiato: scava, scava, scava, e fa una buca così profonda che ci starebbe in piedi un pagliaio. Ma le monete non ci sono più."},{"type":"line","speaker":"La Volpe","to":"Pubblico","line":"Noi non lavoriamo per il vile interesse: noi lavoriamo per arricchire gli altri!","context":"Da lontano, come un''eco beffarda: ripresa teatrale della battuta del cap. XII."},{"type":"line","speaker":"Il Gatto","to":"Pubblico","line":"Gli altri!","context":"Eco dell''eco, ancora più lontana."}]},{"id":"scene_6","title":"Il tribunale di Acchiappacitrulli","setting":"La città di Acchiappacitrulli: il tribunale, poi la prigione.","beats":[{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"E adesso, disperato come sei, dove corri? In tribunale, naturalmente: a denunciare i due malandrini. Vieni, ti presento il giudice: uno scimmione della razza dei Gorilla, rispettabile per la sua grave età, per la sua barba bianca e specialmente per i suoi occhiali d''oro senza vetri, che è costretto a portare a motivo d''una flussione d''occhi che lo tormenta da parecchi anni. In questa città, Pinocchio, è il meglio che ti possa capitare. E scusami: la città l''ho scritta io.","context":"Cap. XIX."},{"type":"line","speaker":"Pinocchio","to":"Giudice","line":"Signor giudice, chiedo giustizia! La Volpe e il Gatto mi hanno derubato con un''iniqua frode: quattro monete d''oro, sotterrate e sparite!","context":"Condensa il racconto «per filo e per segno» dell''iniqua frode, con nomi, cognomi e connotati dei malandrini."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"E il giudice ti ascolta con molta benignità, guarda: prende vivissima parte al racconto, s''intenerisce, si commuove. Poi allunga la mano, suona il campanello, e ai due can mastini vestiti da giandarmi dice: «Quel povero diavolo è stato derubato di quattro monete d''oro: pigliatelo dunque, e mettetelo subito in prigione.»","context":"Collodi presta la voce anche al giudice — e non è fiero di quello che gli tocca dirgli."},{"type":"stage_direction","action":"Pinocchio, sentendosi dare questa sentenza fra capo e collo, resta di princisbecco e vorrebbe protestare: ma i giandarmi, a scanso di perditempi inutili, gli tappano la bocca e lo conducono in gattabuia."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Quattro mesi, Pinocchio. Quattro lunghissimi mesi ti ci ho dovuto lasciare, in gattabuia. E ci saresti rimasto anche di più, se il giovane Imperatore di Acchiappacitrulli, per festeggiare una gran vittoria sui suoi nemici, non avesse ordinato feste pubbliche e fatto aprire le carceri a tutti i malandrini.","context":"L''autore si scusa quasi: ma la giustizia di Acchiappacitrulli funziona così."},{"type":"line","speaker":"Pinocchio","to":"Carceriere","line":"Se escono di prigione gli altri, voglio uscire anch''io."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Voi no, perché voi non siete del bel numero…","context":"Collodi presta la voce al carceriere."},{"type":"line","speaker":"Pinocchio","to":"Carceriere","line":"Domando scusa: sono un malandrino anch''io."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"In questo caso avete mille ragioni.","context":"Voce del carceriere: e levandosi il berretto rispettosamente, gli apre le porte della prigione."},{"type":"stage_direction","action":" Pinocchio viene liberato e prende la corsa fuori dalla città senza voltarsi indietro."},{"type":"line","speaker":"Collodi","to":"Pinocchio","line":"Corri, corri, testa di legno. La morale l''aveva già detta il mio Grillo: di quelli che promettono ricchezze dalla mattina alla sera, per il solito o matti o imbroglioni, non fidarsi mai. Io ho provato a fermarti a ogni pagina, e non ci sono mai riuscito: ma forse è proprio per questo che i bambini non hanno voluto lasciarti morire. Va'', va'' dalla tua Fata. Io resto qui: tanto lo so che al prossimo capitolo mi fai disperare di nuovo.","context":"Congedo dell''autore dal suo personaggio. Il romanzo prosegue con il ritorno di Pinocchio dalla Fata."}]}]}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('Cecè - Pirandello', 'lettura', 'it', NULL, 3, 3, '{"description":"Commedia in un atto di Luigi Pirandello (1913), qui divisa in tre scene. Cecè Vivoli, vitaiolo che tutta Italia chiama per nome, deve riavere tre cambiali da seimila lire finite in mano alla bella Nada. Convince l''imbarazzatissimo commendator Squatriglia a fingersi amico di famiglia e a coprirlo di insulti per farsele restituire a prezzo di saldo. Testo originale adattato dall''edizione Mondadori (Maschere nude, vol. II).","characters":[{"name":"Cecè","description":"Cesare Vivoli, detto Cecè: vitaiolo elegante, chiacchierone e squattrinato, conosciuto da centomila persone in tutta Italia. Improvvisa truffe con la faccia più candida del mondo e non perde mai il controllo della commedia che sta recitando."},{"name":"Squatriglia","description":"Il commendator Carlo Squatriglia, appaltatore di lavori portuali con un occhio ''murato'' da uno scoppio di mina. Goffo, sudatissimo, onesto fino al midollo: l''ultima persona al mondo adatta a recitare una parte, e proprio per questo costretto a farlo."},{"name":"Nada","description":"Signorina del bel mondo, bella, ironica e per niente ingenua. Ha in borsetta tre cambiali firmate da Cecè e un conto della modista da farsi pagare. Si indigna, ride, e si vendica a modo suo."}],"scenes":[{"id":"scene_1","title":"Il favore","setting":"Una stanza d''albergo di prim''ordine a Roma, mobili all''ultima moda, un telefono alla parete. Al levarsi della tela la scena è vuota: il telefono squilla una, due, tre volte. Cecè accorre in pigiama, con le guance insaponate e il pennello da barba in mano.","music":"Foxtrot da caffè-concerto anni ''10","beats":[{"type":"line","speaker":"Cecè","to":"Telefono","line":"E tre! Un momento... Cristo, sto a farmi la barba! Pronto... Chi?... Più forte, non sento... — Ah, Squatriglia? Come? No... dicevo tra me, sto a farmi la barba... Sì, fate salire.","context":"Urla nel ricevitore, metà insaponato. Attacco fulminante della commedia."},{"type":"stage_direction","action":"Cecè s''avvia per tornare in camera; a un certo punto si ferma, sospeso."},{"type":"line","speaker":"Cecè","to":"Pubblico","line":"Chi ha detto? Squatriglia? Uhm! Mi pare che sia commendatore...","context":"Tra sé: non è nemmeno sicuro di chi stia per ricevere."},{"type":"stage_direction","action":"Cecè rientra in camera. Si picchia alla porta, due volte, prima che gridi «Avanti!». Il cameriere introduce il commendator Squatriglia e si ritira."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Carissimo Cecè! Se disturbo...","context":"Espansivo, con un grosso portafogli nella giacca."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Ah, ecco, tu! Abbi pazienza: accomodati, commendatore. Vedi, sto a farmi la barba. Con te non faccio cerimonie: l''uscio è aperto, puoi parlare. Cinque minuti, ho bell''e finito.","context":"Parla dalla soglia della camera da letto, continuando a radersi."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Fa'', fa''; sto qua a guardare un certo conto... Cecè, devo andar via subito, sai? Sono venuto per salutarti e ringraziarti. Parto alle undici.","context":"Siede, esamina una carta dal portafogli, guarda l''orologio."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Così presto? Hai sbrigato tutto?","context":"Rientra finendo di vestirsi in fretta."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Eh, grazie a te! Se non era per te, figurati se avrei trovato così presto la via d''entrare a parlare con Sua Eccellenza!","context":"Gratitudine sincera e un po'' ingombrante."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Te l''ho fatta trovare io, la via? Quale Eccellenza, scusa?","context":"Sincero: non se ne ricorda affatto."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Va'' là, buffone! Ti dai le arie di confonderti, perché le conosci tutte, eh? Cos''è? T''offendi?","context":"Ride, convinto che Cecè finga per modestia."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Non m''offendo; mi fai rabbia! Perché ti giuro, caro, che io non conosco nessuno. Nes-su-no, capisci? Centomila mi chiamano Cecè — a Milano, a Torino, a Roma, a Palermo — e io vivo sparpagliato in centomila che mi conoscono e che io non conosco. Perché non siamo mica sempre gli stessi: allegri con uno, tristi con un altro, serii con questo, burloni con quello... E dentro ti domandi: «Chi sarà costui? Chi sarò io per costui?». Se mi ci fisso, parola d''onore, ammattisco.","context":"Il celebre tema pirandelliano dell''uomo ''uno e centomila'', qui condensato. Da dire con foga crescente, quasi sul serio."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Rido, perché... di'' la verità... sai chi sono io?","context":"Lo mette alla prova, divertito."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Ma sì che ti conosco! Tu hai un fratello, perdio! Filippo, ecco! Lui, l''occhio, e tu la... cioè, no: lui, la mano, e tu l''occhio, già! Una mina, eh? Ma te lo murarono bene, magnificamente: bello liscio, che non pare più niente. T''ho conosciuto a... aspetta! che ci avevi l''impresa d''un porto, o di qualche cosa di simile...","context":"Ricostruisce a tentoni, sbagliando pure quale dei due fratelli ha perso cosa."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Ma sì! A Palermo. Per una riparazione all''antemurale del porto. Prima dal Sotto-segretario, e poi dal Ministro... Era una settimana che mi mandavano da Erode a Pilato. Non so proprio come ringraziarti...","context":"Conferma tutto, felice."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Te n''affliggi? Te n''affliggi sul serio? Te ne riparti con l''afflizione di non sapere come ringraziarmi?","context":"Gli si accende un''idea negli occhi."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Ma sì, davvero... e... Cecè, se posso... senza cerimonie... Siamo tanto amici... sei un discolaccio, sempre in mezzo a tanti imbarazzi...","context":"Accenna a cavare il portafogli dalla tasca in petto."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Ohè! che scherziamo? Commendatore, per chi mi prendi? Il gesto che hai fatto, scusa, è proprio brutto. Ma non credere che mi sia offeso! Sto studiando il modo di levarti l''afflizione: ti vorrei dare in cambio un gran piacere che io non ho mai potuto provare. Quello di dire tutto il male possibile e immaginabile d''un amico — alle sue spalle, s''intende. Te lo vorresti prendere?","context":"Blocca il gesto con la mano, poi passa immediatamente al piano."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Cecè, non ho tempo! Debbo partire alle undici, e ancora non ho pronta la valigia. Purché sia spiccio, ecco, il modo...","context":"Già in trappola senza saperlo."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Spiccissimo! Invece del treno delle undici prenderai quello delle quindici. Servizio per servizio! Più ti guardo e più vedo che sei quello che ci vuole per me: età... statura... portamento... e poi tu sei l''indulgenza personificata...","context":"Lo squadra come un impresario squadra un attore."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Sfido! Con un occhio sempre chiuso...","context":"Autoironia sull''occhio murato."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Caro! Sei un uomo di spirito, per questo ti voglio bene! Dunque, senti: tu sei un amico di papà. Papà è in commercio, io sono in ditta con papà, e siamo rovinati, rovinatissimi — per causa mia. Perché io sono... di'' un po'', come ti piacerebbe meglio di dire: canaglia o farabutto?","context":"Lo bacia, poi gli detta la parte. Nota: il papà di Cecè in realtà è morto."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Canaglia! ...Ma a chi? Perché? Scherzi o dici sul serio?","context":"Ci sta prendendo gusto e insieme si spaventa."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Di'' pure canaglia. Ma anche farabutto, sai? suona bene in bocca. E biscazziere, anche... Falsario! Ti piacerebbe falsario? Ecco, ti dico subito di che si tratta. Quindici giorni fa, alla casina del Pincio, in mezzo al solito passeraio d''amici — Cecè, Cecè, Cecè — passa in automobile un tocco d''Eva di quelli che ti fanno baciar la punta delle dita. «Eh, Cecè», mi dicono, «quella lì, caro, non è per te!» Scommettiamo! Tre giorni dopo, alla stessa ora, io passavo in automobile accanto a lei, salutando graziosamente tutti quei cari amici. Ma per uscirne ho commesso una sciocchezza da cui m''ero sempre guardato: le ho fatto accettare, facendogliele cadere bene dall''alto, tre cambialette di duemila lire l''una.","context":"''Passeraio'' = stormo di passeri che cinguettano, la solita corte di amici. Il racconto della scommessa, condensato dall''originale."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Ah sì?","context":"Comincia a intravedere il guaio."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Ti pare niente? Di quelle bestie in giro io non ne voglio: ne ho sempre avuto un sacro terrore. Ti giuro che da quattro notti non ci dormo. Bisogna assolutamente che io riabbia oggi stesso quelle tre cambiali. Ho scritto ieri a Nada che me le riporti, e...","context":"Per la prima volta è sincero: le cambiali lo terrorizzano davvero."},{"type":"stage_direction","action":"Squilla il campanello del telefono. Cecè si illumina e vi si appressa.","context":"È Nada che chiama dal portiere dell''albergo."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Eccola qua. Dunque, siamo intesi. Vieni qua... Rispondi!","context":"Cerca di trascinarlo all''apparecchio."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Aspetta! Che intesi? Che debbo fare? Vuoi che paghi seimila lire?","context":"Nel panico totale."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"No! Ma che! Seimila? Neanche per ischerzo! Le rovescerai addosso tutte le ingiurie che ti verranno in bocca — canaglia, farabutto — le dirai che mio padre è all''orlo del fallimento, che quelle cambiali in mano sua non valgono nulla. Te le farai restituire, e le darai in cambio... vedi un po''... quattrocento, cinquecento lire. Non di più, sai? Non ne varrebbe la pena!","context":"Le istruzioni complete della truffa, sparate a raffica."},{"type":"line","speaker":"Squatriglia","to":"Cecè","line":"Ma nient''affatto! Non sono parti per me... Io... con una donna...","context":"Ultimo, inutile tentativo di resistenza. Il telefono squilla di nuovo."},{"type":"line","speaker":"Cecè","to":"Squatriglia","line":"Che donna e donna! Va'' là. Di'': pronto! — Addio, eh? Io scappo!","context":"Gli caccia in mano il ricevitore."},{"type":"stage_direction","action":"Cecè fugge di corsa per la porta del corridoio, col cappello in mano, lasciando Squatriglia solo davanti al telefono che squilla.","context":"Fine del primo movimento: la trappola è armata."}]},{"id":"scene_2","title":"L''uomo dall''occhio murato","setting":"La stessa stanza d''albergo, un istante dopo. Squatriglia, solo, col ricevitore del telefono in mano, suda freddo: tra poco dovrà recitare la parte più infame della sua vita davanti a una sconosciuta.","music":"Valzer lento, teso","beats":[{"type":"line","speaker":"Squatriglia","to":"Telefono","line":"Pronto... Va bene... Fate salire...","context":"Voce strozzata."},{"type":"stage_direction","action":"Appende il ricevitore sbuffando; leva le braccia, cava il fazzoletto, si asciuga la fronte e resta in penosissima attesa."},{"type":"line","speaker":"Squatriglia","to":"Pubblico","line":"Perdio... perdio... Ma questo è matto!... Preso in trappola... E come faccio adesso?... Che le dico?... Oh che storia... oh che storia... — Avanti!","context":"Borbotta tra sé; l''ultimo «Avanti!» risponde ai colpi all''uscio."},{"type":"stage_direction","action":"Il cameriere introduce Nada, elegante, con un vistoso cappello in capo, e si ritira. Squatriglia, imbarazzatissimo, s''inchina goffamente."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"Il signor Vivoli?","context":"Impacciata alla vista di quell''estraneo."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"Il signor Vivoli, signorina... il signor Vivoli, non... non c''è...","context":"Partenza disastrosa."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"Ma come? Chi ha risposto al telefono? Come si trova qua e m''invita a salire? Questa è ancora la stanza del signor Vivoli?","context":"Diffidente, pronta ad andarsene."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"Sì, del signor Vivoli. Al telefono ho risposto io, perché... scusi, lei è la... si... signorina Nada, non è vero? Abbia pazienza, le spiego... Ho sentito una voce di donna e... ho creduto che fosse la... la mamma...","context":"Improvvisa malissimo."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"La mamma? che mamma? La sua mamma? Eh, lo volevo dire: scambiare la mia voce con quella della sua mamma!","context":"Scoppia a ridere del suo comico imbarazzo."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"No! Che mia! Lasci, la prego, la mia mamma: qua non c''entra, grazie a Dio! È in paradiso da un pezzo! Dicevo la mamma di lui... Io sono un amico... del padre, che è vivo... purtroppo! cioè... sì... dico purtroppo, perché è vivo per patire... Oh, creda, signorina... dolori... dolori... Ci eravamo proposti, io e la mamma, di venire da lei!","context":"Si impantana sempre di più; il «purtroppo» gli scappa e deve rattopparlo."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"Venire da me? la mamma di Cecè? Ma che scherzo è questo? Io conosco il signor Vivoli da una ventina di giorni appena!","context":"Fra l''allarmata e la divertita."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"Per metterci nelle sue mani, signorina! Perché sappiamo che lei è stata vil... vilmente... vorrei dire di più, m''aiuti lei... spudoratamente, ecco... ingannata da quella canaglia, da quel farabutto, da quel cagliostro — no, la prego, mi lasci dire — biscazziere, donnaiuolo, falsario, ladro, assassino...","context":"Recita la lista d''insulti concordata, prendendo velocità come un treno senza freni."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"Ed è suo amico?","context":"Secca, con un sopracciglio alzato."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"Sissignora. Amicissimo. Ma della sua casa: di suo papà, che è una perla d''uomo, il più gran galantuomo che Dio abbia fatto e messo in terra! E in un momento supremo come questo, in cui la più lieve spinta... che dico? un soffio, signorina, un soffio... può mandar tutto a catafascio... determinare la più spaventosa catastrofe...","context":"Si agita, gesticola, suda."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"Oh, per carità... Lei ha un certo modo di parlare... Se si vedesse... Si agita troppo, è... Dio mio, non posso vederla così agitato... Parli più calmo!","context":"Si nasconde la faccia per non ridere."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"Mi proverò... Lei mi perdoni... M''investo della mia parte d''amico... La catastrofe, le dicevo, non solo d''una casa, ma dell''onore d''un povero vecchio assassinato dalla condotta infame del figlio... Questo figlio si espone a firmare... a mettere in giro... sì, dico... lei lo sa... sono tre, è vero? di duemila lire ciascuna, è vero?","context":"Arriva finalmente al punto: le cambiali."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"Ma che vergogne son queste? ...Ma basta! Sa che lei è buffo sul serio?","context":"Prima sobbalza indignata, poi lo squadra e non riesce a prenderlo sul serio."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"Io? Ah, me l''immagino... E creda che... sono tutto... tutto sudato, signorina!","context":"Patetico e disarmante."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"Lo credo bene! Fare una tal parte... Si rassetti, via, si asciughi, caro signore. Io me ne vado.","context":"Si avvia verso la porta."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"No, per carità, non se ne vada! M''ascolti, la scongiuro! Lei ha lì tre pezzi di carta che non valgono nulla! Che scandalo vuol provocare, se egli è vissuto sempre in mezzo allo scandalo, se è notoriamente uno svergognato, il ludibrio di tutti? Tutto quel poco che resta alla famiglia è oberato da ipoteche scoperte. Scoperte, signorina! Basta il minimo protesto d''una nuova cambiale, e il crollo è inevitabile. Ne resta schiacciato un povero vecchio, una povera donna... Lui, no! Ah, lui, no! Che importa a lui del disonore, della morte d''un povero vecchio?","context":"La grande tirata, condensata dall''originale. Qui, paradossalmente, diventa quasi bravo."},{"type":"stage_direction","action":"Si porta una mano alla tasca interna della giacca, ne trae il portafogli, lo apre titubante e ne cava un mazzetto di biglietti di banca."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"Ah, un mercato! Caro signore, lei sbaglia. Crede d''avere a buon mercato un sentimento, quale la generosità, da una donna come me? Generose, noi? Per amore, se mai! Non per uno che ci mandi una terza persona a supplicarci in nome dei parenti. Questo indigna! Io non provo in questo momento altro che schifo, e una tal rabbia che se avessi qua, invece di lei, quel mascalzone...","context":"Sdegno vero, il momento più serio della commedia."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"Lo ucciderebbe? L''ucciderei anch''io, creda, signorina!","context":"Con sincera e comicissima espressione: per un attimo dice la pura verità."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"Lei mi fa ridere... Ma ha avuto un bel coraggio, mi sembra! ...Va bene. Lei dice che le cambiali non valgono nulla?","context":"Scoppia a ridere; la rabbia si scioglie in decisione."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"Nulla: questo glielo posso proprio giurare: nulla, signorina!","context":"L''unica frase che può dire a cuor leggero: è vera."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"E allora doveva dirmi così, e nient''altro: che protestandole farei ridere le mie amiche, perché saprebbero che ho avuto la dabbenaggine d''accettarle. Non fare appello alla mia generosità! Io non posso essere generosa: io mi devo vendicare. E creda che saprò trovare il modo, e mi vendicherò ferocemente. Questo schifo che m''ha fatto provare, perdio, lo sconterà!","context":"Promessa che manterrà prima di quanto Squatriglia immagini."},{"type":"stage_direction","action":"Di scatto, risoluta, Nada apre la borsetta, ne trae le tre cambiali e gliele porge."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"Ecco a lei le cambiali. Se ne vada! Se ne vada via subito! ...E non mi ringrazi!","context":"Gli tronca il «grazie» in gola."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"No... ma... mi permetta... mi conceda... Mi lasci fare... per favore... non so se faccio bene o male...","context":"Timido, con le dita tremolanti, depone alcuni biglietti di banca sul tavolino, sotto il calamaio."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"Non voglio, le dico! Si riprenda quel denaro! ...Quanto ha messo lì?","context":"Il «non voglio» e la curiosità sulla cifra a mezzo secondo di distanza."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"Mille e cinque... cinquecento lire, signorina, ma... se... se è poco...","context":"Ben oltre le cinquecento massime ordinate da Cecè."},{"type":"stage_direction","action":"Contrariata, Nada cava dalla borsetta una busta aperta e gliela porge: è un conto della modista. Col dito gli indica il cappello che ha in capo."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"«Cappello a cupola piana, con grande Paradis bianco naturale: lire milleseicentocinquanta.» ...Ah... sì... subito... Volentieri...","context":"Legge il conto senza capire, poi capisce: aggiunge sotto il calamaio un biglietto da cento e uno da cinquanta."},{"type":"line","speaker":"Nada","to":"Squatriglia","line":"Basta, la prego!","context":"Gelida, mentre lui ricomincia coi ringraziamenti."},{"type":"line","speaker":"Squatriglia","to":"Nada","line":"Ha ragione. Scappo, corro a dar l''annunzio del suo atto generoso... no, no... non aggiungo altro... Permette? La ossequio.","context":"Le porge la mano, gliela stringe, s''inchina, e via per la porta in fondo."},{"type":"stage_direction","action":"Nada, rimasta sola, fa atti di nausea e di rabbia; passeggia infuriata per la stanza."},{"type":"line","speaker":"Nada","to":"Pubblico","line":"Ah, me la pagherà... me la pagherà... Vigliacco!... Vigliacco! Vigliacco!... Aspetta...","context":"Conta i biglietti con ira e sprezzo, li caccia nella borsetta; poi si morde un dito, gli occhi sfavillanti, siede al tavolino e si mette a scrivere una lettera."}]},{"id":"scene_3","title":"Il compenso","setting":"La stessa stanza. Nada, di spalle alla porta, sta scrivendo la sua lettera di vendetta. La porta si apre silenziosamente: Cecè v''entra col cappello a sghembo, in punta di piedi, e le si avvicina alle spalle.","music":"Ripresa del foxtrot, più maliziosa","beats":[{"type":"stage_direction","action":"Cecè richiude la porta senza far rumore, si appressa a Nada e l''abbraccia per di dietro.","context":"Non sa ancora che qui bisogna recitare il capolavoro."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Naduccia mia bella!","context":"Tutto miele."},{"type":"line","speaker":"Nada","to":"Cecè","line":"Ah? Tu? Con che faccia osi presentarti a me?","context":"Si divincola, furibonda."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Che cos''è? Perdonami: t''ho fatto aspettar troppo? Non credevo di far così tardi. Via, eccomi qua...","context":"Le presenta la faccia sorridente — errore fatale."},{"type":"stage_direction","action":"Nada gli appioppa uno schiaffo sonoro."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Oh Dio... troppo forte... M''hai fatto male... perché?","context":"Genuinamente sorpreso dalla potenza dello schiaffo."},{"type":"line","speaker":"Nada","to":"Cecè","line":"Perché? Hai il coraggio di domandarmi il perché? Sei stato con la mamma? Con la tua mamma, che doveva venire a pregarmi, a scongiurarmi d''aver pietà?","context":"Gli rovescia addosso la messinscena di Squatriglia."},{"type":"line","speaker":"Cecè","to":"Nada","line":"La mia mamma? Che dici? Sei matta? Che mamma, scusa? dov''è la mamma? che c''entra la mia mamma?","context":"Da qui in poi recita l''innocenza con impegno totale."},{"type":"line","speaker":"Nada","to":"Cecè","line":"Imbroglione! Il fallimento! la rovina! il disonore! tutto a catafascio per le tue nequizie! Un povero padre a cui hai inzaccherato la canizie veneranda! Una povera madre... imbroglione! gaglioffo! Come non ti vergogni?","context":"Ripete a memoria le enormità sentite un quarto d''ora prima."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Ma tu farnetichi, mia cara! Io non ho papà, io non ho mamma; che dici? Hai sognato! Ti prego di spiegarmi: io non capisco nulla. Ti vedo infuriata... credevo che fosse per il mio ritardo...","context":"Serio, con freddezza grave. Qui, tra l''altro, dice il vero."},{"type":"line","speaker":"Nada","to":"Cecè","line":"È possibile una faccia così a prova di bomba? Ma come? quell''uomo dall''occhio murato, che ho trovato qua, al tuo posto? Amico di tuo papà!","context":"Gli va incontro con le mani tese, esasperata."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Un uomo dall''occhio murato? L''hai trovato qua? E come? E chi l''aveva fatto salire?","context":"Simula prima sgomento, poi ansia e costernazione."},{"type":"line","speaker":"Nada","to":"Cecè","line":"Che ne so io? Ho telefonato; m''hanno invitata a salire. Credevo di trovar te; ho trovato lui. Aspettava tua madre, per venire da me a pregarmi...","context":"Comincia a vacillare: e se davvero non c''entrasse?"},{"type":"line","speaker":"Cecè","to":"Nada","line":"Mia madre? E tu ci hai creduto? A pregarti di che?","context":"Incalza."},{"type":"line","speaker":"Nada","to":"Cecè","line":"Ti dico di no! ...Di restituire le tre cambiali.","context":"Eccoci al punto."},{"type":"line","speaker":"Cecè","to":"Nada","line":"E tu? Tu gliele hai date?","context":"Con ansia aggressiva: il momento della verità (della sua verità)."},{"type":"line","speaker":"Nada","to":"Cecè","line":"S''è messo a parlarmi della rovina della tua casa... che tuo padre era all''orlo del fallimento... che bastava un soffio a mandar giù un accordo coi creditori... M''ha detto, dimostrato, che non valevano nulla, che non avrei potuto cavarne alcun vantaggio...","context":"Si giustifica, smarrita."},{"type":"line","speaker":"Cecè","to":"Nada","line":"E gliel''hai date? Disgraziata! Mi hai rovinato, mi hai rovinato, mi hai rovinato! Sai chi è costui? Il più feroce strozzino ch''esista sulla faccia della terra! Una sanguisuga! Un vampiro!","context":"Esplode: la controtruffa comincia."},{"type":"line","speaker":"Nada","to":"Cecè","line":"Quello lì? ...Ma io ho creduto che l''avessi mandato tu, per riavere le cambiali!","context":"Ha indovinato tutto — e sta per farsi convincere del contrario."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Io? Ma come? Se t''avevo scritto io stesso di riportarmele qua! Te le volevo cambiare... ritirarle... darti il danaro... Come ti sei arrischiata a dargliele? Ma perché sa fare lo scemo a meraviglia, sfido! Non c''è parte che non sappia fare: l''asino e il porco, la serpe e la iena, la tigre e il coniglio! Da anni mi dava la caccia, perché gli ho strappato dalle grinfie più d''una preda. E sono in bianco, capisci? senza scadenza fissa: mi terrà sotto la minaccia, m''imporrà gl''interessi a suo piacere e mi succhierà il sangue, come ha fatto a tanti altri. Il cento per cento, mi farà pagare, su quelle seimila lire! Ma dimmi: tu gliele hai date così... per niente?","context":"Il ritratto dello ''strozzino'', condensato dall''originale: ogni parola è un''infamia inventata sul povero Squatriglia."},{"type":"line","speaker":"Nada","to":"Cecè","line":"No... m''ha date alcune centinaia di lire... mille... milleseicento... seicentocinquanta.","context":"La cifra esce a rate, con crescente imbarazzo."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Strozzino! Milleseicentocinquanta per seimila, su cui mi farà il cento per cento!","context":"Fa i conti dell''usura immaginaria — intascando mentalmente la differenza."},{"type":"line","speaker":"Nada","to":"Cecè","line":"E me ne voleva dare anche meno! Appena gli ho fatto vedere la nota del cappello...","context":"Si tradisce con candore."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Quale cappello? Codesto? Ma scusa, se codesto te l''ho pagato io? Ho capito: vuol dire che lo pagherò due volte io, codesto cappello. Le aggiungerà agli interessi.","context":"Indignazione da ragioniere."},{"type":"line","speaker":"Nada","to":"Cecè","line":"No, no, senti, Cecè, almeno queste... Te ne prego! Fammi questo piacere...","context":"Prova a offrirgli i soldi appena incassati."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Ma va''! Che ti passa per il capo? Sta'' zitta! Mi dispiace anche per te, ma ti sta bene, sai? Hai potuto credere a tutte le infamie che colui t''avrà dette di me! Che t''ha detto? Che t''ha detto?","context":"Rifiuta i soldi con sdegno: gli servono lì dove sono, in mano a lei."},{"type":"line","speaker":"Nada","to":"Cecè","line":"Caro mio... Povero Cecè... vieni qua... Ti compenserò io, Cecè...","context":"Completamente riconquistata, tenera."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Ah, cara mia, lo credo bene! Mi compenserai alla stregua dell''usura che mi farà quello lì! Ma è pure la rabbia, capisci? la rabbia d''esser caduto in quelle mani!","context":"Accorre e l''abbraccia: la vittima che si lascia consolare."},{"type":"line","speaker":"Nada","to":"Cecè","line":"Anche di più! E ti farò passare anche la rabbia, sta'' zitto... Siedi qua.","context":"Lo fa sedere e gli si siede sulle ginocchia."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Comincia il compenso? Subito un bacio qua! ...Di'' un po'', me ne ha dette molte, quell''infame? Per ognuna, un bacio! E dove voglio io... Cominciamo: che t''ha detto?","context":"Indica la fronte. Trasforma gli insulti che lui stesso ha commissionato in tariffa di baci."},{"type":"line","speaker":"Nada","to":"Cecè","line":"Tante... tante... Canaglia!","context":"Ci sta al gioco."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Subito un bacio qua! Su, avanti, che altro t''ha detto?","context":"Indica la guancia destra; Nada ride e lo bacia."},{"type":"line","speaker":"Nada","to":"Cecè","line":"Aspetta... aborto... di natura...","context":"Se lo gusta sillaba per sillaba."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Aborto di natura?! Vieni qua... vieni qua...","context":"Balza in piedi fingendosi oltraggiato; Nada gli scappa ridendo per la stanza."},{"type":"line","speaker":"Nada","to":"Cecè","line":"Lasciami levare il cappello... Eccomi.","context":"Il famoso cappello da milleseicentocinquanta lire."},{"type":"line","speaker":"Cecè","to":"Nada","line":"Milleseicentocinquanta! E il resto! Dunque, aborto di natura? Eh... questa volta qua, qua, cara mia...","context":"Risiede, con Nada sulle ginocchia, e indica con un dito la bocca."},{"type":"stage_direction","action":"Nada si china per baciarlo in bocca — e a questo punto, come scrive Pirandello, «sarà meglio che cali la tela».","context":"Didascalia finale originale dell''autore."}]}]}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('Il processo a Galileo', 'lettura', 'it', NULL, 3, 4, '{"description":"Roma, 1623-1633. Maffeo Barberini, amico e ammiratore di Galileo, diventa papa Urbano VIII: dieci anni dopo, lo stesso papa lo consegna all''Inquisizione per il ''Dialogo sopra i due massimi sistemi''. Interrogatori, la minaccia della tortura, e la più famosa abiura della storia. Adattamento dai documenti del processo (verbali degli interrogatori, sentenza e abiura del giugno 1633, editi in ''Le Opere di Galileo'' a cura di A. Favaro, vol. XIX), dai dispacci dell''ambasciatore Francesco Niccolini e dalle lettere del commissario Vincenzo Maculano.","characters":[{"name":"Galileo Galilei","description":"Il matematico più famoso d''Europa. Quasi settant''anni al processo: geniale, vanitoso, sarcastico, convinto fino all''ultimo di potersela cavare con l''ingegno — e poi, davanti ai giudici, un vecchio solo."},{"name":"Urbano VIII","description":"Maffeo Barberini, fiorentino, poeta, per vent''anni amico e ammiratore di Galileo. Da papa: orgoglioso, permaloso, assediato dalla politica. L''amicizia tradita lo rende più feroce di qualunque nemico."},{"name":"Vincenzo Maculano","description":"Frate domenicano, commissario generale del Sant''Uffizio. Prima di farsi inquisitore progettava fortezze: uomo pratico, senza fanatismo, che cerca l''uscita meno rovinosa per tutti — tribunale compreso."}],"scenes":[{"id":"scene_1","title":"L''amico papa","setting":"Roma, 1623-1624. Galileo ha puntato il cannocchiale al cielo e il cielo non è più quello di prima: montagne sulla Luna, lune intorno a Giove, macchie sul Sole. Ma nel 1616 il Sant''Uffizio ha dichiarato la teoria di Copernico — il Sole fermo al centro, la Terra che gira — contraria alle Scritture, e Galileo è stato ammonito dal cardinale Bellarmino a lasciarla stare. Poi, nell''agosto del 1623, il miracolo: sul trono di Pietro sale il cardinale Maffeo Barberini, da vent''anni amico e ammiratore di Galileo. Il matematico, sessantenne e celebre in tutta Europa, viene a Roma a rendergli omaggio.","beats":[{"type":"line","speaker":"Galileo Galilei","to":"Pubblico","line":"Maffeo Barberini, papa! L''uomo che mi scrisse versi in latino per le mie scoperte, che a tavola mi difese contro mezzo collegio cardinalizio! Gli ho appena dedicato il mio ''Saggiatore'', e dicono che se lo faccia leggere a cena, ridendo. Amici miei, si alza il vento buono: questa volta il cielo si può dire ad alta voce.","context":"Tutto documentato: nel 1620 Barberini dedicò a Galileo il poema latino ''Adulatio perniciosa''; il ''Saggiatore'' (1623) fu dedicato al nuovo papa, che se lo faceva leggere a mensa."},{"type":"line","speaker":"Urbano VIII","to":"Galileo Galilei","line":"Signor Galilei! Venite, venite: un papa può abbracciare un matematico, se il matematico è il primo del mondo. Vi ho scritto dei versi, una volta — ''serba il tuo vetro, o Galileo, le glorie degli astri'' — e non ero ancora papa, dunque erano sinceri. Ditemi cosa posso fare per voi.","context":"Nella primavera del 1624 Urbano VIII ricevette Galileo in sei lunghe udienze, colmandolo di doni e di una pensione per il figlio Vincenzo."},{"type":"line","speaker":"Galileo Galilei","to":"Urbano VIII","line":"Santità, una cosa sola: liberarmi da un silenzio. Dal sedici mi è vietato tenere l''opinione di Copernico. Ma vietarla non la confuta: i moti del cielo, le maree, le macchie del Sole — tutto grida che è la Terra a muoversi. Lasciate almeno che io metta le due opinioni a confronto, con le ragioni dell''una e dell''altra.","context":"Galileo andò a Roma nel 1624 proprio per sondare la possibilità di riaprire la questione copernicana."},{"type":"line","speaker":"Urbano VIII","to":"Galileo Galilei","line":"Confrontatele pure, da matematico: per ipotesi, non per verità. E ricordate il mio argomento, Galileo: Dio è onnipotente. Poteva fabbricare il mondo in mille modi che la vostra mente non arriva nemmeno a sognare. Chi pretende di chiudere la Sua sapienza dentro una sola dimostrazione, la limita — e questo, amico mio, nessun cristiano lo può scrivere.","context":"L''argomento dell''onnipotenza divina è storicamente di Urbano VIII, che pretese fosse incluso nel futuro ''Dialogo''. Dove Galileo lo mise finirà per costargli caro."},{"type":"line","speaker":"Galileo Galilei","to":"Urbano VIII","line":"Il vostro argomento avrà il posto d''onore, Santità: parola. Scriverò un dialogo tra tre gentiluomini — uno per Copernico, uno per Aristotele e Tolomeo, uno di buon senso nel mezzo — e nessuno vincerà. Sulla carta.","context":"Le ultime due parole vanno quasi mangiate: è la riserva mentale che genererà il disastro."},{"type":"stage_direction","action":"Urbano benedice Galileo e lo congeda con doni. Galileo torna a Firenze e per anni, tra malattie e revisioni, scrive il suo libro. Negli archivi del Sant''Uffizio, intanto, dorme una carta di cui nessuno parla: un verbale del febbraio 1616, senza firma né notaio, secondo cui a Galileo sarebbe stato intimato di non tenere, insegnare o difendere quell''opinione ''in qualsivoglia modo, in voce o in scritto''.","context":"Il ''Dialogo sopra i due massimi sistemi del mondo'' fu scritto tra il 1624 e il 1630. Il precetto del 26 febbraio 1616 (attribuito al commissario Segizzi) è privo di firme e la sua regolarità è discussa dagli storici ancora oggi: sarà il perno dell''accusa nel 1633."},{"type":"line","speaker":"Galileo Galilei","to":"Pubblico","line":"Il cardinale Bellarmino, buonanima, mi diede una dichiarazione di suo pugno: che io non ho mai abiurato né fatto penitenza, e che mi fu solo notificato che la dottrina di Copernico ''non si può difendere né tenere''. Difendere né tenere: di insegnare, di discutere, di scrivere per ipotesi — nemmeno una parola. La conservo come una reliquia. Non si sa mai.","context":"Il certificato di Bellarmino, 26 maggio 1616, è autentico: Galileo lo esibirà al processo. La frase citata viene dal documento."},{"type":"line","speaker":"Urbano VIII","to":"Pubblico","line":"Gli voglio bene, al signor Galilei. Ma il papa non è un uomo: è una fortezza. Ho la guerra in Germania, gli spagnoli che mi accusano di tiepidezza, mezzo Sacro Collegio che aspetta un mio passo falso. L''amicizia è un lusso da cardinali. Speriamo che il matematico scriva con prudenza.","context":"Ponte inventato ma fedele al contesto: nel 1632 Urbano era politicamente assediato, e la crisi con la Spagna lo rendeva vulnerabile all''accusa di indulgenza verso gli eretici."},{"type":"stage_direction","action":"Febbraio 1632: il ''Dialogo sopra i due massimi sistemi del mondo'' esce a Firenze, con regolare imprimatur strappato ai revisori. Tre personaggi: Salviati, copernicano, che vince ogni scontro; Sagredo, arbitro, che gli dà sempre ragione; e il difensore della vecchia scienza, quello che perde ogni disputa, che Galileo ha scelto di chiamare... Simplicio.","context":"L''imprimatur fu concesso dal padre Niccolò Riccardi dopo lunghe trattative. ''Simplicio'' richiama il filosofo antico Simplicio, ma in toscano suona come ''sempliciotto''."},{"type":"line","speaker":"Galileo Galilei","to":"Pubblico","line":"E l''argomento del papa? Mantengo la parola: posto d''onore, ultima pagina, conclusione del libro. L''ho messo in bocca a Simplicio. Chi mai potrà offendersene?","context":"Storico: l''argomento dell''onnipotenza divina caro a Urbano VIII chiude il ''Dialogo'' pronunciato proprio da Simplicio, il personaggio che esce sconfitto da tutto il libro."}]},{"id":"scene_2","title":"L''ira del papa","setting":"Roma, estate-autunno 1632. Il ''Dialogo'' circola da mesi e piace troppo. Qualcuno si è preso la briga di far notare a Sua Santità in bocca a chi sia finito il suo argomento: il papa ha letto il libro, e nei palazzi vaticani il vento è cambiato. L''estate del 1632 è molto calda.","beats":[{"type":"line","speaker":"Urbano VIII","to":"Pubblico","line":"Il mio argomento. Il MIO argomento, quello che gli affidai come un pegno, messo in bocca al personaggio che tutto il libro deride! Simplicio! E i miei nemici, nelle anticamere, già sussurrano che Simplicio sarei io. Mi ha raggirato: ha strappato l''imprimatur con l''inganno e ha stampato ciò che gli era proibito perfino di tenere nella testa.","context":"Il sospetto di Urbano che Simplicio lo caricaturasse è riferito dalle fonti; l''accusa di ''raggiro'' sull''imprimatur è nei dispacci dell''ambasciatore Niccolini."},{"type":"stage_direction","action":"La macchina si mette in moto: a luglio l''ordine di bloccare la vendita del libro, ad agosto una commissione speciale, a settembre il fascicolo passa al Sant''Uffizio. L''ambasciatore di Toscana, Francesco Niccolini, corre dal papa a difendere il matematico del Granduca. Il colloquio finisce male — e lo conosciamo parola per parola, perché Niccolini lo mise per iscritto quella sera stessa.","context":"Dispaccio di Niccolini al segretario granducale Cioli, 5 settembre 1632: una delle scene meglio documentate di tutta la vicenda."},{"type":"line","speaker":"Urbano VIII","to":"Pubblico","line":"Il vostro Galileo ha ardito entrare dove non doveva, e in materie le più gravi e le più pericolose che a questi tempi si potessero suscitare! Lo dite al vostro Granduca: in queste cose del Sant''Uffizio non si viene a trattare, si viene a ubbidire!","context":"La prima frase è la citazione testuale riportata da Niccolini (dispaccio del 5 settembre 1632). Da urlare a un ambasciatore immaginario, davanti a sé."},{"type":"line","speaker":"Vincenzo Maculano","to":"Pubblico","line":"Fra Vincenzo Maculano da Firenzuola, domenicano, commissario generale del Sant''Uffizio. Prima di processare uomini progettavo bastioni, e le fortezze mi hanno insegnato una cosa: ogni assedio costa a chi lo fa quanto a chi lo subisce. Ora sul mio tavolo c''è il fascicolo dell''uomo più famoso d''Europa. Che il cielo mi assista.","context":"Maculano era davvero un apprezzato ingegnere militare. Presentazione al pubblico: tono pratico, per niente da fanatico."},{"type":"line","speaker":"Urbano VIII","to":"Vincenzo Maculano","line":"Padre commissario, il caso è vostro. Negli atti del sedici c''è un precetto: non tenere, non insegnare, non difendere in qualsivoglia modo. Il libro sta lì a dimostrare che l''ha calpestato. Lo si citi a Roma, davanti al tribunale. E non mi si parli di riguardi: qui non si tratta di matematica, si tratta di chi comanda sulle Scritture.","context":"La congregazione del 23 settembre 1632 decise formalmente la citazione di Galileo a Roma."},{"type":"stage_direction","action":"L''ordine di comparire arriva a Firenze il primo ottobre. Galileo ha sessantotto anni, è malato, e in Toscana infuria la peste: chiede tempo, manda certificati medici con sette firme. Da Roma la risposta è di quelle che non si dimenticano: o viene, o lo si porta legato.","context":"Storico: davanti ai rinvii, nel dicembre 1632 il Sant''Uffizio minacciò di mandarlo a prendere e condurlo in catene (''vinctum'')."},{"type":"line","speaker":"Galileo Galilei","to":"Pubblico","line":"Legato. A me. Ho dedicato il libro ai revisori del papa, ho l''imprimatur stampato in prima pagina, e mi si minaccia la corda come un contrabbandiere. Vecchio, mezzo cieco, d''inverno, tre settimane di viaggio e la quarantena della peste a Ponte a Centino. Va bene. Andrò a Roma. Ho ancora la mia reliquia, e ho ancora la mia testa.","context":"Galileo partì il 20 gennaio 1633 e giunse a Roma il 13 febbraio, dopo la quarantena al confine. La ''reliquia'' è il certificato di Bellarmino."},{"type":"line","speaker":"Vincenzo Maculano","to":"Pubblico","line":"Ho studiato il fascicolo. La nostra arma è quel precetto del sedici: ''in qualsivoglia modo, in voce o in scritto''. Senza firma, senza notaio — un giurista di provincia ci ballerebbe sopra. Ma in questo tribunale il giudice e l''accusatore siedono sulla stessa sedia, e la sedia la paga il papa. Non sarà il diritto, il problema del signor Galilei.","context":"Le irregolarità del precetto del 1616 sono reali e discusse dagli storici; l''osservazione sul tribunale è il punto di vista moderno messo in bocca al più lucido dei personaggi."},{"type":"line","speaker":"Galileo Galilei","to":"Pubblico","line":"Roma, tredici febbraio 1633. Non cella: l''ambasciata di Toscana, Villa Medici, il cuoco del Granduca. Persino quando mi trasferiscono al Sant''Uffizio mi danno le stanze del procuratore, con il mio servitore. Mai visto un imputato trattato così, dicono tutti. Forse perché mai visto un imputato così: metà prigioniero, metà monumento.","context":"Tutto documentato: l''alloggio a Villa Medici e poi, durante il processo, nell''appartamento del fiscale del Sant''Uffizio — un privilegio senza precedenti per un inquisito."},{"type":"stage_direction","action":"Due mesi di attesa, di istruttoria, di pareri. Poi, il dodici aprile 1633, il monumento viene condotto al palazzo del Sant''Uffizio, davanti al commissario Maculano. Da qui in avanti, quasi ogni parola sta scritta nei verbali.","context":"I verbali dei quattro costituti (12 e 30 aprile, 10 maggio, 21 giugno 1633) sono editi in Favaro, ''Opere di Galileo'', vol. XIX."}]},{"id":"scene_3","title":"Gli interrogatori","setting":"Palazzo del Sant''Uffizio, Roma, aprile-giugno 1633. Una sala spoglia: un tavolo, un notaio che verbalizza, il commissario Maculano di fronte a Galileo. Primo costituto, dodici aprile: il commissario gira intorno alla preda con le buone maniere del mestiere, e arriva subito all''anno decisivo, il 1616.","beats":[{"type":"line","speaker":"Vincenzo Maculano","to":"Galileo Galilei","line":"Signor Galilei, nel febbraio del 1616 vi fu notificata una determinazione del Sant''Uffizio intorno all''opinione del Copernico. Diteci, in coscienza: che cosa vi fu comandato allora, e da chi?","context":"Fedele all''andamento del primo costituto (verbale: domande in latino, risposte di Galileo in italiano): tutto il processo ruota su cosa fu davvero intimato a Galileo nel 1616."},{"type":"line","speaker":"Galileo Galilei","to":"Vincenzo Maculano","line":"Il signor cardinale Bellarmino mi disse che l''opinione del Copernico, presa assolutamente, non si poteva difendere né tenere. E poiché prevedevo che un giorno qualcuno avrebbe raccontato altro, mi feci dare da lui una fede scritta di sua mano. Eccola, padre: la porto con me da diciassette anni. Vi leggerete ''difendere né tenere'' — e nient''altro.","context":"Storico: al primo costituto Galileo produsse a sorpresa il certificato originale di Bellarmino del 26 maggio 1616, spiazzando l''accusa."},{"type":"line","speaker":"Vincenzo Maculano","to":"Galileo Galilei","line":"La fede è autentica, non si discute. Ma negli atti nostri, di quello stesso febbraio, sta scritto che vi fu fatto precetto di non tenerla, non insegnarla, non difenderla ''in qualsivoglia modo, in voce o in scritto''. Qualsivoglia modo, signor Galilei. Ve lo ricordate, questo precetto?","context":"La formula ''quovis modo... verbo aut scriptis'' è quella del contestato verbale del 26 febbraio 1616."},{"type":"line","speaker":"Galileo Galilei","to":"Vincenzo Maculano","line":"Non mi sovviene di quelle parole, ''insegnare'' e ''in qualsivoglia modo'': saranno passati diciassette anni, e nella fede del cardinale non ci sono. E del resto, padre, avete letto il mio Dialogo? Io in quel libro non difendo il Copernico: mostro che le sue ragioni sono deboli e non concludenti. L''ho scritto per confutarlo.","context":"Risposta storica e famosa: nel primo costituto Galileo sostenne davvero che il ''Dialogo'' confutava Copernico. Nessuno che avesse letto il libro poteva crederci — e lo sapevano tutti nella stanza."},{"type":"line","speaker":"Vincenzo Maculano","to":"Pubblico","line":"Confutarlo. Il tribunale ha fatto leggere il libro a tre consultori, e tutti e tre hanno scritto la stessa cosa: il Dialogo insegna, difende e tiene il moto della Terra. La difesa del signor Galilei non è debole: è un insulto all''intelligenza dei giudici. Così scrivo alle Eminenze: ''Ho proposto un mezzo: che il tribunale mi conceda di trattare extragiudizialmente con il Galilei, per renderlo capace del suo errore e condurlo, riconosciutolo, a confessarlo.'' Fuori dal verbale, da uomo a uomo. Se confessa un errore, il tribunale salva la sua autorità, il papa la sua faccia, e il vecchio la sua vita. Le fortezze migliori sono quelle che si arrendono prima dell''assalto.","context":"I pareri dei tre consultori (tra cui Melchior Inchofer) sono agli atti. Le frasi tra virgolette parafrasano da vicino la lettera autentica di Maculano al cardinale Francesco Barberini, 28 aprile 1633, in cui propone di ''trattare seco extragiudizialmente''."},{"type":"stage_direction","action":"Sera del 27 aprile. Maculano entra senza notaio nelle stanze dove Galileo è custodito. Due sedie, una candela, nessun verbale.","context":"Il colloquio privato avvenne davvero: lo conosciamo solo dalla lettera di Maculano, perché — di proposito — non fu verbalizzato."},{"type":"line","speaker":"Vincenzo Maculano","to":"Galileo Galilei","line":"Niente notaio, signor Galilei: stasera parlo da frate, non da giudice. La vostra difesa non regge e voi lo sapete: tre consultori contro, e i giudici hanno letto il libro. Se vi ostinate, il processo va alle strette, e alle strette questo tribunale ha strumenti che non augurate a nessuno. Rileggete il vostro Dialogo. Trovateci un errore. Ve lo chiedo da uomo che vorrebbe rivedervi a Firenze.","context":"Il contenuto della persuasione è ricostruito; l''esito — Galileo che accetta di confessare — è documentato nella lettera del 28 aprile."},{"type":"line","speaker":"Galileo Galilei","to":"Vincenzo Maculano","line":"Un errore. Mi chiedete di trovare un errore nel libro più vero che io abbia scritto... Padre, ho quasi settant''anni, ho la pietra ai reni e le notti qui non finiscono mai. Datemi qualche giorno: rileggerò il mio libro come fosse d''un altro autore. Forse quell''altro autore, da qualche parte, ha esagerato.","context":"''Quasi come scrittura nuova e di altro autore'' è l''immagine che Galileo stesso userà nel verbale del 30 aprile."},{"type":"stage_direction","action":"Trenta aprile, secondo costituto: Galileo chiede spontaneamente di essere ascoltato. Quello che detta a verbale è la resa concordata tre giorni prima — e fa male ancora oggi, a leggerla.","context":"Il secondo costituto si aprì proprio con la comparizione ''spontanea'' di Galileo."},{"type":"line","speaker":"Galileo Galilei","to":"Vincenzo Maculano","line":"Ho riletto il mio Dialogo, che da tre anni non rivedevo, e mi è parso quasi scrittura nuova e di altro autore. Confesso che in più luoghi le ragioni della parte falsa sono formulate con tale forza che paiono atte a convincere, più che facili a essere sciolte. Fu compiacenza del mostrarmi più arguto del comune degli uomini. Il mio errore dunque è stato, e lo confesso, di una vana ambizione e di una pura ignoranza e inavvertenza. E se mi si concede, sono pronto ad aggiungere al Dialogo una o due giornate per confutare quegli argomenti con la maggior efficacia che potrò.","context":"Montaggio quasi letterale del verbale del 30 aprile 1633, compresa la frase finale sulla ''vana ambizione'' e l''offerta (mai accolta) di aggiungere giornate al Dialogo."},{"type":"line","speaker":"Vincenzo Maculano","to":"Pubblico","line":"Fatta. La confessione è a verbale, il decoro del tribunale è salvo, e la causa si può chiudere con una penitenza e il libro all''Indice: il vecchio torna a Firenze per l''estate. Così scrivo alle Eminenze, e così sarebbe andata... se questo processo appartenesse al tribunale. Ma appartiene a un uomo solo, e quell''uomo si sente tradito.","context":"Nella lettera del 28 aprile Maculano prospettava davvero una rapida chiusura (''si potrà spedire speditamente la causa''). La decisione finale spettava però al papa."},{"type":"line","speaker":"Urbano VIII","to":"Vincenzo Maculano","line":"Una penitenza e a casa? No, padre commissario. Costui ha ingannato me, i revisori e la Chiesa intera: la sua ''vana ambizione'' non basta a pagare il conto. Sia interrogato sopra l''intenzione, anche con la minaccia della tortura. Poi abiuri pubblicamente, davanti alla congregazione piena. Il libro sia proibito, lui tenuto in carcere a nostro arbitrio, e la sentenza mandata a tutti i nunzi e gli inquisitori d''Italia, che la leggano ai loro matematici. Che serva da esempio.","context":"È, punto per punto, la decisione della congregazione del 16 giugno 1633 presieduta da Urbano VIII: esame sull''intenzione ''etiam comminata ei tortura'', abiura de vehementi, carcere ad arbitrio, divieto del ''Dialogo'', sentenza da circolare pubblicamente."},{"type":"stage_direction","action":"Ventuno giugno 1633, ultimo interrogatorio. La formula prevede che all''imputato si chieda la verità ''sotto minaccia di tortura''. Nessuno, con ogni probabilità, intende applicarla a un settantenne protetto dal Granduca di Toscana: ma lui, seduto su quella sedia, non può saperlo.","context":"Gli storici concordano che l''esame rigoroso fosse una minaccia formale (''territio verbalis''); i regolamenti stessi sconsigliavano la tortura dei vecchi. Galileo però non aveva modo di esserne certo."},{"type":"line","speaker":"Vincenzo Maculano","to":"Galileo Galilei","line":"Galileo Galilei: avete voi tenuto, o tenete, che il Sole sia centro del mondo e la Terra si muova? Vi si ammonisce a dire la verità: altrimenti si verrà contro di voi alla tortura.","context":"Dal verbale del 21 giugno: la domanda sull''intenzione fu posta tre volte, e chiusa con la formula di rito ''alias devenietur ad torturam''."},{"type":"line","speaker":"Galileo Galilei","to":"Vincenzo Maculano","line":"Io son qua per far l''obbedienza. Non tengo né ho tenuto questa opinione del Copernico, dopo che mi fu intimato con precetto che io la dovessi lasciare. Del resto, son qua nelle loro mani: faccino quello che gli piace.","context":"Citazione pressoché testuale dal verbale del 21 giugno 1633. Un uomo che ha capito che la verità non è più tra le cose in discussione."},{"type":"stage_direction","action":"Verbalizzato che nulla più si poteva cavare, Galileo viene rimandato al suo luogo. L''indomani mattina lo vestono con l''abito bianco dei penitenti e lo conducono al convento di Santa Maria sopra Minerva.","context":"Dal verbale: ''Et cum nihil aliud posset haberi... remissus fuit ad locum suum''."}]},{"id":"scene_4","title":"La Minerva","setting":"Roma, 22 giugno 1633. La sala capitolare del convento di Santa Maria sopra Minerva. I cardinali della congregazione seduti in fila; Galileo in ginocchio, in abito da penitente, davanti a loro. La sentenza porta dieci nomi di cardinali, ma le firme sono sette: tre — e tra loro Francesco Barberini, il nipote del papa — non firmarono. Un dettaglio che dice molto, e che non cambierà niente.","music":"Un miserere in canto piano, lontano","beats":[{"type":"line","speaker":"Vincenzo Maculano","to":"Galileo Galilei","line":"Diciamo, pronunciamo, sentenziamo e dichiariamo che tu, Galileo, ti sei reso a questo Santo Offizio veementemente sospetto d''eresia: cioè d''aver tenuto e creduto dottrina falsa e contraria alle Sacre e divine Scritture — che il Sole sia centro del mondo e non si muova, e che la Terra si muova e non sia centro del mondo. Si proibisce il libro dei Dialoghi. Ti condanniamo al carcere formale ad arbitrio nostro; e per penitenza, dirai per tre anni, una volta la settimana, i sette salmi penitenziali.","context":"Condensato fedele del dispositivo della sentenza del 22 giugno 1633, con le formule originali (''veementemente sospetto d''eresia'', ''carcere formale ad arbitrio nostro'', i salmi settimanali). La sentenza fu letta al condannato in ginocchio."},{"type":"line","speaker":"Galileo Galilei","to":"Vincenzo Maculano","line":"Io, Galileo, figlio del fu Vincenzo Galilei di Fiorenza, dell''età mia d''anni settanta, inginocchiato avanti di voi, avendo davanti agli occhi i sacrosanti Vangeli che tocco con le proprie mani... con cuor sincero e fede non finta abiuro, maledico e detesto i suddetti errori ed eresie. E giuro che per l''avvenire non dirò mai più, né asserirò, in voce o in scritto, cose tali per le quali si possa avere di me simile sospetto.","context":"Testo autentico dell''abiura (22 giugno 1633), condensato. Da leggere lentamente, a fatica: ogni parola costa."},{"type":"stage_direction","action":"Galileo firma l''abiura. Silenzio lungo. I cardinali escono; lui resta in ginocchio, solo, con la penna ancora in mano.","context":"L''originale firmato (''Io Galileo Galilei ho abiurato come di sopra, di mano propria'') è conservato negli archivi vaticani."},{"type":"line","speaker":"Galileo Galilei","to":"Pubblico","line":"Dicono che mi sia rialzato mormorando: ''Eppur si muove''. Non è vero: nessun testimone la udì, e la frase comparirà in stampa solo centoventiquattro anni dopo, a Londra. Ma vi dico io che cosa ho pensato, rialzandomi: che domattina la Terra farà quello che ha sempre fatto, senza chiedere licenza a nessuno di noi due. Io ho firmato per la mia vecchiaia. Lei non firma niente.","context":"''Eppur si muove'' è attestato per la prima volta in Giuseppe Baretti, ''The Italian Library'', Londra 1757: apocrifo, ma indistruttibile. Il pensiero che segue è invenzione fedele — la verità che la leggenda voleva dire, senza fingere che l''abbia detta."},{"type":"line","speaker":"Urbano VIII","to":"Pubblico","line":"Il carcere glielo commuto subito, s''intende: prima l''ambasciata, poi la custodia dell''arcivescovo Piccolomini a Siena, che lo tratterà da principe, e infine la sua villa d''Arcetri, con l''ordine di starsene lì senza chiamar gente a ragionare. Non sono un mostro: sono un papa offeso. Non l''ho più voluto vedere. Nemmeno una volta.","context":"La commutazione in confino fu immediata (Siena da luglio, Arcetri dal dicembre 1633). Urbano respinse negli anni ogni supplica di piena liberazione, e i due non si incontrarono mai più."},{"type":"line","speaker":"Vincenzo Maculano","to":"Pubblico","line":"Io avevo promesso una via d''uscita e ho consegnato un''abiura: fate voi il conto di quel che vale la parola d''un commissario. Il tribunale mi ricompensò: pochi anni e fui cardinale. Ma vi lascio un dubbio da uomo di fortezze: quel giorno alla Minerva, chi dei due era sotto assedio — il vecchio in ginocchio, o la Chiesa che aveva bisogno di vederlo in ginocchio?","context":"Maculano fu creato cardinale nel 1641. La domanda finale è invenzione: il congedo del personaggio."},{"type":"line","speaker":"Galileo Galilei","to":"Pubblico","line":"Ad Arcetri, nella mia casa-prigione, mi morì la figlia prediletta, suor Maria Celeste. Poi, nel trentasette, mi si spensero gli occhi che avevano visto più cielo di chiunque altro. Scrissi allora a un amico: questo universo, che io con le mie meravigliose osservazioni avevo ampliato cento e mille volte oltre il creduto dei sapienti di tutti i secoli passati, ora per me s''è sì diminuito e ristretto, che non è maggiore di quel che occupa la persona mia. Eppure in quel buio dettai l''opera mia più grande, i ''Discorsi intorno a due nuove scienze'': il manoscritto uscì di nascosto dall''Italia e si stampò in Olanda, dove i papi non arrivano.","context":"La citazione centrale è quasi testuale dalla lettera a Elia Diodati del 2 gennaio 1638, sulla propria cecità. I ''Discorsi'' furono pubblicati da Elzevier a Leida nel 1638: fondano la fisica moderna."},{"type":"line","speaker":"Urbano VIII","to":"Pubblico","line":"Morì l''otto gennaio del 1642, ad Arcetri. Il Granduca voleva fargli un mausoleo in Santa Croce, di fronte a Michelangelo: feci sapere che non era buon esempio, per uno che aveva dato al mondo il maggior scandalo della cristianità. Lo seppellirono in uno stanzino, sotto il campanile. Vinsi anche quella. Credo.","context":"Storico: Urbano VIII fece bloccare il monumento funebre, e Niccolini riferì il giudizio sullo ''scandalo''. La tomba monumentale in Santa Croce arrivò solo nel 1737."},{"type":"line","speaker":"Vincenzo Maculano","to":"Pubblico","line":"Il ''Dialogo'' restò all''Indice dei libri proibiti fino al 1835. E nel 1992 — trecentocinquantanove anni dopo quella mattina alla Minerva — un altro papa, Giovanni Paolo II, riconobbe davanti al mondo gli errori dei giudici di Galileo. La Terra, per parte sua, non ha mai smesso un solo giorno di girare: ma questo, in fondo, lo sapevate già.","context":"La commissione voluta da Giovanni Paolo II concluse i lavori il 31 ottobre 1992. Chiusura al pubblico, affidata al più lucido dei tre."}]}]}');
INSERT INTO scripts (title, mode, language, collection, actors, scenes, content) VALUES ('L''Esame di Maturità di Filippo Spicchi', 'improv', 'it', NULL, 4, 6, '{"mode":"improv","description":"Filippo Spicchi affronta l''esame orale di maturità davanti a tre professori. Ha preparato una tesina sulla crisi dell''uomo moderno, ma la usa spesso come rifugio per evitare risposte precise. I professori cercano di interrogarlo, correggerlo e salvarlo senza ammettere apertamente che stanno cercando di salvarlo.","characters":[{"name":"Filippo Spicchi","description":"Studente di quinta superiore. È agitato, furbo e abbastanza educato. Vuole passare l''esame. Si rifugia spesso in frasi profonde sulla crisi dell''uomo moderno. Quando smette di bluffare e prova a ragionare davvero, migliora.","never_do":"Non confessare di aver copiato. Non sabotare volontariamente l''esame. Non diventare improvvisamente geniale."},{"name":"Antonio Cantante","description":"Professore di Letteratura Italiana. Teatrale, appassionato, narcisista. Ama Pirandello e tende a vedere profondità anche dove Filippo è solo confuso.","never_do":"Non promuovere Filippo durante il colloquio. Non trasformare tutta la scena in un tuo monologo."},{"name":"Annachiara Lo Capo","description":"Professoressa di Letteratura Latina. Precisa, asciutta e ironica. Non sopporta le frasi vaghe spacciate per cultura. Può aiutare Filippo, ma solo se lui smette di bluffare.","never_do":"Non diventare solo cattiva. Non chiedere dettagli impossibili. Non accettare il latino come semplice decorazione."},{"name":"Antonio La Penna","description":"Professore di Storia. Serio, cronologico, allergico agli anacronismi. Vuole date, cause e conseguenze. Detesta quando Filippo usa la storia come serbatoio di metafore.","never_do":"Non trasformare la storia in un elenco infinito di date. Non bocciare Filippo prima della deliberazione."}],"preparation":{"premise":"Siamo all''orale di maturità di Filippo Spicchi. Filippo presenta una tesina intitolata ''La crisi dell''uomo moderno''. L''esame è fragile ma recuperabile. La scena deve restare un esame scolastico, non diventare un processo, una farsa totale o una confessione di imbrogli.","tone":"Commedia da aula scolastica: tensione reale, professori caratterizzati, studente in difficoltà ma non stupido.","ending_to_preserve":"Filippo viene promosso con una sufficienza minima e sofferta. Non deve sembrare brillante, ma nemmeno completamente incapace.","continuity_rules":["La tesina di Filippo è ''La crisi dell''uomo moderno''.","Il primo appiglio è Pirandello: identità, maschera, persona/personaggio.","Il latino passa da Seneca: tempo, morte, controllo di sé, interiorità.","La storia passa dal Novecento: società di massa, guerre, propaganda, totalitarismi.","Filippo può sbagliare, ma non deve fare errori talmente assurdi da rendere impossibile promuoverlo.","I professori non devono annunciare il voto prima della deliberazione.","Nessuno deve introdurre scandali, genitori in aula, prove annullate o confessioni di copiatura.","Il doppio nome Antonio può creare confusione comica, ma non deve bloccare la scena."],"background":[{"title":"Pirandello e la maschera","description":"Luigi Pirandello (1867-1936), scrittore siciliano. Idea centrale: l''identità è multipla e instabile. Ognuno indossa maschere diverse a seconda di chi lo guarda; la ''persona'' che gli altri vedono non coincide con nessun ''io'' vero. Opere chiave: ''Il fu Mattia Pascal'' (un uomo si crede libero cambiando identità e scopre che nessuna maschera regge), ''Uno, nessuno e centomila'' (chi si accorge di essere visto in cento modi diversi entra in crisi), ''Sei personaggi in cerca d''autore'' (i personaggi rifiutano l''autore che li ha creati). Parole utili in scena: identità, maschera, persona vs personaggio, frammentazione, forma vs vita."},{"title":"Seneca e il tempo","description":"Lucio Anneo Seneca (4 a.C. - 65 d.C.), filosofo stoico romano, precettore di Nerone, costretto al suicidio. Idea centrale: il vero problema non è la brevità della vita ma il modo in cui la sprechiamo. Testo chiave: ''De brevitate vitae'' — ''non abbiamo poco tempo, ma molto ne perdiamo''. Concetti: tempo come unico bene davvero nostro, otium (tempo dedicato allo studio interiore, non ozio) contro negotium (l''affannarsi degli occupati), controllo di sé, morte come misura della vita, interiorità. Parole utili in scena: brevitas, tempus fugit, occupati, sapiens, ratio."},{"title":"Il Novecento e la crisi dell''individuo","description":"Il XX secolo europeo, dalle due guerre mondiali (1914-18 e 1939-45) al dopoguerra. Fenomeni chiave: società di massa (folle urbane, produzione industriale, consumo di massa), regimi totalitari (fascismo, nazismo, stalinismo), propaganda e uso dei nuovi media (radio, cinema, poi TV), Shoah, guerra fredda. L''individuo si sente schiacciato tra masse anonime, ideologie totalizzanti e catastrofi collettive: da qui la ''crisi dell''uomo moderno'' che attraversa filosofia (esistenzialismo), letteratura e arte. Ordine minimo da rispettare: prima guerra mondiale, poi fascismo e nazismo, poi seconda guerra mondiale, poi dopoguerra."}],"scene_flow":[{"scene":"scene_1","summary":"Ingresso e presentazione della tesina. Filippo espone il tema in modo fumoso."},{"scene":"scene_2","summary":"Italiano: Pirandello, identità e maschera. Filippo se la cava a metà."},{"scene":"scene_3","summary":"Latino: Seneca. Lo Capo costringe Filippo a essere meno vago."},{"scene":"scene_4","summary":"Storia: Novecento. La Penna corregge gli anacronismi e pretende ordine."},{"scene":"scene_5","summary":"Deliberazione. I professori discutono se promuoverlo."},{"scene":"scene_6","summary":"Verdetto. Filippo viene promosso al minimo."}]},"scenes":[{"id":"scene_1","title":"L''ingresso","setting":"Aula d''esame. Tre professori seduti dietro un tavolo. Filippo entra con una cartellina troppo piena.","scene_prep":"Filippo deve iniziare agitato ma non muto. La commissione deve sembrare severa ma non ostile.","beats":[{"speaker":"Antonio Cantante","to":"Filippo Spicchi","context":"Apri l''esame con tono solenne. Invitalo a presentare la tesina.","constraint":"Non fare ancora domande difficili."},{"speaker":"Filippo Spicchi","to":"Commissione","context":"Presenta la tesina: ''La crisi dell''uomo moderno''. Sembri preparato, ma resti molto vago.","constraint":"Devi nominare la crisi dell''uomo moderno."},{"speaker":"Annachiara Lo Capo","to":"Filippo Spicchi","context":"Interrompi con precisione. Chiedi cosa significhi concretamente il titolo della tesina.","constraint":"Non passare ancora al latino."},{"speaker":"Antonio La Penna","to":"Filippo Spicchi","context":"Riporta il tema alla storia. Fai capire che la crisi moderna ha un contesto storico.","constraint":"Non chiedere ancora date specifiche."}]},{"id":"scene_2","title":"Pirandello e la maschera","setting":"Filippo ha aperto la cartellina. Cerca il foglio giusto, ma non lo trova subito.","scene_prep":"Questa scena deve stabilire che Filippo conosce il concetto generale di maschera, ma non padroneggia bene le opere.","beats":[{"speaker":"Antonio Cantante","to":"Filippo Spicchi","context":"Avvia la parte di Letteratura Italiana. Chiedi di parlare di Pirandello e della maschera.","constraint":"Domanda ampia, non punitiva."},{"speaker":"Filippo Spicchi","to":"Antonio Cantante","context":"Rispondi su Pirandello. Usa parole come identità, maschera, società, frammentazione.","constraint":"Devi stare vago ma con tono epico per sembrare che ne sai."},{"speaker":"Antonio Cantante","to":"Filippo Spicchi","context":"Ti entusiasmi troppo. Trasforma una frase vaga di Filippo in una grande intuizione poetica.","constraint":"Non dire che è stato perfetto."},{"speaker":"Annachiara Lo Capo","to":"Antonio Cantante","context":"Ridimensiona Cantante. Ricorda che una bella frase non basta se non c''è contenuto.","constraint":"Non attaccarlo personalmente."},{"speaker":"Antonio La Penna","to":"Filippo Spicchi","context":"Collega alla storia. Chiedi perché il Novecento rende credibile questa crisi dell''identità.","constraint":"Apri la storia senza saltare troppo avanti."},{"speaker":"Filippo Spicchi","to":"Antonio La Penna","context":"Tenta il collegamento storico. Parla di società di massa, guerre e individuo che si perde.","constraint":"Non fare errori storici irreparabili."}]},{"id":"scene_3","title":"Il latino entra dalla finestra","setting":"Lo Capo prende il controllo dell''interrogazione. Filippo capisce che la parte difficile sta arrivando.","scene_prep":"Il latino deve passare da Seneca. Filippo deve dimostrare una conoscenza minima, non brillante.","beats":[{"speaker":"Annachiara Lo Capo","to":"Filippo Spicchi","context":"Avvia la parte di Letteratura Latina. Chiedi di collegare Seneca al tema del tempo e della fragilità umana.","constraint":"Non chiedere una traduzione lunga."},{"speaker":"Filippo Spicchi","to":"Annachiara Lo Capo","context":"Rispondi su Seneca. Parla del tempo che fugge e dell''uomo che non sa usarlo.","constraint":"Non inventare opere inesistenti."},{"speaker":"Annachiara Lo Capo","to":"Filippo Spicchi","context":"Stringi la domanda. Chiedi cosa distingue Seneca da una frase motivazionale.","constraint":"Se Filippo è onesto, puoi aiutarlo."},{"speaker":"Filippo Spicchi","to":"Annachiara Lo Capo","context":"Smetti di bluffare. Ammetti il limite e prova a ragionare davvero.","constraint":"Questo è un piccolo recupero."},{"speaker":"Antonio Cantante","to":"Annachiara Lo Capo","context":"Nobilita il momento. Vedi nella risposta di Filippo una piccola verità teatrale.","constraint":"Non rubare tutta la scena."},{"speaker":"Antonio La Penna","to":"Gruppo","context":"Riporta ordine. Ricorda che adesso bisogna verificare il contesto storico.","constraint":"Prepara la scena di storia."}]},{"id":"scene_4","title":"La Storia non è una metafora","setting":"La Penna ha davanti alcuni fogli e una penna. Filippo capisce che ogni parola può diventare una data.","scene_prep":"Questa scena deve mostrare il limite di Filippo: capisce i grandi concetti, ma confonde ordine, cause e conseguenze.","beats":[{"speaker":"Antonio La Penna","to":"Filippo Spicchi","context":"Avvia la parte di Storia. Chiedi come il Novecento mette in crisi l''individuo.","constraint":"Tieni la domanda su guerra, massa e propaganda."},{"speaker":"Filippo Spicchi","to":"Antonio La Penna","context":"Rispondi da studente fragile. Usa un concetto valido, ma confondi un po'' causa e conseguenza.","constraint":"Non inventare eventi assurdi."},{"speaker":"Antonio La Penna","to":"Filippo Spicchi","context":"Correggi con severità. Spiega che collegare non significa confondere.","constraint":"Non bocciarlo ancora."},{"speaker":"Filippo Spicchi","to":"Antonio La Penna","context":"Riformula. Prova a essere più semplice e cronologico.","constraint":"Devi migliorare, non diventare perfetto."},{"speaker":"Annachiara Lo Capo","to":"Filippo Spicchi","context":"Fai una critica utile. Digli che quando smette di fare frasi profonde si capisce meglio.","constraint":"Tono secco, non crudele."},{"speaker":"Antonio Cantante","to":"Filippo Spicchi","context":"Chiedi la chiusura. Invitalo a tornare a Pirandello e all''identità.","constraint":"Deve essere l''ultima risposta."},{"speaker":"Filippo Spicchi","to":"Commissione","context":"Chiudi la tesina. Dai una conclusione semplice e personale sulle maschere e sull''identità.","constraint":"Risposta sufficiente, non brillante."}]},{"id":"scene_5","title":"La deliberazione","setting":"Filippo è uscito. I professori restano soli con la griglia di valutazione.","scene_prep":"L''esame è andato male ma non malissimo. La decisione deve andare verso una promozione minima.","beats":[{"speaker":"Antonio La Penna","to":"Gruppo","context":"Apri severamente. Riconosci errori e confusione, ma anche un piccolo recupero finale.","constraint":"Non chiedere la bocciatura secca."},{"speaker":"Annachiara Lo Capo","to":"Gruppo","context":"Valuta il latino. Dì che era fragile, ma che l''onestà finale ha aiutato.","constraint":"Non dire che è andato bene."},{"speaker":"Antonio Cantante","to":"Gruppo","context":"Difendi Filippo. Insisti sul fatto che almeno ha trovato una conclusione umana.","constraint":"Non proporre un voto alto."},{"speaker":"Antonio La Penna","to":"Antonio Cantante","context":"Stai pensando di bocciarlo. Non è stata disastroso come orale ma nemmeno sufficiente","constraint":"Litigio ma non lo devi bocciare."},{"speaker":"Annachiara Lo Capo","to":"Gruppo","context":"Trova la sintesi. Proponi una sufficienza minima e sofferta.","constraint":"La promozione è il compromesso."},{"speaker":"Antonio Cantante","to":"Gruppo","context":"Accetta poeticamente. Trasforma la sufficienza in una piccola rinascita dell''individuo.","constraint":"Gli altri possono tagliarti corto."}]},{"id":"scene_6","title":"Il verdetto","setting":"Filippo rientra nell''aula. I professori hanno già deciso.","scene_prep":"La scena deve chiudere senza riaprire l''esame. Filippo è promosso, ma per pochissimo.","beats":[{"speaker":"Antonio La Penna","to":"Filippo Spicchi","context":"Comunica il risultato. Digli che è promosso con tono asciutto.","constraint":"Deve capire che è andata bene per poco."},{"speaker":"Filippo Spicchi","to":"Commissione","context":"Reagisci al verdetto. Mostra sollievo enorme, cercando di restare dignitoso.","constraint":"Non confessare imbrogli."},{"speaker":"Annachiara Lo Capo","to":"Filippo Spicchi","context":"Dai l''ultimo consiglio. Digli di distinguere il pensiero dalle frasi a effetto.","constraint":"Duro ma costruttivo."},{"speaker":"Antonio Cantante","to":"Filippo Spicchi","context":"Chiudi solennemente. Fai una riflessione pomposa sulle maschere della vita.","constraint":"Sarai interrotto nella tua riflessione poetica da Antonio La Penna."},{"speaker":"Antonio La Penna","to":"Antonio Cantante","context":"Taglia la poesia. Ricorda che bisogna chiamare il candidato successivo.","constraint":"Devi far uscire Spicchi dall''aula."},{"speaker":"Filippo Spicchi","to":"Pubblico","context":"Esci sopravvissuto. Fai una confidenza intima al Pubblico.","constraint":"Nessun limite."}]}]}');
